const QUESTIONS = [
  { id: 1, text: "Which GCP service below provides a direct physical connection between your GCP environment and your on-premises network using GCP network co-locations?", options: { A: "Cloud VPN", B: "Carrier Peering", C: "Dedicated Interconnect", D: "Partner Interconnect" }, correct: ["C"] },
  { id: 2, text: "Steve is the cloud admin for Blue Widget Corp. He has been asked to configure a Kubernetes-hosted app so that it can be accessed internally by the GKE cluster. It will NOT be accessed from the public internet. Which service is suitable for exposing an internal IP address for apps that do not need to be accessed from the public internet?", options: { A: "Node Port", B: "Cluster IP", C: "Load Balancer", D: "External Name" }, correct: ["B"] },
  { id: 3, text: "Which of the following Kubernetes controllers should be used for maintenance operations that must run with exactly one pod running on each node?", options: { A: "Daemon Set", B: "ReplicaSet", C: "Stateful Set", D: "Deployment" }, correct: ["A"] },
  { id: 4, text: "You want to configure auto healing for network load balancing for a group of Compute Engine instances that run in multiple zones, using the fewest possible steps. You need to configure re-creation of VMs if they are unresponsive after 3 attempts of 10 seconds each. What should you do?", options: { A: "Create an HTTP load balancer with a backend configuration that references an existing instance group. Set the health check to healthy (HTTP)", B: "Create an HTTP load balancer with a backend configuration that references an existing instance group. Define a balancing mode and set the maximum RPS to 10.", C: "Create a managed instance group. Set the Auto healing health check to healthy (HTTP)", D: "Create a managed instance group. Verify that the autoscaling setting is on." }, correct: ["C"] },
  { id: 5, text: "Jennifer is the cloud admin for the Blue Widget Corp. She has been asked to deploy a Kubernetes cluster so that the organization can perform some testing of a containerized app. After creating the cluster, her teams begins testing. Thirty days later, Jennifer's team informs her the the cluster appears to have been deleted. Nobody on the team has deleted the cluster. What is likely the cause of this?", options: { A: "Jennifer deployed a private cluster with a 30-day window", B: "Jennifer deployed a zonal cluster", C: "Jennifer deployed a dev cluster", D: "Jennifer deployed an alpha cluster" }, correct: ["D"] },
  { id: 6, text: "You are deploying an application to App Engine. You want the number of instances to scale based on request rate. You need at least 3 unoccupied instances at all times. Which scaling type should you use?", options: { A: "Manual Scaling with 3 instances.", B: "Basic Scaling with min_instances set to 3.", C: "Basic Scaling with max_instances set to 3.", D: "Automatic Scaling with min_idle_instances set to 3." }, correct: ["D"] },
  { id: 7, text: "As the GCP admin in your organization, you need to perform some tasks using the Google Cloud SDK, using your Windows 10 workstation. To begin using the SDK on your workstation, you've created a Google Cloud Platform project, downloaded the Google Cloud SDK installer, and completed the installation. At this point, you need to initialize the SDK. Which command do you use to complete this task?", options: { A: "initialize gcloud", B: "gcloud init", C: "gcloud start", D: "start gcloud" }, correct: ["B"] },
  { id: 8, text: "Every employee of your company has a Google account. Your operational team needs to manage a large number of instances on Compute Engine. Each member of this team needs only administrative access to the servers. Your security team wants to ensure that the deployment of credentials is operationally efficient and must be able to determine who accessed a given instance. What should you do?", options: { A: "Generate a new SSH key pair. Give the private key to each member of your team. Configure the public key in the metadata of each instance.", B: "Ask each member of the team to generate a new SSH key pair and to send you their public key. Use a configuration management tool to deploy those keys on each instance.", C: "Ask each member of the team to generate a new SSH key pair and to add the public key to their Google account. Grant the compute.osAdminLogin role to the Google group corresponding to this team.", D: "Generate a new SSH key pair. Give the private key to each member of your team. Configure the public key as a project-wide public SSH key in your Cloud Platform project and allow project-wide public SSH keys on each instance." }, correct: ["C"] },
  { id: 9, text: "Jennifer is the cloud admin for Blue Widget Corp. She has been asked to build out a cloud application in GCP that leverages the serverless architecture model. Which GCP service will be of most interest to her?", options: { A: "Compute Engine", B: "Kubernetes Engine", C: "App Engine", D: "Direct Peering" }, correct: ["C"] },
  { id: 10, text: "You are using multiple configurations for gcloud. You want to review the configured Kubernetes Engine cluster of an inactive configuration using the fewest possible steps. What should you do?", options: { A: "Use gcloud config configurations describe to review the output.", B: "Use gcloud config configurations activate and gcloud config list to review the output.", C: "Use kubectl config get-contexts to review the output.", D: "Use kubectl config use-context and kubectl config view to review the output." }, correct: ["D"] },
  { id: 11, text: "When using Google BigQuery, which of the following best describes the pricing models? Choose two options.", options: { A: "Flat-rate pricing", B: "Monthly subscription tiers for processing more than 500 terabytes per month", C: "On-demand pricing", D: "Capacity-pricing" }, correct: ["C"] },
  { id: 12, text: "Dana, the junior cloud admin, has been asked to deploy a virtual machine on the GCP platform. Which images below can Dana use to deploy her VM?", options: { A: "Public image", B: "Custom image", C: "Container image", D: "None of these" }, correct: ["A", "B", "C"] },
  { id: 13, text: "You need to create a custom VPC with a single subnet. The subnet's range must be as large as possible. Which tange should you use?", options: { A: "0.0.0.0/0", B: "10.0.0.0/8", C: "172.16.0.0/12", D: "192.168.0.0/16" }, correct: ["B"] },
  { id: 14, text: "To configure Stackdriver to monitor a web server and notify you if it goes down, what steps do you need to take? (Choose 2 answers)", options: { A: "Install the Stackdriver Monitoring Agent on the web server", B: "Create an uptime check", C: "Create an alerting policy", D: "Install the Operations Monitoring Logging Agent on the web server" }, correct: ["B", "C"] },
  { id: 15, text: "Your company uses Cloud Storage to store application backup files for disaster recovery purposes. You want to follow Google's recommended practices. Which storage option should you use?", options: { A: "Multi-Regional Storage", B: "Regional Storage", C: "Nearline Storage", D: "Coldline Storage" }, correct: ["D"] },
  { id: 16, text: "Steve is a cloud admin at the Blue Widget Company. He's been asked to deploy a public-facing web application. Jen, who is Steve's manager, doesn't want to deploy any more hardware, infrastructure, or services than are absolutely necessary. Which service should Steve use to host the web application?", options: { A: "Compute Engine", B: "App Engine", C: "Kubernetes Engine", D: "None of the Above" }, correct: ["B"] },
  { id: 17, text: "You want to select and configure a cost-effective solution for relational data on Google Cloud Platform. You are working with a small set of operational data in one geographic location. You need to support point-in-time recovery. What should you do?", options: { A: "Select Cloud SQL (MySQL). Verify that the enable binary logging option is selected.", B: "Select Cloud SQL (MySQL). Select the create failover replicas option.", C: "Select Cloud Spanner. Set up your instance with 2 nodes.", D: "Select Cloud Spanner. Set up your instance as multi-regional." }, correct: ["A"] },
  { id: 18, text: "Dave is a junior cloud admin at the Blue Widget Corp. He's been asked to review the logs to identify which user created the APP01 virtual machine in GCP. Which audit log should Dave review?", options: { A: "data access logs", B: "system events logs", C: "admin activity logs", D: "None of the Above" }, correct: ["C"] },
  { id: 19, text: "Several employees at your company have been creating projects with Cloud Platform and paying for it with their personal credit cards, which the company reimburses. The company wants to centralize all these projects under a single, new billing account. What should you do?", options: { A: "Contact cloud-billing@google.com with your bank account details and request a corporate billing account for your company.", B: "Create a ticket with Google Support and wait for their call to share your credit card details over the phone.", C: "In the Google Platform Console, go to the Resource Manage and move all projects to the root Organizarion.", D: "In the Google Cloud Platform Console, create a new billing account and set up a payment method." }, correct: ["D"] },
  { id: 20, text: "After an incident at Blue Widget Corp, where a user deleted some resources accidentally, corporate leaders are now demanding that users only have the exact access and management privileges that they need. What tool (or service) will allow Steve, as the administrator, enforce this doctrine of “least privilege\"?", options: { A: "Role-Based Access Control", B: "GCP Cloud Identity and Access Management", C: "Assigning Liens", D: "GCP Trust and Security" }, correct: ["B"] },
  { id: 21, text: "You have an application that looks for its licensing server on the IP 10.0.3.21. You need to deploy the licensing server on Compute Engine. You do not want to change the configuration of the application and want the application to be able to reach the licensing server. What should you do?", options: { A: "Reserve the IP 10.0.3.21 as a static internal IP address using gcloud and assign it to the licensing server.", B: "Reserve the IP 10.0.3.21 as a static public IP address using gcloud and assign it to the licensing server.", C: "Use the IP 10.0.3.21 as a custom ephemeral IP address and assign it to the licensing server.", D: "Start the licensing server with an automatic ephemeral IP address, and then promote it to a static internal IP address." }, correct: ["A"] },
  { id: 22, text: "Which statement regarding Cloud IAM primitive roles is incorrect?", options: { A: "Primitive roles are concentric.", B: "There are three primitive roles: viewer, editor, and owner.", C: "The most permissive primitive role is the owner role, which allows you to invite project members and delete projects.", D: "Primitive roles can be assigned to Google accounts, service accounts, and Google App domains." }, correct: ["D"] },
  { id: 23, text: "You have a development project with appropriate IAM roles defined. You are creating a production project and want to have the same IAM roles on the new project, using the fewest possible steps. What should you do?", options: { A: "Use gcloud iam roles copy and specify the production project as the destination project.", B: "Use gcloud iam roles copy and specify your organization as the destination organization.", C: "In the Google Cloud Platform Console, use the ‘create role from role’ functionality.", D: "In the Google Cloud Platform Console, use the ‘create role’ functionality and select all applicable permissions." }, correct: ["A"] },
  { id: 24, text: "To use load balancing and protocol forwarding, you must create a forwarding rule that directs traffic to specific ___________ that contain instances from multiple zones.", options: { A: "priority pools", B: "target pools", C: "source pools", D: "resource groups" }, correct: ["B"] },
  { id: 25, text: "You need a dynamic way of provisioning VMs on Compute Engine. The exact specifications will be in a dedicated configuration file. You want to follow Google's recommended practices. Which method should you use?", options: { A: "Deployment Manager", B: "Cloud Composer", C: "Managed Instance Group", D: "Unmanaged Instance Group" }, correct: ["C"] },
  { id: 26, text: "Which type of account would you use in code when you want to interact with Google Cloud services?", options: { A: "Service account", B: "Google account", C: "Google group", D: "Code account" }, correct: ["A"] },
  { id: 27, text: "You have a Dockerfile that you need to deploy on Kubernetes Engine. What should you do?", options: { A: "Use kubectl app deploy <dockerfilename>.", B: "Use gcloud app deploy <dockerfilename>.", C: "Create a docker image from the Dockerfile and upload it to Container Registry. Create a Deployment YAML file to point to that image. Use kubectl to create the deployment with that file.", D: "Create a docker image from the Dockerfile and upload it to Cloud Storage. Create a Deployment YAML file to point to that image. Use kubectl to create the deployment with that file." }, correct: ["C"] },
  { id: 28, text: "Which of the following accurately describes Google Cloud Platform’s multi-region product availability?", options: { A: "GCP globally is divided into zones that map to continents. Each zone has multiple regions that constitute individual data centers in specific countries.", B: "GCP globally is divided into regions that map to continents. Each region has multiple zones that constitute individual data centers in specific countries.", C: "GCP zones are locations within a country. Individual countries can have multiple zones. Zones are then broken into regions which represent a specific set of hardware within a data center.", D: "GCP regions are specific geographical locations. Individual countries can have multiple regions. Regions are then broken into zones that represent a specific set of hardware within a data center." }, correct: ["D"] },
  { id: 29, text: "Your development team needs a new Jenkins server for their project. You need to deploy the server using the fewest steps possible. What should you do?", options: { A: "Download and deploy the Jenkins Java WAR to App Engine Standard.", B: "Create a new Compute Engine instance and install Jenkins through the command line interface.", C: "Create a Kubernetes cluster on Compute Engine and create a deployment with the Jenkins Docker image.", D: "Use GCP Marketplace to launch the Jenkins solution." }, correct: ["D"] },
  { id: 30, text: "Cindy is the cloud admin for Blue Widget Corp. She has been tasked with deploying a basic internal-facing IIS website that she will use to post staff updates. She also wants to load balance the website, since there are thousands of employees that will be accessing the backend on a daily basis. Which type of load balancer should Cindy deploy?", options: { A: "Regional Network TCP/UDP load balancer", B: "Global TCP proxy load balancer", C: "_ Internal HTTP(s) load balancer", D: "Regional SSL proxy load balancer" }, correct: ["C"] },
  { id: 31, text: "You need to update a deployment in Deployment Manager without any resource downtime in the deployment. Which command should you use?", options: { A: "gcloud deployment-manager deployments create -config <deployment-config-path>", B: "gcloud deployment-manager deployments update --config <deployment-config-path>", C: "gcloud deployment-manager resources create --config <deployment-config-path>", D: "gcloud deployment-manager resources update --config <deployment-config-path>" }, correct: ["B"] },
  { id: 32, text: "Steve has been asked to deploy a virtual machine with a custom configuration. He has been asked to deploy a VM with 4 virtual CPUs and 6GB of RAM. Which gcloud command below will successfully create this custom VM?", options: { A: "gcloud instances create vm01 --custom-cpu 4 -custom-memory 6", B: "gcloud compute instances create vm01 -custom-cpu 4 —custom-memory 6", C: "gcloud instances create vm01 -custom-cpu 4 -custom-memory 6", D: "gcloud compute instances create vm01 -custom-cpu 4 -custom-memory 6 @ _ sabitses e" }, correct: ["B"] },
  { id: 33, text: "You need to run an important query in BigQuery but expect it to return a lot of records. You want to find out how much it will cost to run the query. You are using on-demand pricing. What should you do?", options: { A: "Arrange to switch to Flat-Rate pricing for this query, then move back to on-demand.", B: "Use the command line to run a dry run query to estimate the number of bytes read. Then convert that bytes estimate to dollars using the Pricing Calculator.", C: "Use the command line to run a dry run query to estimate the number of bytes returned. Then convert that bytes estimate to dollars using the Pricing Calculator.", D: "Run a select count (*) to get an idea of how many records your query will look through. Then convert that number of rows to dollars using the Pricing Calculator. @ _ sabitses e" }, correct: ["B"] },
  { id: 34, text: "Google Compute Engine offers to distribute incoming network traffic across multiple virtual machine instances.", options: { A: "Load balancing", B: "Firewall", C: "Route", D: "Static IP address" }, correct: ["A"] },
  { id: 35, text: "You have a single binary application that you want to run on Google Cloud Platform. You decided to automatically scale the application based on underlying infrastructure CPU usage. Your organizational policies require you to use virtual machines directly. You need to ensure that the application scaling is operationally efficient and completed as quickly as possible. What should you do?", options: { A: "Create a Google Kubernetes Engine cluster, and use horizontal pod autoscaling to scale the application.", B: "Create an instance template, and use the template in a managed instance group with autoscaling configured.", C: "Create an instance template, and use the template in a managed instance group that scales up and down based on the time of day.", D: "Use a set of third-party tools to build automation around scaling the application up and down, based on Stackdriver CPU usage monitoring. Peony" }, correct: ["B"] },
  { id: 36, text: "Cloud Dataproc charges you only for what you really use with billing.", options: { A: "daily", B: "hour-by-hour", C: "minute-by-minute", D: "second-by-second" }, correct: ["D"] },
  { id: 37, text: "You are analyzing Google Cloud Platform service costs from three separate projects. You want to use this information to create service cost estimates by service type, daily and monthly, for the next six months using standard query syntax. What should you do?", options: { A: "Export your bill to a Cloud Storage bucket, and then import into Cloud Bigtable for analysis.", B: "Export your bill to a Cloud Storage bucket, and then import into Google Sheets for analysis.", C: "Export your transactions to a local file, and perform analysis with a desktop tool.", D: "Export your bill to a BigQuery dataset, and then write time window-based SQL queries for analysis." }, correct: ["D"] },
  { id: 38, text: "Regarding Cloud IAM, what type of role(s) are available?", options: { A: "Basic, predefined, and custom roles", B: "User, service, and domain roles", C: "Basic and curated roles", D: "User, service, and custom roles" }, correct: ["A"] },
  { id: 39, text: "You need to set up a policy so that videos stored in a specific Cloud Storage Regional bucket are moved to Coldline after 90 days, and then deleted after one year from their creation. How should you set up the policy?", options: { A: "Use Cloud Storage Object Lifecycle Management using Age conditions with SetStorageClass and Delete actions. Set the SetStorageClass action to 90 days and the Delete action to 275 days", B: "Use Cloud Storage Object Lifecycle Management using Age conditions with SetStorageClass and Delete actions. Set the SetStorageClass action to 90 days and the Delete action to 365 days.", C: "Use gsutil rewrite and set the Delete action to 275 days (365-90).", D: "Use gsutil rewrite and set the Delete action to 365 days." }, correct: ["A"] },
  { id: 40, text: "The Blue Widget Corporation needs to run a VM-based, mission-critical application continuously on Google Cloud Platform for one year. What is the most cost-effective way to accomplish this?", options: { A: "Deploy preemptible instances or spot VMs", B: "Deploy custom virtual machines", C: "Purchase committed use instances", D: "Purchase sustained use instances" }, correct: ["C"] },
  { id: 41, text: "You have a Linux VM that must connect to Cloud SQL. You created a service account with the appropriate access rights. You want to make sure that the VM uses this service account instead of the default Compute Engine service account. What should you do?", options: { A: "When creating the VM via the web console, specify the service account under the ‘Identity and API Access' section.", B: "Download a JSON Private Key for the service account. On the Project Metadata, add that JSON as the value for the key compute-engine-service- account.", C: "Download a JSON Private Key for the service account. On the Custom Metadata of the VM, add that JSON as the value for the key compute-engine- service-account.", D: "Download a JSON Private Key for the service account. After creating the VM, ssh into the VM and save the JSON under ~/.gcloud/compute-engine-service- account.json." }, correct: ["A"] },
  { id: 42, text: "Dave has been asked to track down logging on some actions that were initiated by the GCP infrastructure. He's also been asked to review the audit logs for some API calls that modified the configuration of certain resources. Which audit log(s) should Dave be interested in?", options: { A: "Admin Activity audit logs only", B: "System Event audit logs only", C: "Admin Activity and System Event audit logs", D: "No choice is correct." }, correct: ["C"] },
  { id: 43, text: "You created an instance of SQL Server 2017 on Compute Engine to test features in the new version. You want to connect to this instance using the fewest number of steps. What should you do?", options: { A: "Install a RDP client on your desktop. Verify that a firewall rule for port 3389 exists.", B: "Install a RDP client in your desktop. Set a Windows username and password in the GCP Console. Use the credentials to log in to the instance.", C: "Set a Windows password in the GCP Console. Verify that a firewall rule for port 22 exists. Click the RDP button in the GCP Console and supply the credentials to log in.", D: "Set a Windows username and password in the GCP Console. Verify that a firewall rule for port 3389 exists. Click the RDP button in the GCP Console, and supply the credentials to log in." }, correct: ["B"] },
  { id: 44, text: "You have deployed several VMs within a Google Cloud VPC, but are considering implementing Cloud Armor for additional security. What additional security does Cloud Armor provide, in addition to your VPC's instance firewalls?", options: { A: "Cloud Armor requires additional authentication to process requests.", B: "Cloud Armor offers additional request data packet encryption for data in transit.", C: "Cloud Armor analyzes requests at a secure perimeter outside your VPC.", D: "Cloud Armor provides a private network connection, to avoid sending packets over the public internet" }, correct: ["C"] },
  { id: 45, text: "You have one GCP account running in your default region and zone and another account running in a non-default region and zone. You want to start a new Compute Engine instance in these two Google Cloud Platform accounts using the command line interface. What should you do?", options: { A: "Create two configurations using gcloud config configurations create [NAME]. Run gcloud config configurations activate [NAME] to switch between accounts when running the commands to start the Compute Engine instances.", B: "Create two configurations using gcloud config configurations create [NAME]. Run gcloud configurations list to start the Compute Engine instances.", C: "Activate two configurations using gcloud configurations activate [NAME]. Run gcloud config list to start the Compute Engine instances.", D: "Activate two configurations using gcloud configurations activate [NAME]. Run gcloud configurations list to start the Compute Engine instances." }, correct: ["A"] },
  { id: 46, text: "Steven has been asked to deploy a custom, home-grown application on a VM on GCP. This application collects data and stores it for review on a hard-coded S: drive, which must be local to the VM. Which storage option should Steven use to store the application's data?", options: { A: "VM-attachable persistent disk storage", B: "Cloud Storage Nearline", C: "Cloud Storage Coldline", D: "None of the Above" }, correct: ["A"] },
  { id: 47, text: "You significantly changed a complex Deployment Manager template and want to confirm that the dependencies of all defined resources are properly met before committing it to the project. You want the most rapid feedback on your changes. What should you do?", options: { A: "Use granular logging statements within a Deployment Manager template authored in Python.", B: "Monitor activity of the Deployment Manager execution on the Stackdriver Logging page of the GCP Console.", C: "Execute the Deployment Manager template against a separate project with the same configuration, and monitor for failures.", D: "Execute the Deployment Manager template using the -preview option in the same project, and observe the state of interdependent resources." }, correct: ["D"] },
  { id: 48, text: "When you set the project using the \"gcloud config\" command, which of the following ways of referring to a project do you use?", options: { A: "Project Name", B: "Project ID", C: "Project Number", D: "None of the choices are correct." }, correct: ["B"] },
  { id: 49, text: "You are building a pipeline to process time-series data. Which Google Cloud Platform services should you put in boxes 1,2,3, and 4? SEP\" SRE 0 Cooke courte", options: { A: "Cloud Pub/Sub, Cloud Dataflow, Cloud Datastore, BigQuery QO oO", B: "Firebase Messages, Cloud Pub/Sub, Cloud Spanner, ~ en BigQuery 3", C: "Cloud Pub/Sub, Cloud Storage, BigQuery, Cloud —_—== Bigtable 8 —-a— 1 — 2", D: "Cloud Pub/Sub, Cloud Dataflow, Cloud Bigtable, a SS ee BigQuery ann 4 EE Co pt" }, correct: ["D"] },
  { id: 50, text: "You've asked your junior admin to setup billing for a project you are planning in your Google Cloud Organization. However, your junior admin reports back that GCP will not allow her to setup the billing. Which primitive role definition below is the minimum necessary to setup billing for a project?", options: { A: "roles/viewer", B: "roles/editor", C: "roles/owner", D: "roles/manager" }, correct: ["C"] },
  { id: 51, text: "You have a project for your App Engine application that serves a development environment. The required testing has succeeded and you want to create a new project to serve as your production environment. What should you do?", options: { A: "Use gcloud to create the new project, and then deploy your application to the new project.", B: "Use gcloud to create the new project and to copy the deployed application to the new project.", C: "Create a Deployment Manager configuration file that copies the current App Engine deployment into a new project.", D: "Deploy your application again using gcloud and specify the project parameter with the new project name to create the new project." }, correct: ["A"] },
  { id: 52, text: "Which of the following statements about traffic splitting in App Engine is TRUE?", options: { A: "Distributes a percentage of traffic to versions of your application", B: "You can split traffic to move 100% of traffic to a single version or to route percentages of traffic to multiple versions", C: "Allows you to conduct A/B testing between your versions", D: "All of the Above" }, correct: ["D"] },
  { id: 53, text: "You need to configure IAM access audit logging in BigQuery for external auditors. You want to follow Google- recommended practices. What should you do?", options: { A: "Add the auditors group to the ‘logging.viewer' and ‘bigQuery.dataViewer’ predefined IAM roles.", B: "Add the auditors group to two new custom IAM roles.", C: "Add the auditor user accounts to the ‘logging.viewer' and ‘bigQuery.dataViewer' predefined IAM roles.", D: "Add the auditor user accounts to two new custom IAM roles." }, correct: ["A"] },
  { id: 54, text: "The Blue Widget Corp website is visited by hundreds of thousands of users every month - from all over the world. The website is currently hosted on a single server. Steve has been asked to improve the response times for the website users while also reducing the load on the server hosting the website. Which solution below should Steve take advantage of?", options: { A: "Partner Interconnect", B: "Traffic Director", C: "Dedicated Interconnect", D: "Cloud CDN" }, correct: ["D"] },
  { id: 55, text: "You need to set up permissions for a set of Compute Engine instances to enable them to write data into a particular Cloud Storage bucket. You want to follow Google-recommended practices. What should you do?", options: { A: "Create a service account with an access scope. Use the access scope ‘", B: "Create a service account with an access scope. Use the access scope ‘", C: "Create a service account and add it to the IAM role ‘storage.objectCreator’ for that bucket.", D: "Create a service account and add it to the IAM role 'storage.objectAdmin’ for that bucket." }, correct: ["C"] },
  { id: 56, text: "Infrequently, the Blue Widget Corporation runs a number of very short-lived data processing jobs in Google Cloud Platform. These workloads take anywhere from a few minutes to an hour or so to run, and there is no concern about downtime if a job fails to complete due to VM failure. What type of Compute Engine instance would be the most cost- effective to recommend to the team for this work?", options: { A: "Preemptible Instance", B: "Custom Machine", C: "Committed Use Instance", D: "Flexible App Engine Environment" }, correct: ["A"] },
  { id: 57, text: "You have sensitive data stored in three Cloud Storage buckets and have enabled data access logging. You want to verify activities for a particular user for these buckets, using the fewest possible steps. You need to verify the addition of metadata labels and which files have been viewed from those buckets. What should you do?", options: { A: "Using the GCP Console, filter the Activity log to view the information.", B: "Using the GCP Console, filter the Stackdriver log to view the information.", C: "View the bucket in the Storage section of the GCP Console.", D: "Create a trace in Stackdriver to view the information." }, correct: ["A"] },
  { id: 58, text: "After an incident at Blue Widget Corp, where a user accidentally deleted a project, corporate leaders are now demanding that projects be protected from accidental deletion. What tool (or service) will allow Steve, as the administrator, to enforce this standard?", options: { A: "GCP Cloud Identity and Access Management", B: "Role-Based Access Control", C: "Assigning Liens", D: "GCP Trust and Security" }, correct: ["C"] },
  { id: 59, text: "You are the project owner of a GCP project and want to delegate control to colleagues to manage buckets and files in Cloud Storage. You want to follow Google- recommended practices. Which IAM roles should you grant your colleagues?", options: { A: "Project Editor", B: "Storage Admin", C: "Storage Object Admin", D: "Storage Object Creator" }, correct: ["B"] },
  { id: 60, text: "Google App Engine has a second hosting option, called App Engine Flexible Environment. Which of the following best describes App Engine Flexible Environment?", options: { A: "The Flexible Environment supports App Engine applications on configurable Compute Engine instances.", B: "The Flexible Environment supports App Engine instances on third-party networks.", C: "The Flexible Environment supports applications on configurable GKE containers.", D: "The Flexible Environment supports managed functions as well as managed instances." }, correct: ["A"] },
  { id: 61, text: "You have an object in a Cloud Storage bucket that you want to share with an external company. The object contains sensitive data. You want access to the content to be removed after four hours. The external company does not have a Google account to which you can grant specific user-based access privileges. You want to use the most secure method that requires the fewest steps. What should you do?", options: { A: "Create a signed URL with a four-hour expiration and share the URL with the company.", B: "Set object access to ‘public’ and use object lifecycle management to remove the object after four hours.", C: "Configure the storage bucket as a static website and furnish the object's URL to the company. Delete the object from the storage bucket after four hours.", D: "Create a new Cloud Storage bucket specifically for the external company to access. Copy the obj2ct to that bucket. Delete the bucket after four hours have passed." }, correct: ["A"] },
  { id: 62, text: "Which statement regarding the cost of querying with Google BigQuery is correct?", options: { A: "BigQuery charges for processing the data in queries and for reading it.", B: "Querying data stored within BigQuery is less expensive than querying data stored outside of it, such as in Cloud Storage.", C: "You are not charged for querying data that is cached within BigQuery.", D: "The first 10 TB of data queries per month are free." }, correct: ["C"] },
  { id: 63, text: "You are creating a Google Kubernetes Engine (GKE) cluster with a cluster autoscaler feature enabled. You need to make sure that each node of the cluster will run a monitoring pod that sends container metrics to a third-party monitoring solution. What should you do?", options: { A: "Deploy the monitoring pod in a Stateful Set object.", B: "Deploy the monitoring pod in a Daemon Set object.", C: "Reference the monitoring pod in a Deployment object.", D: "Reference the monitoring pod in a cluster initializer at the GKE cluster creation time." }, correct: ["B"] },
  { id: 64, text: "Which of the following is not an IAM best practice?", options: { A: "Use primitive roles by default", B: "Grant roles at the smallest scope needed", C: "Restrict who has access to create and manage service accounts in your project", D: "Treat each component of your application as a separate trust boundary" }, correct: ["A"] },
  { id: 65, text: "You want to send and consume Cloud Pub/Sub messages from your App Engine application. The Cloud Pub/Sub API is currently disabled. You will use a service account to authenticate your application to the API. You want to make sure your application can use Cloud Pub/Sub. What should you do?", options: { A: "Enable the Cloud Pub/Sub API in the API Library on the GCP Console.", B: "Rely on the automatic enablement of the Cloud Pub/Sub API when the Service Account accesses it.", C: "Use Deployment Manager to deploy your application. Rely on the automatic enablement of all APIs used by the application being deployed.", D: "Grant the App Engine Default service account the role of Cloud Pub/Sub Admin. Have your application enable the API on the first connection to Cloud Pub/ Sub." }, correct: ["A"] },
  { id: 66, text: "A 5 TB persistent disk is attached to a standard Compute Engine instance. Currently, 2 TB of the total storage is used. The user took an initial snapshot yesterday, and 250 GB of the 2 TB now stored is new or updated data since that snapshot was taken. If the user creates a second snapshot of the instance disk now, approximately how large will the snapshot be (do not take snapshot data compression into account)?", options: { A: "250 GB", B: "21B", C: "2.25 TB", D: "STB" }, correct: ["A"] },
  { id: 67, text: "You need to monitor resources that are distributed over different projects in Google Cloud Platform. You want to consolidate reporting under the same Stackdriver Monitoring dashboard. What should you do?", options: { A: "Use Shared VPC to connect all projects, and link Stackdriver to one of the projects.", B: "For each project, create a Stackdriver account. In each project, create a service account for that project and grant it the role of Stackdriver Account Editor in all other projects.", C: "Configure a single Stackdriver account, and link all projects to the same account.", D: "Configure a single Stackdriver account for one of the projects. In Stackdriver, create a Group and add the other project names as criteria for that Group." }, correct: ["C"] },
  { id: 68, text: "Steven has been tasked with ensuring that only those people who actually need access to certain GCP resources have access. Which service should Steven be relying on to secure access to his organization's GCP resources?", options: { A: "Cloud IAM", B: "Cloud AD", C: "Directory Services", D: "RBAC" }, correct: ["A"] },
  { id: 69, text: "You are deploying an application to a Compute Engine VM in a managed instance group. The application must be running at all times, but only a single instance of the VM should run per GCP project. How should you configure the instance group?", options: { A: "Set autoscaling to On, set the minimum number of instances to 1, and then set the maximum number of instances to 1.", B: "Set autoscaling to Off, set the minimum number of instances to 1, and then set the maximum number of instances to 1.", C: "Set autoscaling to On, set the minimum number of instances to 1, and then set the maximum number of instances to 2.", D: "Set autoscaling to Off, set the minimum number of instances to 1, and then set the maximum number of instances to 2." }, correct: ["A"] },
  { id: 70, text: "Mike is a new cloud admin. He's been asked to stop one of two Windows VMs that are running a load balanced application in order to confirm that the load balancer is working. Which of the following will not be retained when Mike stops the VM instance?", options: { A: "Application State", B: "Configured Persistent Disks", C: "Internal IP", D: "MAC Address" }, correct: ["A"] },
  { id: 71, text: "You want to verify the IAM users and roles assigned within a GCP project named my-project. What should you do?", options: { A: "Run gcloud iam roles list. Review the output section.", B: "Run gcloud iam service-accounts list. Review the output section.", C: "Navigate to the project and then to the IAM section in the GCP Console. Review the members and roles.", D: "Navigate to the project and then to the Roles section in the GCP Console. Review the roles and status." }, correct: ["C"] },
  { id: 72, text: "David is the cloud admin for Blue Widget Corp. He has deployed a Linux VM called Linux01, and he needs to SSH to it from the console. Which command should David use to SSH to the VM?", options: { A: "gcloud ssh --project blue-widget-project -zone us-central1-a Linux01", B: "gcloud compute ssh --project blue-widget-project -zone us- central1-a Linux01", C: "gcloud connect ssh --project blue-widget-project -zone us- central1-a Linux01", D: "gcloud compute ssh -project blue-widget-project -zone us- central1-a Linux01" }, correct: ["B"] },
  { id: 73, text: "You need to create a new billing account and then link it with an existing Google Cloud Platform project. What should you do?", options: { A: "Verify that you are Project Billing Manager for the GCP project. Update the existing project to link it to the existing billing account.", B: "Verify that you are Project Billing Manager for the GCP project. Create a new billing account and link the new billing account to the existing project.", C: "Verify that you are Billing Administrator for the billing account. Create a new project and link the new project to the existing billing account.", D: "Verify that you are Billing Administrator for the billing account. Update the existing project to link it to the existing billing account." }, correct: ["B"] },
  { id: 74, text: "You are a member of your organization's Google Cloud Organzition and you use the Organization node to manage resources. You've been asked to create a new billing account. To perform this task, youmustalsobea__", options: { A: "Billing Account Creator", B: "Billing Account Operator", C: "Billing Manager", D: "Billing Account Manager" }, correct: ["A"] },
  { id: 76, text: "David is the cloud administrator for the Blue Widget Company. He has been asked to protect his organization's public-facing web application from DDoS attacks. Which service should Michael take advantage of?", options: { A: "Traffic Manager", B: "Traffic Director", C: "Cloud Armor", D: "DDoS Shield" }, correct: ["C"] },
  { id: 77, text: "You created a Google Cloud Platform project with an App Engine application inside the project. You initially configured the application to be served from the us- central region. Now you want the application to be served from the asia- northeast1 region. What should you do?", options: { A: "Change the default region property setting in the existing GCP project to asia-northeast1.", B: "Change the region property setting in the existing App Engine application from us-central to asia- northeast1.", C: "Create a second App Engine application in the existing GCP project and specify asia-northeast1 as the region to serve your application.", D: "Create a new GCP project and create an App Engine application inside this new project. Specify asia-northeast1 as the region to serve your application." }, correct: ["D"] },
  { id: 78, text: "Which of the following practices can help you develop more secure software? (Select 3 answers.)", options: { A: "Peer review of code", B: "Integrating static code analysis tools into your CI/CD pipeline", C: "Penetration tests", D: "Encrypting your source code" }, correct: ["A", "B", "C"] },
  { id: 79, text: "You need to grant access for three users so that they can view and edit table data on a Cloud Spanner instance. What should you do?", options: { A: "Run gcloud iam roles describe roles/spanner.databaseUser. Add the users to the role.", B: "Run gcloud iam roles describe roles/spanner.databaseUser. Add the users to a new group. Add the group to the role.", C: "Run gcloud iam roles describe roles/spanner.viewer - -project my-project. Add the users to the role.", D: "Run gcloud iam roles describe roles/spanner.viewer - -project my-project. Add the users to a new group. Add the group to the role." }, correct: ["B"] },
  { id: 80, text: "Catie, the cloud admin at Blue Widget Corp, has been asked to build a VPC network in GCP. This VPC network will be connected to the on-prem network via the Cloud VPN service. The address space for the on-prem network spans the CIDR block of 10.128.0.0/9. After deploying the VPC network, Laurie finds that there are issues with the VPN connectivity. What could be causing the VPN connectivity issues?", options: { A: "Catie deployed an Auto Mode VPC Network", B: "Catie deployed a Custom Mode VPC Network", C: "The Cloud VPN service doesn't allow you to connect a VPC to an on-prem network", D: "None of the Above" }, correct: ["A"] },
  { id: 81, text: "You create a new Google Kubernetes Engine (GKE) cluster and want to make sure that it always runs a supported and stable version of Kubernetes. What should you do?", options: { A: "Enable the Node Auto-Repair feature for your GKE cluster.", B: "Enable the Node Auto-Upgrades feature for your GKE cluster.", C: "Select the latest available cluster version for your GKE cluster.", D: "Select Container-Optimized OS (cos) as a node image for your GKE cluster." }, correct: ["B"] },
  { id: 82, text: "What is the primary function of Google BigQuery?", options: { A: "Storing and querying massive datasets", B: "Providing machine learning services", C: "Implementing real-time messaging", D: "Monitoring GCP resources" }, correct: ["A"] },
  { id: 83, text: "You have an instance group that you want to load balance. You want the load balancer to terminate the client SSL session. The instance group is used to serve a public web application over HTTPS. You want to follow Google- recommended practices. What should you do?", options: { A: "Configure an HTTP(S) load balancer.", B: "Configure an internal TCP load balancer.", C: "Configure an external SSL proxy load balancer.", D: "Configure an external TCP proxy load balancer." }, correct: ["A"] },
  { id: 84, text: "Cloud Key Management Service (KMS) generates encryption keys which you can use, rotate and then destroy. There are four specific key states for KMS keys: 1.Enabled 2.Disabled 3.Scheduled for destruction 4.Destroyed. Keys in several stages can change from one state to another, but at which state(s) can a key no longer be returned to an \"enabled\" state?", options: { A: "Disabled", B: "Scheduled for destruction", C: "Destroyed", D: "Both scheduled for destruction and destroyed" }, correct: ["C"] },
  { id: 85, text: "You have 32 GB of data in a single file that you need to upload to a Nearline Storage bucket. The WAN connection you are using is rated at 1 Gbps, and you are the only one on the connection. You want to use as much of the rated 1 Gbps as possible to transfer the file rapidly. How should you upload the file?", options: { A: "Use the GCP Console to transfer the file instead of gsutil.", B: "Enable parallel composite uploads using gsutil on the file transfer.", C: "Decrease the TCP window size on the machine initiating the transfer.", D: "Change the storage class of the bucket from Nearline to Multi-Regional." }, correct: ["B"] },
  { id: 86, text: "Cloud Key Management Service (KMS) generates encryption keys which you can use, rotate and then destroy. There are four specific key states for KMS keys: 1.Enabled 2.Disabled 3.Scheduled for destruction 4 Destroyed. Keys in several stages can change from one state to another, but at which state(s) can a key no longer be returned to an \"enabled\" state?", options: { A: "Disabled", B: "Scheduled for destruction", C: "Destroyed", D: "Both scheduled for destruction and destroyed" }, correct: ["C"] },
  { id: 87, text: "You've deployed a microservice called myapp1 to a Google Kubernetes Engine cluster using the YAML file specified below: You need to refactor this configuration so that the database apiversica: appe/v1 password is not stored in plain text. You want to follow Google- kind: Deployment recommended practices. What should you do? pn “Puelector:", options: { A: "Store the database password inside the Docker image of the Ena container, not in the YAML file. replicas: 2", B: "Store the database password inside a Secret object. Modify Era: the YAML file to populate the DB_LPASSWORD environment Tabels: variable from the Secret. Pa ——", C: "Store the database password inside a ConfigMap object. a Modify the YAML file to populate the DB_LPASSWORD image: gcr.io/my-company-repo/myapp1:1.4 environment variable from the ConfigMap. SMname: DB_PASSWORD", D: "Store the database password in a file inside a Kubernetes Value: \"t0ugh2guess!™ persistent volume, and use a persistent volume claim to mount PecontainerPort: #080 the volume to the container." }, correct: ["B"] },
  { id: 88, text: "Brian is the cloud admin for the Blue Widget Company. He needs to upload a file, called \"FinanceReport.xls\", from his workstation to GCP. The file needs to be uploaded to a bucket, called “financereports\", in Cloud Storage. Which command below will allow Brian to upload the file?", options: { A: "gsutil cp desktop/FinanceReport.xls gs://financereports/", B: "gsutil cp desktop/FinanceReport.xls g://financereports/", C: "gsupload cp desktop/FinanceReport.xls gs://financereports/", D: "gsutil desktop/FinanceReport.xls financereports" }, correct: ["A"] },
  { id: 89, text: "You are running an application on multiple virtual machines within a managed instance group and have autoscaling enabled. The autoscaling policy is configured so that additional instances are added to the group if the CPU utilization of instances goes above 80%. VMs are added until the instance group reaches its maximum limit of five VMs or until CPU utilization of instances lowers to 80%. The initial delay for HTTP health checks against the instances is set to 30 seconds. The virtual machine instances take around three minutes to become available for users. You observe that when the instance group autoscales, it adds more instances then necessary to support the levels of end-user traffic. You want to properly maintain instance group sizes when autoscaling. What should you do?", options: { A: "Set the maximum number of instances to 1.", B: "Decrease the maximum number of instances to 3.", C: "Use a TCP health check instead of an HTTP health check.", D: "Increase the initial delay of the HTTP health check to 200 seconds." }, correct: ["D"] },
  { id: 90, text: "How does Google Compute Engine match certain types of traffic and forward it to a load balancer?", options: { A: "By using forwarding rules", B: "By using target pools", C: "By performing health checks", D: "By using routing tables" }, correct: ["A"] },
  { id: 91, text: "You need to select and configure compute resources for a set of batch processing jobs. These jobs take around 2 hours to complete and are run nightly. You want to minimize service costs. What should you do?", options: { A: "Select Google Kubernetes Engine. Use a single-node cluster with a small instance type.", B: "Select Google Kubernetes Engine. Use a three-node cluster with micro instance types.", C: "Select Compute Engine. Use preemptible VM instances of the appropriate standard machine type.", D: "Select Compute Engine. Use VM instance types that support micro bursting." }, correct: ["C"] },
  { id: 92, text: "When setting up a domain with Cloud DNS, what steps are recommended? (Choose 2 answers)", options: { A: "Avoid registering parent domains that are not hosted on Cloud DNS.", B: "Register the parent domain first, then create records for any subdomains.", C: "_ If subdomains will be hosted on Cloud DNS but parent domains will not, then register the parent domains anyhow.", D: "Register the parent domain only - subdomain records are not required." }, correct: ["D"] },
  { id: 93, text: "You recently deployed a new version of an application to App Engine and then discovered a bug in the release. You need to immediately revert to the prior version of the application. What should you do?", options: { A: "Run gcloud app restore.", B: "On the App Engine page of the GCP Console, select the application that needs to be reverted and click Revert.", C: "On the App Engine Versions page of the GCP Console, route 100% of the traffic to the previous version.", D: "Deploy the original version as a separate application. Then go to App Engine settings and split traffic between applications so that the original version serves 100% of the requests." }, correct: ["C"] },
  { id: 94, text: "David is the cloud admin for Blue Widget Corp. He needs to stop the APP01 virtual machine instance to test his load balancer. Which command below should David use?", options: { A: "gcloud compute stop APP01 --zone us --central1-a", B: "gcloud instances stop APP01 --zone us-central1-a", C: "gcloud compute instances stop APP01 --zone us-central1-a", D: "gcloud stop APP01 --zone us-central1-a" }, correct: ["C"] },
  { id: 95, text: "You deployed an App Engine application using gcloud app deploy, but it did not deploy to the intended project. You want to find out why this happened and where the application deployed. What should you do?", options: { A: "Check the app.yaml file for your application and check project settings.", B: "Check the web-application.xml file for your application and check project settings.", C: "Go to Deployment Manager and review settings for deployment of applications.", D: "Go to Cloud Shell and run gcloud config list to review the Google Cloud configuration used for deployment." }, correct: ["D"] },
  { id: 96, text: "Dave has been tasked with migrating the organization's MongoDB data to a managed document database service in Google Cloud Platform. Which GCP storage product will be most relevant to Dave's needs?", options: { A: "BigQuery", B: "CloudSpanner", C: "Memorystore", D: "Firestore" }, correct: ["D"] },
  { id: 97, text: "You want to configure 10 Compute Engine instances for availability when maintenance occurs. Your requirements state that these instances should attempt to automatically restart if they crash. Also, the instances should be highly available including during system maintenance. What should you do?", options: { A: "Create an instance template for the instances. Set the ‘Automatic Restart’ to on. Set the ‘On-host maintenance’ to Migrate VM instance. Add the instance template to an instance group.", B: "Create an instance template for the instances. Set ‘Automatic Restart’ to off. Set ‘On-host maintenance’ to Terminate VM instances. Add the instance template to an instance group.", C: "Create an instance group for the instances. Set the ‘Auto healing’ health check to healthy (HTTP).", D: "Create an instance group for the instance. Verify that the ‘Advanced creation options’ setting for ‘do not retry machine creation’ is set to off." }, correct: ["A"] },
  { id: 98, text: "Steven has been asked to provision storage for archival purposes. The data that is archived will be accessed no more than once quarterly. Which type of storage should Steven provision?", options: { A: "VM-attachable persistent disk storage", B: "Cloud Storage Nearline", C: "Cloud Storage Coldline", D: "None of the Above" }, correct: ["C"] },
  { id: 99, text: "You host a static website on Cloud Storage. Recently, you began to include links to PDF files on this site. Currently, when users click on the links to these PDF files, their browsers prompt them to save the file onto their local system. Instead, you want the clicked PDF files to be displayed within the browser window directly, without prompting the user to save the file locally. What should you do?", options: { A: "Enable Cloud CDN on the website frontend.", B: "Enable ‘Share publicly’ on the PDF file objects.", C: "Set Content-Type metadata to application/pdf on the PDF file objects.", D: "Add a label to the storage bucket with a key of Content-Type and value of application/pdf." }, correct: ["C"] },
  { id: 100, text: "You have a virtual machine that is currently configured with 2 vCPUs and 4 GB of memory. It is running out of memory. You want to upgrade the virtual machine to have 8 GB of memory. What should you do?", options: { A: "Rely on live migration to move the workload to a machine with more memory.", B: "Use gcloud to add metadata to the VM. Set the key to required-memory- size and the value to 8 GB.", C: "Stop the VM, change the machine type to n1-standard-8, and start the VM.", D: "Stop the VM, increase the memory to 8 GB, and start the VM." }, correct: ["D"] },
  { id: 101, text: "You have production and test workloads that you want to deploy on Compute Engine. Production VMs need to be in a different subnet than the test VMs. All the VMs must be able to reach each other over Internal IP without creating additional routes. You need to set up VPC and the 2 subnets. Which configuration meets these requirements?", options: { A: "Create a single custom VPC with 2 subnets. Create each subnet in a different region and with a different CIDR range.", B: "Create a single custom VPC with 2 subnets. Create each subnet in the same region and with the same CIDR range.", C: "Create 2 custom VPCs, each with a single subnet. Create each subnet in a different region and with a different CIDR range.", D: "Create 2 custom VPCs, each with a single subnet. Create each subnet in the same region and with the same CIDR range." }, correct: ["A"] },
  { id: 102, text: "You need to create an autoscaling managed instance group for an HTTPS web application. You want to make sure that unhealthy VMs are recreated. What should you do?", options: { A: "Create a health check on port 443 and use that when creating the Managed Instance Group.", B: "Select Multi-Zone instead of Single-Zone when creating the Managed Instance Group.", C: "In the Instance Template, add the label ‘health-check’.", D: "In the Instance Template, add a startup script that sends a heartbeat to the metadata server." }, correct: ["A"] },
  { id: 103, text: "Your company has a Google Cloud Platform project that uses BigQuery for data warehousing. Your data science team changes frequently and has few members. You need to allow members of this team to perform queries. You want to follow Google-recommended practices. What should you do?", options: { A: "1. Create an IAM entry for each data scientist's user account. 2. Assign the BigQuery jobUser role to the group.", B: "1. Create an IAM entry for each data scientist's user account. 2. Assign the BigQuery dataViewer user role to the group.", C: "1. Create a dedicated Google group in Cloud Identity. 2. Add each data scientist's user account to the group. 3. Assign the BigQuery jobUser role to the group.", D: "1. Create a dedicated Google group in Cloud Identity. 2. Add each data scientist's user account to the group. 3. Assign the BigQuery dataViewer user role to the group." }, correct: ["C"] },
  { id: 104, text: "You are given a project with a single Virtual Private Cloud (VPC) and a single subnetwork in the us-central1 region. There is a Compute Engine instance hosting an application in this subnetwork. You need to deploy a new instance in the same project in the europe-west1 region. This new instance needs access to the application. You want to follow Google- recommended practices. What should you do?", options: { A: "1. Create a subnetwork in the same VPC, in europe-west1. 2. Create the new instance in the new subnetwork and use the first instance's private address as the endpoint.", B: "1. Create a VPC and a subnetwork in europe-west1. 2. Expose the application with an internal load balancer. 3. Create the new instance in the new subnetwork and use the load balancer's address as the endpoint.", C: "1. Create a subnetwork in the same VPC, in europe-west1. 2. Use Cloud VPN to connect the two subnetworks. 3. Create the new instance in the new subnetwork and use the first instance's private address as the endpoint.", D: "1. Create a VPC and a subnetwork in europe-west1. 2. Peer the 2 VPCs. 3. Create the new instance in the new subnetwork and use the first instance's private address as the endpoint." }, correct: ["A"] },
  { id: 105, text: "Your projects incurred more costs than you expected last month. Your research reveals that a development GKE container emitted a huge number of logs, which resulted in higher costs. You want to disable the logs quickly using the minimum number of steps. What should you do?", options: { A: "1. Go to the Logs ingestion window in Stackdriver Logging, and disable the log source for the GKE container resource.", B: "1. Go to the Logs ingestion window in Stackdriver Logging, and disable the log source for the GKE Cluster Operations resource.", C: "1. Go to the GKE console, and delete existing clusters. 2. Recreate a new cluster. 3. Clear the option to enable legacy Stackdriver Logging.", D: "1. Go to the GKE console, and delete existing clusters. 2. Recreate a new cluster. 3. Clear the option to enable legacy Stackdriver Monitoring." }, correct: ["A"] },
  { id: 106, text: "You have a website hosted on App Engine standard environment. You want 1% of your users to see a new test version of the website. You want to minimize complexity. What should you do?", options: { A: "Deploy the new version in the same application and use the --migrate option.", B: "Deploy the new version in the same application and use the --splits option to give a weight of 99 to the current version and a weight of 1 to the new version.", C: "Create a new App Engine application in the same project. Deploy the new version in that application. Use the App Engine library to proxy 1% of the requests to the new version.", D: "Create a new App Engine application in the same project. Deploy the new version in that application. Configure your network load balancer to send 1% of the traffic to that new application." }, correct: ["B"] },
  { id: 107, text: "You have a web application deployed as a managed instance group. You have a new version of the application to gradually deploy. Your web application is currently receiving live web traffic. You want to ensure that the available capacity does not decrease during the deployment. What should you do?", options: { A: "Perform a rolling-action start-update with maxSurge set to 0 and maxUnavailable set to 1.", B: "Perform a rolling-action start-update with maxSurge set to 1 and maxUnavailable set to 0.", C: "Create a new managed instance group with an updated instance template. Add the group to the backend service for the load balancer. When all instances in the new managed instance group are healthy, delete the old managed instance group.", D: "Create a new instance template with the new application version. Update the existing managed instance group with the new instance template. Delete the instances in the managed instance group to allow the managed instance group to recreate the instance using the new instance template." }, correct: ["B"] },
  { id: 108, text: "You are building an application that stores relational data from users. Users across the globe will use this application. Your CTO is concerned about the scaling requirements because the size of the user base is unknown. You need to implement a database solution that can scale with your user growth with minimum configuration changes. Which storage solution should you use?", options: { A: "Cloud SQL", B: "Cloud Spanner", C: "Cloud Firestore", D: "Cloud Datastore" }, correct: ["B"] },
  { id: 109, text: "You are the organization and billing administrator for your company. The engineering team has the Project Creator role on the organization. You do not want the engineering team to be able to link projects to the billing account. Only the finance team should be able to link a project to a billing account, but they should not be able to make any other changes to projects. What should you do?", options: { A: "Assign the finance team only the Billing Account User role on the billing account.", B: "Assign the engineering team only the Billing Account User role on the billing account.", C: "Assign the finance team the Billing Account User role on the billing account and the Project Billing Manager role on the organization.", D: "Assign the engineering team the Billing Account User role on the billing account and the Project Billing Manager role on the organization." }, correct: ["C"] },
  { id: 110, text: "You have an application running in Google Kubernetes Engine (GKE) with cluster autoscaling enabled. The application exposes a TCP endpoint. There are several replicas of this application. You have a Compute Engine instance in the same region, but in another Virtual Private Cloud (VPC), called gce-network, that has no overlapping IP ranges with the first VPC. This instance needs to connect to the application on GKE. You want to minimize effort. What should you do?", options: { A: "1. In GKE, create a Service of type Load Balancer that uses the application's Pods as backend. 2. Set the service's externalTrafficPolicy to Cluster. 3. Configure the Compute Engine instance to use the address of the load balancer that has been created.", B: "1. In GKE, create a Service of type Node Port that uses the application's Pods as backend. 2. Create a Compute Engine instance called proxy with 2 network interfaces, one in each VPC. 3. Use iptables on this instance to forward traffic from gce-network to the GKE nodes. 4. Configure the Compute Engine instance to use the address of proxy in gce-network as endpoint.", C: "1. In GKE, create a Service of type Load Balancer that uses the application's Pods as backend. 2. Add an annotation to this service: cloud.google.com/load-balancer-type: Internal 3. Peer the two VPCs together. 4. Configure the Compute Engine instance to use the address of the load balancer that has been created.", D: "1. In GKE, create a Service of type Load Balancer that uses the application's Pods as backend. 2. Add a Cloud Armor Security Policy to the load balancer that whitelists the internal IPs of the MIG's instances. 3. Configure the Compute Engine instance to use the address of the load balancer that has been created." }, correct: ["A"] },
  { id: 111, text: "Your organization is a financial company that needs to store audit log files for 3 years. Your organization has hundreds of Google Cloud projects. You need to implement a cost-effective approach for log file retention. What should you do?", options: { A: "Create an export to the sink that saves logs from Cloud Audit to BigQuery.", B: "Create an export to the sink that saves logs from Cloud Audit to a Coldline Storage bucket.", C: "Write a custom script that uses logging API to copy the logs from Stackdriver logs to BigQuery.", D: "Export these logs to Cloud Pub/Sub and write a Cloud Dataflow pipeline to store logs to Cloud SQL." }, correct: ["B"] },
  { id: 112, text: "You want to run a single caching HTTP reverse proxy on GCP for a latency-sensitive website. This specific reverse proxy consumes almost no CPU. You want to have a 30-GB in-memory cache, and need an additional 2 GB of memory for the rest of the processes. You want to minimize cost. How should you run this reverse proxy?", options: { A: "Create a Cloud Memorystore for Redis instance with 32-GB capacity.", B: "Run it on Compute Engine, and choose a custom instance type with 6 vCPUs and 32 GB of memory.", C: "Package it in a container image, and run it on Kubernetes Engine, using n1-standard-32 instances as nodes.", D: "Run it on Compute Engine, choose the instance type n1-standard-1, and add an SSD persistent disk of 32 GB." }, correct: ["B"] },
  { id: 113, text: "You are hosting an application on bare-metal servers in your own data center. The application needs access to Cloud Storage. However, security policies prevent the servers hosting the application from having public IP addresses or access to the internet. You want to follow Google-recommended practices to provide the application with access to Cloud Storage. What should you do?", options: { A: "1. Use nslookup to get the IP address for storage.googleapis.com. 2. Negotiate with the security team to be able to give a public IP address to the servers. 3. Only allow egress traffic from those servers to the IP addresses for storage.googleapis.com.", B: "1. Using Cloud VPN, create a VPN tunnel to a Virtual Private Cloud (VPC) in Google Cloud. 2. In this VPC, create a Compute Engine instance and install the Squid proxy server on this instance. 3. Configure your servers to use that instance as a proxy to access Cloud Storage.", C: "1. Use Migrate for Compute Engine (formerly known as Velostrata) to migrate those servers to Comput? Engine. 2. Create an internal load balancer (ILB) that uses storage.googleapis.com as backend. 3. Configure your new instances to use this ILB as proxy.", D: "1. Using Cloud VPN or Interconnect, create a tunnel to a VPC in Google Cloud. 2. Use Cloud Router to create a custom route advertisement for 199.36.153.4/30. Announce that network to your on-premises network through the VPN tunnel. 3. In your on-premises network, configure your DNS server to resolve *.googleapis.com as a CNAME to restricted.googleapis.com." }, correct: ["D"] },
  { id: 114, text: "You want to deploy an application on Cloud Run that processes messages from a Cloud Pub/Sub topic. You want to follow Google-recommended practices. What should you do?", options: { A: "1. Create a Cloud Function that uses a Cloud Pub/Sub trigger on that topic. 2. Call your application on Cloud Run from the Cloud Function for every message.", B: "1. Grant the Pub/Sub Subscriber role to the service account used by Cloud Run. 2. Create a Cloud Pub/Sub subscription for that topic. 3. Make your application pull messages from that subscription.", C: "1. Create a service account. 2. Give the Cloud Run Invoker role to that service account for your Cloud Run application. 3. Create a Cloud Pub/Sub subscription that uses that service account and uses your Cloud Run application as the push endpoint.", D: "1. Deploy your application on Cloud Run on GKE with the connectivity set to Internal. 2. Create a Cloud Pub/Sub subscription for that topic. 3. In the same Google Kubernetes Engine cluster as your application, deploy a container that takes the messages and sends them to your application." }, correct: ["C"] },
  { id: 115, text: "You need to deploy an application, which is packaged in a container image, in a new project. The application exposes an HTTP endpoint and receives very few requests per day. You want to minimize costs. What should you do?", options: { A: "Deploy the container on Cloud Run.", B: "Deploy the container on Cloud Run on GKE.", C: "Deploy the container on App Engine Flexible.", D: "Deploy the container on GKE with cluster autoscaling and horizontal pod autoscaling enabled." }, correct: ["A"] },
  { id: 116, text: "Your company has an existing GCP organization with hundreds of projects and a billing account. Your company recently acquired another company that also has hundreds of projects and its own billing account. You would like to consolidate all GCP costs of both GCP organizations onto a single invoice. You would like to consolidate all costs as of tomorrow. What should you do?", options: { A: "Link the acquired company's projects to your company's billing account.", B: "Configure the acquired company's billing account and your company's billing account to export the billing data into the same BigQuery dataset.", C: "Migrate the acquired company's projects into your company's GCP organization. Link the migrated projects to your company's billing account.", D: "Create a new GCP organization and a new billing account. Migrate the acquired company's projects and your company's projects into the new GCP organization and link the projects to the new billing account." }, correct: ["A"] },
  { id: 117, text: "You built an application on Google Cloud that uses Cloud Spanner. Your support team needs to monitor the environment but should not have access to table data. You need a streamlined solution to grant the correct permissions to your support team, and you want to follow Google-recommended practices. What should you do?", options: { A: "Add the support team group to the roles/monitoring.viewer role", B: "Add the support team group to the roles/spanner.databaseUser role.", C: "Add the support team group to the roles/spanner.databaseReader role.", D: "Add the support team group to the roles/stackdriver.accounts.viewer role." }, correct: ["A"] },
  { id: 118, text: "For analysis purposes, you need to send all the logs from all of your Compute Engine instances to a BigQuery dataset called platform-logs. You have already installed the Cloud Logging agent on all the instances. You want to minimize cost. What should you do?", options: { A: "1. Give the BigQuery Data Editor role on the platform-logs dataset to the service accounts used by your instances. 2. Update your instances’ metadata to add the following value: logs-destination: bq://platform-logs.", B: "1. In Cloud Logging, create a logs export with a Cloud Pub/Sub topic called logs as a sink. 2. Create a Cloud Function that is triggered by messages in the logs topic. 3. Configure that Cloud Function to drop logs that are not from Compute Engine and to insert Compute Engine logs in the platform-logs dataset.", C: "1. In Cloud Logging, create a filter to view only Compute Engine logs. 2. Click Create Export. 3. Choose BigQuery as Sink Service, and the platform-logs dataset as Sink Destination.", D: "1. Create a Cloud Function that has the BigQuery User role on the platform-logs dataset. 2. Configure this Cloud Function to create a BigQuery Job that executes this query: INSERT INTO dataset.platform-logs (timestamp, log) SELECT timestamp, log FROM compute.logs WHERE timestamp > DATE_SUB(CURRENT_DATE(), INTERVAL 1 DAY) 3. Use Cloud Scheduler to trigger this Cloud Function once a day." }, correct: ["C"] },
  { id: 119, text: "You are using Deployment Manager to create a Google Kubernetes Engine cluster. Using the same Deployment Manager deployment, you also want to create a Daemon Set in the kube-system namespace of the cluster. You want a solution that uses the fewest possible services. What should you do?", options: { A: "Add the cluster's API as a new Type Provider in Deployment Manager, and use the new type to create the Daemon Set.", B: "Use the Deployment Manager Runtime Configurator to create a new Config resource that contains the Daemon Set definition.", C: "With Deployment Manager, create a Compute Engine instance with a startup script that uses kubectl to create the Daemon Set.", D: "In the cluster's definition in Deployment Manager, add a metadata that has kube-system as key and the Daemon Set manifest as value." }, correct: ["A"] },
  { id: 120, text: "You are building an application that will run in your data center. The application will use Google Cloud Platform (GCP) services like AutoML. You created a service account that has appropriate access to AutoML. You need to enable authentication to the APIs from your on-premises environment. What should you do?", options: { A: "Use service account credentials in your on-premises application.", B: "Use gcloud to create a key file for the service account that has appropriate permissions.", C: "Set up direct interconnect between your data center and Google Cloud Platform to enable authentication for your on-premises applications.", D: "Go to the IAM & admin console, grant a user account permissions similar to the service account permissions, and use this user account for authentication from your data center." }, correct: ["B"] },
  { id: 121, text: "You are using Container Registry to centrally store your company's container images in a separate project. In another project, you want to create a Google Kubernetes Engine (GKE) cluster. You want to ensure that Kubernetes can download images from Container Registry. What should you do?", options: { A: "In the project where the images are stored, grant the Storage Object Viewer IAM role to the service account used by the Kubernetes nodes.", B: "When you create the GKE cluster, choose the Allow full access to all Cloud APIs option under ‘Access scopes’.", C: "Create a service account, and give it access to Cloud Storage. Create a P12 key for this service account and use it as an imagePullSecrets in Kubernetes.", D: "Configure the ACLs on each image in Cloud Storage to give read-only access to the default Compute Engine service account." }, correct: ["A"] },
  { id: 122, text: "You deployed a new application inside your Google Kubernetes Engine cluster using the YAML file specified below. You check the status of the deployed pods and notice that one of apiversion: apps/vi apiversion: vi them is still in PENDING status: kind: Deployment kind: Service metadata: metadata: name: myapp-deployment name: myapp-service kubectl get pods -1 app=myapp spec: spec: NAME READY STATUS RESTART AGE selector: ports: myapp-deployment-S8ddbbb995-1p8ém 0/1 Pending 0 on matchLabels: - port: 8000 myapp-deployment-S8ddbbb995-qjpkg wi Running 0 om app: myapp targetPort: 80 replicas: 2 protocol: TCP template: selector: You want to find out why the pod is stuck in pending status. What aicente S22? BYSEE should you do? app: myapp spec:", options: { A: "Review details of the myapp-service Service object and check containers: for error messages. a . . . image: myapp:1.1", B: "Review details of the myapp-deployment Deployment object and ports: check for error messages. ~ containerPort: 80", C: "Review details of myapp-deployment-58ddbbb995-Ip86m Pod and check for warning messages.", D: "View logs of the container in myapp-deployment-58ddbbb995- Ip86m pod and check for warning messages." }, correct: ["C"] },
  { id: 123, text: "You are setting up a Windows VM on Compute Engine and want to make sure you can log in to the VM via RDP. What should you do?", options: { A: "After the VM has been created, use your Google Account credentials to log in into the VM.", B: "After the VM has been created, use gcloud compute reset-windows-password to retrieve the login credentials for the VM.", C: "When creating the VM, add metadata to the instance using 'windows-password' as the key and a password as the value.", D: "After the VM has been created, download the JSON private key for the default Compute Engine service account. Use the credentials in the JSON file to log in to the VM." }, correct: ["B"] },
  { id: 124, text: "You want to configure an SSH connection to a single Compute Engine instance for users in the dev1 group. This instance is the only resource in this particular Google Cloud Platform project that the dev1 users should be able to connect to. What should you do?", options: { A: "Set metadata to enable-oslogin=true for the instance. Grant the dev1 group the compute.osLogin role. Direct them to use the Cloud Shell to ssh to that instance.", B: "Set metadata to enable-oslogin=true for the instance. Set the service account to no service account for that instance. Direct them to use the Cloud Shell to ssh to that instance.", C: "Enable block project wide keys for the instance. Generate an SSH key for each user in the dev1 group. Distribute the keys to dev1 users and direct them to use their third-party tools to connect.", D: "Enable block project wide keys for the instance. Generate an SSH key and associate the key with that instance. Distribute the key to dev1 users and direct them to use their third-party tools to connect." }, correct: ["A"] },
  { id: 125, text: "You need to produce a list of the enabled Google Cloud Platform APIs for a GCP project using the gcloud command line in the Cloud Shell. The project name is my-project. What should you do?", options: { A: "Run gcloud projects list to get the project ID, and then run gcloud services list --project <project ID>.", B: "Run gcloud init to set the current project to my-project, and then run gcloud services list -available.", C: "Run gcloud info to view the account value, and then run gcloud services list -account <Account>.", D: "Run gcloud projects describe <project ID> to verify the project value, and then run gcloud services list -- available." }, correct: ["A"] },
  { id: 126, text: "You are building a new version of an application hosted in an App Engine environment. You want to test the new version with 1% of users before you completely switch your application over to the new version. What should you do?", options: { A: "Deploy a new version of your application in Google Kubernetes Engine instead of App Engine and then use GCP Console to split traffic.", B: "Deploy a new version of your application in a Compute Engine instance instead of App Engine and then use GCP Console to split traffic.", C: "Deploy a new version as a separate app in App Engine. Then configure App Engine using GCP Console to split traffic between the two apps.", D: "Deploy a new version of your application in App Engine. Then go to App Engine settings in GCP Console and split traffic between the current version and newly deployed versions accordingly." }, correct: ["D"] },
  { id: 127, text: "You need to provide a cost estimate for a Kubernetes cluster using the GCP pricing calculator for Kubernetes. Your workload requires high IOPs, and you will also be using disk snapshots. You start by entering the number of nodes, average hours, and average days. What should you do next?", options: { A: "Fill in local SSD. Fill in persistent disk storage and snapshot storage.", B: "Fill in local SSD. Add estimated cost for cluster management.", C: "Select Add GPUs. Fill in persistent disk storage and snapshot storage.", D: "Select Add GPUs. Add estimated cost for cluster management." }, correct: ["A"] },
  { id: 128, text: "You are using Google Kubernetes Engine with autoscaling enabled to host a new application. You want to expose this new application to the public, using HTTPS on a public IP address. What should you do?", options: { A: "Create a Kubernetes Service of type Node Port for your application, and a Kubernetes Ingress to expose this Service via a Cloud Load Balancer.", B: "Create a Kubernetes Service of type Cluster IP for your application. Configure the public DNS name of your application using the IP of this Service.", C: "Create a Kubernetes Service of type Node Port to expose the application on port 443 of each node of the Kubernetes cluster. Configure the public DNS name of your application with the IP of every node of the cluster to achieve load-balancing.", D: "Create a HAProxy pod in the cluster to load-balance the traffic to all the pods of the application. Forwaid the public traffic to HAProxy with an iptable rule. Configure the DNS name of your application using the public IP of the node HAProxy is running on." }, correct: ["A"] },
  { id: 129, text: "You need to enable traffic between multiple groups of Compute Engine instances that are currently running two different GCP projects. Each group of Compute Engine instances is running in its own VPC. What should you do?", options: { A: "Verify that both projects are in a GCP Organization. Create a new VPC and add all instances.", B: "Verify that both projects are in a GCP Organization. Share the VPC from one project and request that the Compute Engine instances in the other project use this shared VPC.", C: "Verify that you are the Project Administrator of both projects. Create two new VPCs and add all instances.", D: "Verify that you are the Project Administrator of both projects. Create a new VPC and add all instances." }, correct: ["B"] },
  { id: 130, text: "You want to add a new auditor to a Google Cloud Platform project. The auditor should be allowed to read, but not modify, all project items. How should you configure the auditor's permissions?", options: { A: "Create a custom role with view-only project permissions. Add the user's account to the custom role.", B: "Create a custom role with view-only service permissions. Add the user's account to the custom role.", C: "Select the built-in IAM project Viewer role. Add the user's account to this role.", D: "Select the built-in IAM service Viewer role. Add the user's account to this role." }, correct: ["C"] },
  { id: 131, text: "You are operating a Google Kubernetes Engine (GKE) cluster for your company where different teams can run non- production workloads. Your Machine Learning (ML) team needs access to Nvidia Tesla P100 GPUs to train their models. You want to minimize effort and cost. What should you do?", options: { A: "Ask your ML team to add the €aaccelerator: gpu€ aannotation to their pod specification.", B: "Recreate all the nodes of the GKE cluster to enable GPUs on all of them.", C: "Create your own Kubernetes cluster on top of Compute Engine with nodes that have GPUs. Dedicate this cluster to your ML team.", D: "Add a new, GPU-enabled, node pool to the GKE cluster. Ask your ML team to add the cloud.google.com/gke -accelerator: nvidia-tesla-p100 nodeSelector to their pod specification." }, correct: ["D"] },
  { id: 132, text: "Your VMs are running in a subnet that has a subnet mask of 255.255.255.240. The current subnet has no more free IP addresses and you require an additional 10 IP addresses for new VMs. The existing and new VMs should all be able to reach each other without additional routes. What should you do?", options: { A: "Use gcloud to expand the IP range of the current subnet.", B: "Delete the subnet, and recreate it using a wider range of IP addresses.", C: "Create a new project. Use Shared VPC to share the current network with the new project.", D: "Create a new subnet with the same starting IP but a wider range to overwrite the current subnet." }, correct: ["A"] },
  { id: 133, text: "Your organization uses G Suite for communication and collaboration. All users in your organization have a G Suite account. You want to grant some G Suite users access to your Cloud Platform project. What should you do?", options: { A: "Enable Cloud Identity in the GCP Console for your domain.", B: "Grant them the required IAM roles using their G Suite email address.", C: "Create a CSV sheet with all users’ email addresses. Use the gcloud command line tool to convert them into Google Cloud Platform accounts.", D: "In the G Suite console, add the users to a special group called cloud-console- users@yourdomain.com. Rely on the default behavior of the Cloud Platform to grant users access if they are members of this group." }, correct: ["B"] },
  { id: 134, text: "You have a Google Cloud Platform account with access to both production and development projects. You need to create an automated process to list all compute instances in development and production projects on a daily basis. What should you do?", options: { A: "Create two configurations using gcloud config. Write a script that sets configurations as active, individually. For each configuration, use gcloud compute instances list to get a list of compute resources.", B: "Create two configurations using gsutil config. Write a script that sets configurations as active, individually. For each configuration, use gsutil compute instances list to get a list of compute resources.", C: "Go to Cloud Shell and export this information to Cloud Storage on a daily basis.", D: "Go to GCP Console and export this information to Cloud SQL on a daily basis. oa" }, correct: ["A"] },
  { id: 135, text: "You have a large 5-TB AVRO file stored in a Cloud Storage bucket. Your analysts are proficient only in SQL and need access to the data stored in this file. You want to find a cost-effective way to complete their request as soon as possible. What should you do?", options: { A: "Load data in Cloud Datastore and run a SQL query against it.", B: "Create a BigQuery table and load data in BigQuery. Run a SQL query on this table and drop this table after you complete your request.", C: "Create external tables in BigQuery that point to Cloud Storage buckets and run a SQL query on these external tables to complete your request.", D: "Create a Hadoop cluster and copy the AVRO file to NDFS by compressing it. Load the file in a hive table and provide access to your analysts so that they can run SQL queries." }, correct: ["C"] },
  { id: 136, text: "You need to verify that a Google Cloud Platform service account was created at a particular time. What should you do?", options: { A: "Filter the Activity log to view the Configuration category. Filter the Resource type to Service Account.", B: "Filter the Activity log to view the Configuration category. Filter the Resource type to Google Project.", C: "Filter the Activity log to view the Data Access category. Filter the Resource type to Service Account.", D: "Filter the Activity log to view the Data Access category. Filter the Resource type to Google Project." }, correct: ["A"] },
  { id: 137, text: "You deployed an LDAP server on Compute Engine that is reachable via TLS through port 636 using UDP. You want to make sure it is reachable by clients over that port. What should you do?", options: { A: "Add the network tag allow-udp-636 to the VM instance running the LDAP server.", B: "Create a route called allow-udp-636 and set the next hop to be the VM instance running the LDAP server.", C: "Add a network tag of your choice to the instance. Create a firewall rule to allow ingress on UDP port 636 for that network tag.", D: "Add a network tag of your choice to the instance running the LDAP server. Create a firewall rule to allow egress on UDP port 636 for that network tag. om" }, correct: ["C"] },
  { id: 138, text: "You need to set a budget alert for use of Compute Engineer services on one of the three Google Cloud Platform projects that you manage. All three projects are linked to a single billing account. What should you do?", options: { A: "Verify that you are the project billing administrator. Select the associated billing account and create a budget and alert for the appropriate project.", B: "Verify that you are the project billing administrator. Select the associated billing account and create a budget and a custom alert.", C: "Verify that you are the project administrator. Select the associated billing account and create a budget for the appropriate project.", D: "Verify that you are project administrator. Select the associated billing account and create a budget and a custom alert." }, correct: ["A"] },
  { id: 139, text: "You are migrating a production-critical on-premises application that requires 96 vCPUs to perform its task. You want to make sure the application runs in a similar environment on GCP. What should you do?", options: { A: "When creating the VM, use machine type n1-standard-96.", B: "When creating the VM, use Intel Skylake as the CPU platform.", C: "Create the VM using Compute Engine default settings. Use gcloud to modify the running instance to have 96 vCPUs.", D: "Start the VM using Compute Engine default settings, and adjust as you go based on Rightsizing Recommendations." }, correct: ["A"] },
  { id: 140, text: "You want to configure a solution for archiving data in a Cloud Storage bucket. The solution must be cost-effective. Data with multiple versions should be archived after 30 days. Previous versions are accessed once a month for reporting. This archive data is also occasionally updated at month-end. What should you do?", options: { A: "Add a bucket lifecycle rule that archives data with newer versions after 30 days to Coldline Storage.", B: "Add a bucket lifecycle rule that archives data with newer versions after 30 days to Nearline Storage.", C: "Add a bucket lifecycle rule that archives data from regional storage after 30 days to Coldline Storage.", D: "Add a bucket lifecycle rule that archives data from regional storage after 30 days to Nearline Storage." }, correct: ["B"] },
  { id: 141, text: "Your company’s infrastructure is on-premises, but all machines are running at maximum capacity. You want to burst to Google Cloud. The workloads on Google Cloud must be able to directly communicate to the workloads on- premises using a private IP range. What should you do?", options: { A: "In Google Cloud, configure the VPC as a host for Shared VPC.", B: "In Google Cloud, configure the VPC for VPC Network Peering.", C: "Create bastion hosts both in your on-premises environment and on Google Cloud. Configure both as proxy servers using their public IP addresses.", D: "Set up Cloud VPN between the infrastructure on-premises and Google Cloud." }, correct: ["D"] },
  { id: 142, text: "You want to select and configure a solution for storing and archiving data on Google Cloud Platform. You need to support compliance objectives for data from one geographic location. This data is archived after 30 days and needs to be accessed annually. What should you do?", options: { A: "Select Multi-Regional Storage. Add a bucket lifecycle rule that archives data after 30 days to Coldline Storage.", B: "Select Multi-Regional Storage. Add a bucket lifecycle rule that archives data after 30 days to Nearline Storage.", C: "Select Regional Storage. Add a bucket lifecycle rule that archives data after 30 days to Nearline Storage.", D: "Select Regional Storage. Add a bucket lifecycle rule that archives data after 30 days to Coldline Storage." }, correct: ["D"] },
  { id: 143, text: "Your company uses BigQuery for data warehousing. Over time, many different business units in your company have created 1000+ datasets across hundreds of projects. Your CIO wants you to examine all datasets to find tables that contain an employee_ssn column. You want to minimize effort in performing this task. What should you do?", options: { A: "Go to Data Catalog and search for employee_ssn in the search box.", B: "Write a shell script that uses the bq command line tool to loop through all the projects in your organization.", C: "Write a script that loops through all the projects in your organization and runs a query on INFORMATION_SCHEMA.COLUMNS view to find the employee_ssn column.", D: "Write a Cloud Dataflow job that loops through all the projects in your organization and runs a query on INFORMATION_SCHEMA.COLUMNS view to find employee_ssn column." }, correct: ["A"] },
  { id: 144, text: "You create a Deployment with 2 replicas in a Google Kubernetes Engine cluster that has a single preemptible node pool. After a few minutes, you use kubectl to examine the status of your Pod and observe that one of them is still in Pending status: $ kubectl get pods -1 app=myapp NAME READY STATUS RESTART AGE myapp-deployment-S8ddbbb995-1pSém o/1 Pending 0 om myapp-deployment-S8ddbbb995-qjpkg wi Running 0 om What is the most likely cause?", options: { A: "The pending Pod's resource requests are too large to fit on a single node of the cluster.", B: "Too many Pods are already running in the cluster, and there are not enough resources left to schecule the pending Pod.", C: "The node pool is configured with a service account that does not have permission to pull the container image used by the pending Pod.", D: "The pending Pod was originally scheduled on a node that has been preempted between the creation of the Deployment and your verification of the Pods’ status. It is currently being rescheduled on a new node." }, correct: ["B"] },
  { id: 145, text: "You want to find out when users were added to Cloud Spanner Identity Access Management (IAM) roles on your Google Cloud Platform (GCP) project. What should you do in the GCP Console?", options: { A: "Open the Cloud Spanner console to review configurations.", B: "Open the IAM & admin console to review IAM policies for Cloud Spanner roles.", C: "Go to the Stackdriver Monitoring console and review information for Cloud Spanner.", D: "Go to the Stackdriver Logging console, review admin activity logs, and filter them for Cloud Spanner IAM roles. om" }, correct: ["D"] },
  { id: 146, text: "Your company implemented BigQuery as an enterprise data warehouse. Users from multiple business units run queries on this data warehouse. However, you notice that query costs for BigQuery are very high, and you need to control costs. Which two methods should you use? (Choose two.)", options: { A: "Split the users from business units to multiple projects.", B: "Apply a user- or project-level custom query quota for BigQuery data warehouse.", C: "Create separate copies of your BigQuery data warehouse for each business unit.", D: "Split your BigQuery data warehouse into multiple data warehouses for each business unit.", E: "Change your BigQuery query model from on-demand to flat rate. Apply the appropriate number of slots to each Project." }, correct: ["B", "E"] },
  { id: 147, text: "You have designed a solution on Google Cloud that uses multiple Google Cloud products. Your company has asked you to estimate the costs of the solution. You need to provide estimates for the monthly total cost. What should you do?", options: { A: "For each Google Cloud product in the solution, review the pricing details on the products pricing page. Use the pricing calculator to total the monthly costs for each Google Cloud product.", B: "For each Google Cloud product in the solution, review the pricing details on the products pricing page. Create a Google Sheet that summarizes the expected monthly costs for each product.", C: "Provision the solution on Google Cloud. Leave the solution provisioned for 1 week. Navigate to the Billing Report page in the Cloud Console. Multiply the 1 week cost to determine the monthly costs.", D: "Provision the solution on Google Cloud. Leave the solution provisioned for 1 week. Use Cloud Monitoring to determine the provisioned and used resource amounts. Multiply the 1 week cost to determine the monthly costs. a" }, correct: ["A"] },
  { id: 148, text: "You have an application that receives SSL-encrypted TCP traffic on port 443. Clients for this application are located all over the world. You want to minimize latency for the clients. Which load balancing option should you use?", options: { A: "HTTPS Load Balancer", B: "Network Load Balancer", C: "SSL Proxy Load Balancer", D: "Internal TCP/UDP Load Balancer. Add a firewall rule allowing ingress traffic from 0.0.0.0/0 on the target instances." }, correct: ["C"] },
  { id: 149, text: "You have an application on a general-purpose Compute Engine instance that is experiencing excessive disk read throttling on its Zonal SSD Persistent Disk. The application primarily reads large files from disk. The disk size is currently 350 GB. You want to provide the maximum amount of throughput while minimizing costs. What should you do?", options: { A: "Increase the size of the disk to 1 TB.", B: "Increase the allocated CPU to the instance.", C: "Migrate to use a Local SSD on the instance.", D: "Migrate to use a Regional SSD on the instance." }, correct: ["C"] },
  { id: 150, text: "Your Dataproc cluster runs in a single Virtual Private Cloud (VPC) network in a single subnet with range 172.16.20.128/25. There are no private IP addresses available in the VPC network. You want to add new VMs to communicate with your cluster using the minimum number of steps. What should you do?", options: { A: "Modify the existing subnet range to 172.16.20.0/24.", B: "Create a new Secondary IP Range in the VPC and configure the VMs to use that range.", C: "Create a new VPC network for the VMs. Enable VPC Peering between the VMs' VPC network and the Dataproc cluster VPC network.", D: "Create a new VPC network for the VMs with a subnet of 172.32.0.0/16. Enable VPC network Peering between the Dataproc VPC network and the VMs VPC network. Configure a custom Route exchange. a" }, correct: ["A"] },
  { id: 151, text: "You manage an App Engine Service that aggregates and visualizes data from BigQuery. The application is deployed with the default App Engine Service account. The data that needs to be visualized resides in a different project managed by another team. You do not have access to this project, but you want your application to be able to read data from the BigQuery dataset. What should you do?", options: { A: "Ask the other team to grant your default App Engine Service account the role of BigQuery Job User.", B: "Ask the other team to grant your default App Engine Service account the role of BigQuery Data Viewer.", C: "In Cloud IAM of your project, ensure that the default App Engine service account has the role of BigQuery Data Viewer.", D: "In Cloud IAM of your project, grant a newly created service account from the other team the role of BigQuery Job User in your project." }, correct: ["B"] },
  { id: 152, text: "Your managed instance group raised an alert stating that new instance creation has failed to create new instances You need to maintain the number of running instances specified by the template to be able to process expected application traffic. What should you do?", options: { A: "Create an instance template that contains valid syntax which will be used by the instance group. Delete any persistent disks with the same name as instance names.", B: "Create an instance template that contains valid syntax that will be used by the instance group. Verify that the instance name and persistent disk name values are not the same in the template.", C: "Verify that the instance template being used by the instance group contains valid syntax. Delete any persistent disks with the same name as instance names. Set the disks.autoDelete property to true in the instance template.", D: "Delete the current instance template and replace it with a new instance template. Verify that the instance name and persistent disk name values are not the same in the template. Set the disks.autoDelete property to true in the instance template." }, correct: ["C"] },
  { id: 153, text: "Your company is moving from an on-premises environment to Google Cloud. You have multiple development teams that use Cassandra environments as backend databases. They all need a development environment that is isolated from other Cassandra instances. You want to move to Google Cloud quickly and with minimal support effort. What should you do?", options: { A: "1. Build an instruction guide to install Cassandra on Google Cloud. 2. Make the instruction guide accessible to your developers.", B: "1. Advise your developers to go to Cloud Marketplace. 2. Ask the developers to launch a Cassandra image for their development work.", C: "1. Build a Cassandra Compute Engine instance and take a snapshot of it. 2. Use the snapshot to create instances for your developers.", D: "1. Build a Cassandra Compute Engine instance and take a snapshot of it. 2. Upload the snapshot to Cloud Storage and make it accessible to your developers. 3. Build instructions to create a Compute Engine instance from the snapshot so that developers can do it themselves." }, correct: ["B"] },
  { id: 154, text: "You have a Compute Engine instance hosting a production application. You want to receive an email if the instance consumes more than 90% of its CPU resources for more than 15 minutes. You want to use Google services. What should you do?", options: { A: "1. Create a consumer Gmail account. 2. Write a script that monitors the CPU usage. 3. When the CPU usage exceeds the threshold, have that script send an email using the Gmail account and smtp.gmail.com on port 25 as SMTP server.", B: "1. Create a Cloud Monitoring Workspace and associate your Google Cloud Platform (GCP) project with it. 2. Create a Cloud Monitoring Alerting Policy that uses the threshold as a trigger condition. 3. Configure your email address in the notification channel.", C: "1. Create a Cloud Monitoring Workspace and associate your GCP project with it. 2. Write a script that monitors the CPU usage and sends it as a custom metric to Cloud Monitoring. 3. Create an uptime check for the instance in Cloud Monitoring.", D: "1. In Cloud Logging, create a logs-based metric to extract the CPU usage by using this regular expression: CPU Usage: ([0-9] {1,3})% 2. In Cloud Monitoring, create an Alerting Policy based on this metric. 3. Configure your email address in the notification channel. om" }, correct: ["B"] },
  { id: 155, text: "You have an application that uses Cloud Spanner as a backend database. The application has a very predictable traffic pattern. You want to automatically scale up or down the number of Spanner nodes depending on traffic. What should you do?", options: { A: "Create a cron job that runs on a scheduled basis to review Cloud Monitoring metrics, and then resize the Spanner instance accordingly.", B: "Create a Cloud Monitoring alerting policy to send an alert to oncall SRE emails when Cloud Spanner CPU exceeds the threshold. SREs would scale resources up or down accordingly.", C: "Create a Cloud Monitoring alerting policy to send an alert to Google Cloud Support email when Cloud Spanner CPU exceeds your threshold. Google support would scale resources up or down accordingly.", D: "Create a Cloud Monitoring alerting policy to send an alert to webhook when Cloud Spanner CPU is over <r under your threshold. Create a Cloud Function that listens to HTTP and resizes Spanner resources accordingly. a" }, correct: ["D"] },
  { id: 156, text: "Your company publishes large files on an Apache web server that runs on a Compute Engine instance. The Apache web server is not the only application running in the project. You want to receive an email when the egress network costs for the server exceed 100 dollars for the current month as measured by Google Cloud. What should you do?", options: { A: "Set up a budget alert on the project with an amount of 100 dollars, a threshold of 100%, and notification type of €aemail.€a", B: "Set up a budget alert on the billing account with an amount of 100 dollars, a threshold of 100%, and notification type of €aemail.€a", C: "Export the billing data to BigQuery. Create a Cloud Function that uses BigQuery to sum the egress network costs of the exported billing data for the Apache web server for the current month and sends an email if it is over 100 dollars. Schedule the Cloud Function using Cloud Scheduler to run hourly.", D: "Use the Cloud Logging Agent to export the Apache web server logs to Cloud Logging. Create a Cloud Function that uses BigQuery to parse the HTTP response log data in Cloud Logging for the current month and sends an email if the size of all HTTP responses, multiplied by current Google Cloud egress prices, totals over 100 dollars. Schedule the Cloud Function using Cloud Scheduler to run hourly. ug" }, correct: ["C"] },
  { id: 157, text: "You are configuring service accounts for an application that spans multiple projects. Virtual machines (VMs) running in the web-applications project need access to BigQuery datasets in crm-databases-proj. You want to follow Google- recommended practices to give access to the service account in the web-applications project. What should you do?", options: { A: "Give €aproject owner€ afor web-applications appropriate roles to crm-databases-proj.", B: "Give €aproject owner€ arole to crm-databases-proj and the web-applications project.", C: "Give €aproject owner€ arole to crm-databases-proj and bigquery.dataViewer role to web- applications.", D: "Give bigquery.dataViewer role to crm-databases-proj and appropriate roles to web-applications." }, correct: ["C"] },
  { id: 158, text: "An employee was terminated, but their access to Google Cloud was not removed until 2 weeks later. You need to find out if this employee accessed any sensitive customer information after their termination. What should you do?", options: { A: "View System Event Logs in Cloud Logging. Search for the user's email as the principal.", B: "View System Event Logs in Cloud Logging. Search for the service account associated with the user.", C: "View Data Access audit logs in Cloud Logging. Search for the user's email as the principal.", D: "View the Admin Activity log in Cloud Logging. Search for the service account associated with the user. a" }, correct: ["C"] },
  { id: 159, text: "You need to create a custom IAM role for use with a GCP service. All permissions in the role must be suitable for production use. You also want to clearly share with your organization the status of the custom role. This will be the first version of the custom role. What should you do?", options: { A: "Use permissions in your role that use the ‘supported’ support level for role permissions. Set the role stage to ALPHA while testing the role permissions.", B: "Use permissions in your role that use the ‘supported’ support level for role permissions. Set the role stage to BETA while testing the role permissions.", C: "Use permissions in your role that use the ‘testing’ support level for role permissions. Set the role stage to ALPHA while testing the role permissions.", D: "Use permissions in your role that use the ‘testing’ support level for role permissions. Set the role stage io BETA while testing the role permissions. oe" }, correct: ["A"] },
  { id: 160, text: "Your company has a large quantity of unstructured data in different file formats. You want to perform ETL transformations on the data. You need to make the data accessible on Google Cloud so it can be processed by a Dataflow job. What should you do?", options: { A: "Upload the data to BigQuery using the bq command line tool.", B: "Upload the data to Cloud Storage using the gsutil command line tool.", C: "Upload the data into Cloud SQL using the import function in the console.", D: "Upload the data into Cloud Spanner using the import function in the console." }, correct: ["B"] },
  { id: 161, text: "You need to manage multiple Google Cloud projects in the fewest steps possible. You want to configure the Google Cloud SDK command line interface (CLI) so that you can easily manage multiple projects. What should you do?", options: { A: "1. Create a configuration for each project you need to manage. 2. Activate the appropriate configuration when you work with each of your assigned Google Cloud projects.", B: "1. Create a configuration for each project you need to manage. 2. Use gcloud init to update the configuration values when you need to work with a non-default project", C: "1. Use the default configuration for one project you need to manage. 2. Activate the appropriate configuration when you work with each of your assigned Google Cloud projects.", D: "1. Use the default configuration for one project you need to manage. 2. Use gcloud init to update the configuration values when you need to work with a non-default project. oa" }, correct: ["A"] },
  { id: 162, text: "Your management has asked an external auditor to review all the resources in a specific project. The security team has enabled the Organization Policy called Domain Restricted Sharing on the organization node by specifying only your Cloud Identity domain. You want the auditor to only be able to view, but not modify, the resources in that project. What should you do?", options: { A: "Ask the auditor for their Google account, and give them the Viewer role on the project.", B: "Ask the auditor for their Google account, and give them the Security Reviewer role on the project.", C: "Create a temporary account for the auditor in Cloud Identity, and give that account the Viewer role on the project.", D: "Create a temporary account for the auditor in Cloud Identity, and give that account the Security Reviewer role on the project. ee" }, correct: ["C"] },
  { id: 163, text: "You have a workload running on Compute Engine that is critical to your business. You want to ensure that the data on the boot disk of this workload is backed up regularly. You need to be able to restore a backup as quickly as possible in case of disaster. You also want older backups to be cleaned automatically to save on cost. You want to follow Google-recommended practices. What should you do?", options: { A: "Create a Cloud Function to create an instance template.", B: "Create a snapshot schedule for the disk using the desired interval.", C: "Create a cron job to create a new disk from the disk using gcloud.", D: "Create a Cloud Task to create an image and export it to Cloud Storage." }, correct: ["B"] },
  { id: 164, text: "You need to assign a Cloud Identity and Access Management (Cloud IAM) role to an external auditor. The auditor needs to have permissions to review your Google Cloud Platform (GCP) Audit Logs and also to review your Data Access logs. What should you do?", options: { A: "Assign the auditor the IAM role roles/logging.privateLogViewer. Perform the export of logs to Cloud Storage.", B: "Assign the auditor the IAM role roles/logging.privateLogViewer. Direct the auditor to also review the logs for changes to Cloud IAM policy.", C: "Assign the auditor's IAM user to a custom role that has logging. privateLogEntries.list permission. Perform the export of logs to Cloud Storage.", D: "Assign the auditor's IAM user to a custom role that has logging. privateLogEntries.list permission. Direct the auditor to also review the logs for changes to Cloud IAM policy. a" }, correct: ["B"] },
  { id: 165, text: "You are managing several Google Cloud Platform (GCP) projects and need access to all logs for the past 60 days. You want to be able to explore and quickly analyze the log contents. You want to follow Google-recommended practices to obtain the combined logs for all projects. What should you do?", options: { A: "Navigate to Stackdriver Logging and select resource. labels.project_id=\"*\"", B: "Create a Stackdriver Logging Export with a Sink destination to a BigQuery dataset. Configure the table expiration to 60 days.", C: "Create a Stackdriver Logging Export with a Sink destination to Cloud Storage. Create a lifecycle rule to delete objects after 60 days.", D: "Configure a Cloud Scheduler job to read from Stackdriver and store the logs in BigQuery. Configure the table expiration to 60 days." }, correct: ["B"] },
  { id: 166, text: "You need to reduce GCP service costs for a division of your company using the fewest possible steps. You need to turn off all configured services in an existing GCP project. What should you do?", options: { A: "1. Verify that you are assigned the Project Owners IAM role for this project. 2. Locate the project in the GCP console, click Shut down and then enter the project ID.", B: "1. Verify that you are assigned the Project Owners IAM role for this project. 2. Switch to the project in the GCP console, locate the resources and delete them.", C: "1. Verify that you are assigned the Organizational Administrator IAM role for this project. 2. Locate the project in the GCP console, enter the project ID and then click Shut down.", D: "1. Verify that you are assigned the Organizational Administrators IAM role for this project. 2. Switch to the project in the GCP console, locate the resources and delete them. a" }, correct: ["A"] },
  { id: 167, text: "Your organization has a dedicated person who creates and manages all service accounts for Google Cloud projects. You need to assign this person the minimum role for projects. What should you do?", options: { A: "Add the user to roles/iam.roleAdmin role.", B: "Add the user to roles/iam.securityAdmin role.", C: "Add the user to roles/iam.serviceAccountUser role.", D: "Add the user to roles/iam.serviceAccountAdmin role. a" }, correct: ["D"] },
  { id: 168, text: "You are building an archival solution for your data warehouse and have selected Cloud Storage to archive your data. Your users need to be able to access this archived data once a quarter for some regulatory requirements. You want to select a cost-efficient option. Which storage option should you use?", options: { A: "Cold Storage", B: "Nearline Storage", C: "Regional Storage", D: "Multi-Regional Storage" }, correct: ["A"] },
  { id: 169, text: "A team of data scientists infrequently needs to use a Google Kubernetes Engine (GKE) cluster that you manage. They require GPUs for some long-running, non- restartable jobs. You want to minimize cost. What should you do?", options: { A: "Enable node auto-provisioning on the GKE cluster.", B: "Create a VerticalPodAutscaler for those workloads.", C: "Create a node pool with preemptible VMs and GPUs attached to those VMs.", D: "Create a node pool of instances with GPUs, and enable autoscaling on this node pool with a minimum size of 1. a" }, correct: ["A"] },
  { id: 170, text: "Your organization has user identities in Active Directory. Your organization wants to use Active Directory as their source of truth for identities. Your organization wants to have full control over the Google accounts used by employees for all Google services, including your Google Cloud Platform (GCP) organization. What should you do?", options: { A: "Use Google Cloud Directory Sync (GCDS) to synchronize users into Cloud Identity.", B: "Use the cloud Identity APIs and write a script to synchronize users to Cloud Identity.", C: "Export users from Active Directory as a CSV and import them to Cloud Identity via the Admin Console.", D: "Ask each employee to create a Google account using self signup. Require that each employee use their company email address and password." }, correct: ["A"] },
  { id: 171, text: "You have successfully created a development environment in a project for an application. This application uses Compute Engine and Cloud SQL. Now you need to create a production environment for this application. The security team has forbidden the existence of network routes between these 2 environments and has asked you to follow Google- recommended practices. What should you do?", options: { A: "Create a new project, enable the Compute Engine and Cloud SQL APIs in that project, and replicate the setup you have created in the development environment.", B: "Create a new production subnet in the existing VPC and a new production Cloud SQL instance in your existing project, and deploy your application using those resources.", C: "Create a new project, modify your existing VPC io be a Shared VPC, share that VPC with your new project, and replicate the setup you have in the development environment in that new project in the Shared VPU.", D: "Ask the security team to grant you the Project Editor role in an existing production project used by another division of your company. Once they grant you that role, replicate the setup you have in the development environment in that project. a" }, correct: ["A"] },
  { id: 172, text: "You need to host an application on a Compute Engine instance in a project shared with other teams. You want to prevent the other teams from accidentally causing downtime on that application. Which feature should you use?", options: { A: "Use a Shielded VM.", B: "Use a Preemptible VM.", C: "Use a sole-tenant node.", D: "Enable deletion protection on the instance." }, correct: ["D"] },
  { id: 173, text: "You have a developer laptop with the Cloud SDK installed on Ubuntu. The Cloud SDK was installed from the Google Cloud Ubuntu package repository. You want to test your application locally on your laptop with Cloud Datastore. What should you do?", options: { A: "Export Cloud Datastore data using gcloud datastore export.", B: "Create a Cloud Datastore index using gcloud datastore indexes create.", C: "Install the google-cloud-sdk-datastore-emulator component using the apt get install command.", D: "Install the cloud-datastore-emulator component using the gcloud components install command. a" }, correct: ["D"] },
  { id: 174, text: "Your company set up a complex organizational structure on Google Cloud. The structure includes hundreds of folders and projects. Only a few team members should be able to view the hierarchical structure. You need to assign minimum permissions to these team members, and you want to follow Google-recommended practices. What should you do?", options: { A: "Add the users to roles/browser role.", B: "Add the users to roles/iam.roleViewer role.", C: "Add the users to a group, and add this group to roles/browser.", D: "Add the users to a group, and add this group to roles/iam.roleViewer role. a" }, correct: ["C"] },
  { id: 175, text: "Your company has a single sign-on (SSO) identity provider that supports Security Assertion Markup Language (SAML) integration with service providers. Your company has users in Cloud Identity. You would like users to authenticate using your company's SSO provider. What should you do?", options: { A: "In Cloud Identity, set up SSO with Google as an identity provider to access custom SAML apps.", B: "In Cloud Identity, set up SSO with a third-party identity provider with Google as a service provider.", C: "Obtain OAuth 2.0 credentials, configure the user consent screen, and set up OAuth 2.0 for Mobile & Desktop Apps.", D: "Obtain OAuth 2.0 credentials, configure the user consent screen, and set up OAuth 2.0 for Web Server Applications. a" }, correct: ["B"] },
  { id: 176, text: "Your company implemented BigQuery as an enterprise data warehouse. Users from multiple business units run queries on this data warehouse. However, you notice that query costs for BigQuery are very high, and you need to control costs. Which two methods should you use? (Choose two.)", options: { A: "Split the users from business units to multiple projects.", B: "Apply a user- or project-level custom query quota for BigQuery data warehouse.", C: "Create separate copies of your BigQuery data warehouse for each business unit.", D: "Split your BigQuery data warehouse into multiple data warehouses for each business unit.", E: "Change your BigQuery query model from on-demand to flat rate. Apply the appropriate number of slots to each Project." }, correct: ["B", "E"] },
  { id: 177, text: "You are building a product on top of Google Kubernetes Engine (GKE). You have a single GKE cluster. For each of your customers, a Pod is running in that cluster, and your customers can run arbitrary code inside their Pod. You want to maximize the isolation between your customers’ Pods. What should you do?", options: { A: "Use Binary Authorization and whitelist only the container images used by your customers’ Pods.", B: "Use the Container Analysis API to detect vulnerabilities in the containers used by your customers’ Pods.", C: "Create a GKE node pool with a sandbox type configured to gvisor. Add the parameter tuntimeClassName: gvisor to the specification of your customers’ Pods.", D: "Use the cos_containerd image for your GKE nodes. Add a nodeSelector with the value cloud.google.com/gke-os-distribution: cos_containerd to the specification of your customers’ Pods." }, correct: ["C"] },
  { id: 178, text: "Your customer has implemented a solution that uses Cloud Spanner and notices some read latency-related performance issues on one table. This table is accessed only by their users using a primary key. The table schema is shown below. CREATE TABLE Persons ( person_id INT64 NOT NULL, // sequential number based on number of registration account_creation_date DATE, // system date birthdate DATE, // customer birthdate firstname STRING (255), // first name lastname STRING (255), // last name profile picture BYTES (255) // profile picture ) PRIMARY KEY (person_id) You want to resolve the issue. What should you do?", options: { A: "Remove the profile_picture field from the table.", B: "Add a secondary index on the person_id column.", C: "Change the primary key to not have monotonically increasing CREATE INDEX person_id_ix values ON Persons ( : person_id,", D: "Create a secondary index using the following Data Definition firstname, « lastname Language (DDL): Penance profile picture ) ee" }, correct: ["D"] },
  { id: 179, text: "Your finance team wants to view the billing report for your projects. You want to make sure that the finance team does not get additional permissions to the project. What should you do?", options: { A: "Add the group for the finance team to roles/billing user role.", B: "Add the group for the finance team to roles/billing admin role.", C: "Add the group for the finance team to roles/billing viewer role.", D: "Add the group for the finance team to roles/billing project/Manager role." }, correct: ["C"] },
  { id: 180, text: "Your organization has strict requirements to control access to Google Cloud projects. You need to enable your Site Reliability Engineers (SREs) to approve requests from the Google Cloud support team when an SRE opens a support case. You want to follow Google-recommended practices. What should you do?", options: { A: "Add your SREs to roles/iam.roleAdmin role.", B: "Add your SREs to roles/accessapproval.approver role.", C: "Add your SREs to a group and then add this group to roles/iam.roleAdmin.role.", D: "Add your SREs to a group and then add this group to roles/accessapproval.approver role. a" }, correct: ["D"] },
  { id: 181, text: "You are the team lead of a group of 10 developers. You provided each developer with an individual Google Cloud Project that they can use as their personal sandbox to experiment with different Google Cloud solutions. You want to be notified if any of the developers are spending above $500 per month on their sandbox environment. What should you do?", options: { A: "Create a single budget for all projects and configure budget alerts on this budget.", B: "Create a separate billing account per sandbox project and enable BigQuery billing exports. Create a Data Studio dashboard to plot the spending per billing account.", C: "Create a budget per project and configure budget alerts on all of these budgets.", D: "Create a single billing account for all sandbox projects and enable BigQuery billing exports. Create a Data Studio dashboard to plot the spending per project." }, correct: ["C"] },
  { id: 182, text: "You are storing sensitive information in a Cloud Storage bucket. For legal reasons, you need to be able to record all requests that read any of the stored dat", options: { A: "You want to make sure you comply with these requirements. What should you do?", B: "Enable the Identity Aware Proxy API on the project.", C: "Scan the bucker using the Data Loss Prevention API.", D: "Allow only a single Service Account access to read the data.", E: "Enable Data Access audit logs for the Cloud Storage API." }, correct: ["D"] },
  { id: 183, text: "You have been asked to set up Object Lifecycle Management for objects stored in storage buckets. The objects are written once and accessed frequently for 30 days. After 30 days, the objects are not read again unless there is a special need. The object should be kept for three years, and you need to minimize cost. What should you do?", options: { A: "Set up a policy that uses Nearline storage for 30 days and then moves to Archive storage for three years.", B: "Set up a policy that uses Standard storage for 30 days and then moves to Archive storage for three years.", C: "Set up a policy that uses Nearline storage for 30 days, then moves the Coldline for one year, and then moves to Archive storage for two years.", D: "Set up a policy that uses Standard storage for 30 days, then moves to Coldline for one year, and then movas to Archive storage for two years." }, correct: ["B"] },
  { id: 184, text: "You have created a code snippet that should be triggered whenever a new file is uploaded to a Cloud Storage bucket. You want to deploy this code snippet. What should you do?", options: { A: "Use App Engine and configure Cloud Scheduler to trigger the application using Pub/Sub.", B: "Use Cloud Functions and configure the bucket as a trigger resource.", C: "Use Google Kubernetes Engine and configure a CronJob to trigger the application using Pub/Sub.", D: "Use Dataflow as a batch job, and configure the bucket as a data source." }, correct: ["B"] },
  { id: 185, text: "You are running multiple VPC-native Google Kubernetes Engine clusters in the same subnet. The IPs available for the nodes are exhausted, and you want to ensure that the clusters can grow in nodes when needed. What should you do?", options: { A: "Create a new subnet in the same region as the subnet being used.", B: "Add an alias IP range to the subnet used by the GKE clusters.", C: "Create a new VPC, and set up VPC peering with the existing VP", D: "Expand the CIDR range of the relevant subnet for the cluster." }, correct: ["D"] },
  { id: 186, text: "You have a batch workload that runs every night and uses a large number of virtual machines (VMs). It is fault- tolerant and can tolerate some of the VMs being terminated. The current cost of VMs is too high. What should you do?", options: { A: "Run a test using simulated maintenance events. If the test is successful, use preemptible N1 Standard VMs when running future jobs.", B: "Run a test using simulated maintenance events. If the test is successful, use N1 Standard VMs when running future jobs.", C: "Run a test using a managed instance group. If the test is successful, use N1 Standard VMs in the managed instance group when running future jobs.", D: "Run a test using N1 standard VMs instead of N2. If the test is successful, use N1 Standard VMs when running future jobs. nswer(s): A xplanation: treating and starting a preemptible VM instance This page explains how to create and use a oreem Renee eee stance. A preemptible instance is an instance you can create and run at a much lower price than nj ompute Engine might terminate (preempt) these instances if it requires access to those resources cag stances will always terminate after 24 hours. To learn more about preemptible instances, read the} a oe i) a ocumentation. Preemptible instances are recommended only for fault- tolerant applications that cq reemptions. Make sure your application can handle preemptions before you decide to create a pre@iipHple i) stancru lo Miderst: 1e risks and value of preemptible instances, read the preemptible instances documentation. — Sa Op Geers Cl -- ee ae" }, correct: ["A"] },
  { id: 187, text: "You are working with a user to set up an application in a new VPC behind a firewall. The user is concerned about data egress. You want to configure the fewest open egress ports. What should you do?", options: { A: "Set up a low-priority (65534) rule that blocks all egress and a high-priority rule (1000) that allows only the appropriate ports.", B: "Set up a high-priority (1000) rule that pairs both ingress and egress ports.", C: "Set up a high-priority (1000) rule that blocks all egress and a low-priority (65534) rule that allows only the appropriate ports.", D: "Set up a high-priority (1000) rule to allow the appropriate ports." }, correct: ["A"] },
  { id: 188, text: "Your company runs its Linux workloads on Compute Engine instances. Your company will be working with a new operations partner that does not use Google Accounts. You need to grant access to the instances to your operations partner so they can maintain the installed tooling. What should you do?", options: { A: "Enable Cloud IAP for the Compute Engine instances, and add the operations partner as a Cloud IAP Tunnel User.", B: "Tag all the instances with the same network tag. Create a firewall rule in the VPC to grant TCP access on port 22 for traffic from the operations partner to instances with the network tag.", C: "Set up Cloud VPN between your Google Cloud VPC and the internal network of the operations partner.", D: "Ask the operations partner to generate SSH key pairs, and add the public keys to the VM instances." }, correct: ["D"] },
  { id: 189, text: "Your existing application running in Google Kubernetes Engine (GKE) consists of multiple pods running on four GKE n1- standard2 nodes. You need to deploy additional pods requiring n2 highmem16 nodes without any downtime. What should you do?", options: { A: "Use gcloud container clusters upgrade. Deploy the new services.", B: "Create a new Node Pool and specify machine type n2highmem16. Deploy the new pods.", C: "Create a new cluster with n2highmem16 nodes. Redeploy the pods and delete the old cluster.", D: "Create a new cluster with both nistandard2 and n2highmem16 nodes. Redeploy the pods and delete the old cluster." }, correct: ["B"] },
  { id: 190, text: "You have an application that uses Cloud Spanner as a database backend to keep current state information about users. Cloud Bigtable logs all events triggered by users. You export Cloud Spanner data to Cloud Storage during daily backups. One of your analysts asks you to join data from Cloud Spanner and Cloud Bigtable for specific users. You want to complete this ad hoc request as efficiently as possible. What should you do?", options: { A: "Create a dataflow job that copies data from Cloud Bigtable and Cloud Storage for specific users.", B: "Create a dataflow job that copies data from Cloud Bigtable and Cloud Spanner for specific users.", C: "Create a Cloud Dataproc cluster that runs a Spark job to extract data from Cloud Bigtable and Cloud Storage for specific users.", D: "Create two separate BigQuery external tables on Cloud Storage and Cloud Bigtable. Use the BigQuery console to join these tables through user fields, and apply appropriate filters." }, correct: ["D"] },
  { id: 191, text: "You are hosting an application from Compute Engine virtual machines (VMs) in uscentral1", options: { A: "You want to adjust your design to support the failure of a single Compute Engine zone, eliminate downtime, and minimize cost. What should you do?", B: "Create Compute Engine resources in uscentral1b. Balance the load across both uscentral1a and uscentral1b.", C: "Create a Managed Instance Group and specify uscentralla as the zone. Configure the Health Check with a short Health Interval.", D: "Create an HTTP(S) Load Balancer. Create one or more global forwarding rules to direct traffic to your VMs.", E: "Perform regular backups of your application. Create a Cloud Monitoring Alert and be notified if your application becomes unavailable. Restore from backups when notified." }, correct: ["A"] },
  { id: 192, text: "A colleague handed over a Google Cloud Platform project for you to maintain. As part of a security checkup, you want to review who has been granted the Project Owner role. What should you do?", options: { A: "In the console, validate which SSH keys have been stored as project-wide keys.", B: "Navigate to Identity-Aware Proxy and check the permissions for these resources.", C: "Enable Audit Logs on the IAM & admin page for all resources, and validate the results.", D: "Use the command gcloud projects getiampolicy to view the current role assignments." }, correct: ["D"] },
  { id: 193, text: "You created several resources in multiple Google Cloud projects. All projects are linked to different billing accounts. To better estimate future charges, you want to have a single visual representation of all costs incurred. You want to include new cost data as soon as possible. What should you do?", options: { A: "Configure Billing Data Export to BigQuery and visualize the data in Data Studio.", B: "Visit the Cost Table page to get a CSV export and visualize it using Data Studio.", C: "Fill all resources in the Pricing Calculator to get an estimate of the monthly cost.", D: "Use the Reports view in the Cloud Billing Console to view the desired cost information. a" }, correct: ["A"] },
  { id: 194, text: "Your company has workloads running on Compute Engine and on-premises. The Google Cloud Virtual Private Cloud (VPC) is connected to your WAN over a Virtual Private Network (VPN). You need to deploy a new Compute Engine instance and ensure that no public Internet traffic can be routed to it. What should you do?", options: { A: "Create the instance without a public IP address.", B: "Create the instance with Private Google Access enabled.", C: "Create a deny-all egress firewall rule on the VPC network.", D: "Create a route on the VPC to route all traffic to the instance over the VPN tunnel." }, correct: ["A"] },
  { id: 195, text: "Your team maintains the infrastructure for your organization. The current infrastructure requires changes. You need to share your proposed changes with the rest of the team. You want to follow Google's recommended best practices. What should you do?", options: { A: "Use Deployment Manager templates to describe the proposed changes and store them in a Cloud Storage bucket.", B: "Use Deployment Manager templates to describe the proposed changes and store them in Cloud Source Repositories.", C: "Apply the change in a development environment, run gcloud compute instances list, and then save the output in a shared Storage bucket.", D: "Apply the change in a development environment, run gcloud compute instances list, and then save the output in Cloud Source Repositories." }, correct: ["B"] },
  { id: 196, text: "You have a Compute Engine instance hosting an application used between 9 AM and 6 PM on weekdays. You want to back up this instance daily for disaster recovery purposes. You want to keep the backups for 30 days. You want the Google- recommended solution with the least management overhead and the least number of services. What should you do?", options: { A: "1. Update your instances’ metadata to add the following value: snapshotschedule: 0 1 * * * 2. Update your instances’ metadata to add the following value: snapshotretention: 30", B: "1. In the Cloud Console, go to the Compute Engine Disks page and select your instance's disk. 2. In the Snapshot Schedule section, select Create Schedule and configure the following parameters: Schedule frequency: Daily Start time: 1:00 AM 2:00 AM Autodelete snapshots after 30 days", C: "1. Create a Cloud Function that creates a snapshot of your instance's disk. 2. Create a Cloud Function that deletes snapshots that are older than 30 days. 3. Use Cloud Scheduler to trigger both Cloud Functions daily at 1:00 AM.", D: "1. Create a bash script in the instance that copies the content of the disk to Cloud Storage. 2. Create a bash script in the instance that deletes data older than 30 days in the backup Cloud Storage bucket. 3. Configure the instance's crontab to execute these scripts daily at 1:00 AM. oa" }, correct: ["B"] },
  { id: 197, text: "You are developing a new application and are looking for a Jenkins installation to build and deploy your source code. You want to automate the installation as quickly and easily as possible. What should you do?", options: { A: "Deploy Jenkins through the Google Cloud Marketplace.", B: "Create a new Compute Engine instance. Run the Jenkins executable.", C: "Create a new Kubernetes Engine cluster. Create a deployment for the Jenkins image.", D: "Create an instance template with the Jenkins executable. Create a managed instance group with this template." }, correct: ["A"] },
  { id: 198, text: "You have downloaded and installed the gcloud command line interface (CLI) and have authenticated with your Google Account. Most of your Compute Engine instances in your project run in the europe- west1-d zone. You want to avoid having to specify this zone with each CLI command when managing these instances. What should you do?", options: { A: "Set the europe-west1-d zone as the default zone using the gcloud config subcommand.", B: "In the Settings page for Compute Engine under Default location, set the zone to europewest1-d.", C: "In the CLI installation directory, create a file called default.conf containing zone=europewest1d.", D: "Create a Metadata entry on the Compute Engine page with key compute/zone and value europe west1d." }, correct: ["A"] },
  { id: 199, text: "The core business of your company is to rent out construction equipment at a large scale. All the equipment that is being rented out has been equipped with multiple sensors that send event information every few seconds. These signals can vary from engine status, distance traveled, fuel level, and more. Customers are billed based on the consumption monitored by these sensors. You expect high throughput up to thousands of events per hour per device and need to retrieve consistent data based on the time of the event. Storing and retrieving individual signals should be atomic. What should you do?", options: { A: "Create a file in Cloud Storage per device and append new data to that file.", B: "Create a file in Cloud Filestore per device and append new data to that file.", C: "Ingest the data into Datastore. Store data in an entity group based on the device.", D: "Ingest the data into Cloud Bigtable. Create a row key based on the event timestamp. SE a SS Ch) 0 zamsnyesnse == S wou" }, correct: ["D"] },
  { id: 200, text: "You are asked to set up application performance monitoring on Google Cloud projects A, B, and C as a single pane of glass. You want to monitor CPU, memory, and disk. What should you do?", options: { A: "Enable API and then share charts from project A, B, and C.", B: "Enable API and then give the metrics.reader role to projects A, B, and C.", C: "Enable API and then use default dashboards to view all projects in sequence.", D: "Enable API, create a workspace under project A, and then add project B and C. @ _ sabitses e" }, correct: ["D"] },
  { id: 201, text: "An application generates daily reports in a Compute Engine virtual machine (VM). The VM is in the project corp-iot-insights. Your team operates only in the project corp-aggregate-reports and needs a copy of the daily exports in the bucket corp- aggregate-reports-storage. You want to configure access so that the daily reports from the VM are available in the bucket corp- aggregate-reports-storage and use as few steps as possible while following Google-recommended practices. What should you do?", options: { A: "Move both projects under the same folder.", B: "Grant the VM Service Account the role Storage Object Creator on corp-aggregate-reports-storage.", C: "Create a Shared VPC network between both projects. Grant the VM Service Account the role Storage Object Creator on corp-iot-insights.", D: "Make corp-aggregate-reports-storage public and create a folder with a pseudo-randomized suffix name. Share the folder with the loT team." }, correct: ["B"] },
  { id: 202, text: "You built an application on your development laptop that uses Google Cloud services. Your application uses Application Default Credentials for authentication and works fine on your development laptop. You want to migrate this application to a Compute Engine virtual machine (VM) and set up authentication using Google- recommended practices and minimal changes. What should you do?", options: { A: "Assign appropriate access for Google services to the service account used by the Compute Engine VM.", B: "Create a service account with appropriate access for Google services, and configure the application to use this account.", C: "Store credentials for service accounts with appropriate access for Google services in a config file, and deploy this config file with your application.", D: "Store credentials for your user account with appropriate access for Google services in a config file, and deploy this config file with your application." }, correct: ["B"] },
  { id: 203, text: "You need to create a Compute Engine instance in a new project that doesn't exist yet. What should you do?", options: { A: "Using the Cloud SDK, create a new project, enable the Compute Engine API in that project, and then create the instance specifying your new project.", B: "Enable the Compute Engine API in the Cloud Console, use the Cloud SDK to create the instance, and then use the - project flag to specify a new project.", C: "Using the Cloud SDK, create the new instance, and use the project flag to specify the new project.", D: "Enable the Compute Engine API in the Cloud Console. Go to the Compute Engine section of the Console to create a new instance, and look for the Create In A New Project option in the creation form." }, correct: ["A"] },
  { id: 204, text: "Your company runs one batch process in an on-premises server that takes around 30 hours to complete. The task runs monthly, can be performed offline, and must be restarted if interrupted. You want to migrate this workload to the cloud while minimizing cost. What should you do?", options: { A: "Migrate the workload to a Compute Engine Preemptible VM.", B: "Migrate the workload to a Google Kubernetes Engine cluster with Preemptible nodes.", C: "Migrate the workload to a Compute Engine VM. Start and stop the instance as needed.", D: "Create an Instance Template with Preemptible VMs On. Create a Managed Instance Group from the template and adjust Target CPU Utilization. Migrate the workload." }, correct: ["D"] },
  { id: 205, text: "You need to create a copy of a custom Compute Engine virtual machine (VM) to facilitate an expected increase in application traffic due to a business acquisition. What should you do?", options: { A: "Create a Compute Engine snapshot of your base VM. Create your images from that snapshot.", B: "Create a Compute Engine snapshot of your base VM. Create your instances from that snapshot.", C: "Create a custom Compute Engine image from a snapshot. Create your images from that image.", D: "Create a custom Compute Engine image from a snapshot. Create your instances from that image." }, correct: ["D"] },
  { id: 206, text: "You have deployed an application on a single Compute Engine instance. The application writes logs to disk. Users start reporting errors with the application. You want to diagnose the problem. What should you do?", options: { A: "Navigate to Cloud Logging and view the application logs.", B: "Connect to the instance's serial console and read the application logs.", C: "Configure a Health Check on the instance and set a Low Healthy Threshold value.", D: "Install and configure the Cloud Logging Agent and view the logs from Cloud Logging. inswer(s): D ‘eference: ttps://cloud.google.com/error-reporting/docs/setup/compute-engine ‘loud Loging knows nothing about applications installed on the system without an agent collecting logs. Using the serial console is ot a best-practice and is impractical on a large scale. he VM images for Compute Engine and Amazon Elastic Compute Cloud (EC2) don't include the Logging agent, so you must omplete these steps to install it on those instances. The agent runs under both Linux and Windows. Source: [ips.72c loud.goOOgle.cOl logging do agent/logging/installatlo Ups 77ecl aaa iene OGGINGTAOCSTAGENTTONTING Sa com Qe»" }, correct: ["D"] },
  { id: 207, text: "You need to manage a Cloud Spanner instance for best query performance. Your instance in production runs in a single Google Cloud region. You need to improve performance in the shortest amount of time. You want to follow Google best practices for service configuration. What should you do?", options: { A: "Create an alert in Cloud Monitoring to alert when the percentage of high priority CPU utilization reaches 45%. If you exceed this threshold, add nodes to your instance.", B: "Create an alert in Cloud Monitoring to alert when the percentage of high priority CPU utilization reaches 45%. Use database query statistics to identify queries that result in high CPU usage, and then rewrite those queries to optimize their resource usage.", C: "Create an alert in Cloud Monitoring to alert when the percentage of high priority CPU utilization reaches 65%. If you exceed this threshold, add nodes to your instance.", D: "Create an alert in Cloud Monitoring to alert when the percentage of high priority CPU utilization reaches 65%. Use database query statistics to identify queries that result in high CPU usage, and then rewrite those queries to optimize their resource usage." }, correct: ["C"] },
  { id: 208, text: "Your web application has been running successfully on Cloud Run for Anthos. You want to evaluate an updated version of the application with a specific percentage of your production users (canary deployment). What should you do?", options: { A: "Create a new service with the new version of the application. Split traffic between this version and the version that is currently running.", B: "Create a new revision with the new version of the application. Split traffic between this version and the version that is currently running.", C: "Create a new service with the new version of the application. Add an HTTP Load Balancer in front of both services.", D: "Create a new revision with the new version of the application. Add an HTTP Load Balancer in front of bet!: revisions." }, correct: ["B"] },
  { id: 209, text: "You will have several applications running on different Compute Engine instances in the same project. You want to specify at a more granular level the service account each instance uses when calling Google Cloud APIs. What should you do?", options: { A: "When creating the instances, specify a Service Account for each instance.", B: "When creating the instances, assign the name of each Service Account as instance metadata.", C: "After starting the instances, use gcloud compute instances update to specify a Service Account for each instance.", D: "After starting the instances, use gcloud compute instances update to assign the name of the relevant Service Account as instance metadata. a" }, correct: ["A"] },
  { id: 210, text: "Your organization uses Active Directory (AD) to manage user identities. Each user uses this identity for federated access to various on-premises systems. Your security team has adopted a policy that requires users to log into Google Cloud with their AD identity instead of their own login. You want to follow the Google-recommended practices to implement this policy. What should you do?", options: { A: "Sync Identities with Cloud Directory Sync, and then enable SAML for single sign-on", B: "Sync Identities in the Google Admin console, and then enable Oauth for single sign- on", C: "Sync identities with 3rd party LDAP sync, and then copy passwords to allow simplified login with (he same credentials", D: "Sync identities with Cloud Directory Sync, and then copy passwords to allow simplified login with the same credentials." }, correct: ["A"] },
  { id: 211, text: "You need to track and verity modifications to a set of Google Compute Engine instances in your Google Cloud project. In particular, you want to verify OS system patching events on your virtual machines (VMs). What should you do?", options: { A: "Review the Compute Engine activity logs Select and review the Admin Event logs", B: "Review the Compute Engine activity logs Select and review the System Event logs", C: "Install the Cloud Logging Agent In Cloud Logging review the Compute Engine syslog logs", D: "Install the Cloud Logging Agent In Cloud Logging, review the Compute Engine operation logs" }, correct: ["A"] },
  { id: 212, text: "Your company has embraced a hybrid cloud strategy where some of the applications are deployed on Google Cloud. A Virtual Private Network (VPN) tunnel connects your Virtual Private Cloud (VPC) in Google Cloud with your company's on- premises network. Multiple applications in Google Cloud need to connect to an on-premises database server, and you want to avoid having to change the IP configuration in all of your applications when the IP of the database changes. What should you do?", options: { A: "Configure Cloud NAT for all subnets of your VPC to be used when egressing from the VM instances.", B: "Create a private zone on Cloud DNS, and configure the applications with the DNS name.", C: "Configure the IP of the database as custom metadata for each instance, and query the metadata server.", D: "Query the Compute Engine internal DNS from the applications to retrieve the IP of the database." }, correct: ["B"] },
  { id: 213, text: "Your company is moving its entire workload to Compute Engine. Some servers should be accessible through the Internet, and other servers should only be accessible over the internal network. All servers need to be able to talk to each other over specific ports and protocols. The current on-premises network relies on a demilitarized zone (DMZ) for the public servers and a Local Area Network (LAN) for the private servers. You need to design the networking infrastructure on Google Cloud to match these requirements. What should you do?", options: { A: "1. Create a single VPC with a subnet for the DMZ and a subnet for the LAN. 2. Set up firewall rules to open up relevant traffic between the DMZ and the LAN subnets, and another firewall rule to allow public ingress traffic for the DMZ.", B: "1. Create a single VPC with a subnet for the DMZ and a subnet for the LAN. 2. Set up firewall rules to open up relevant traffic between the DMZ and the LAN subnets, and another firewall rule to allow public egress traffic for the DMZ.", C: "1. Create a VPC with a subnet for the DMZ and another VPC with a subnet for the LAN. 2. Set up firewall rules to open up relevant traffic between the DMZ and the LAN subnets, and another firewall rule to allow public ingress traffic for the DMZ.", D: "1. Create a VPC with a subnet for the DMZ and another VPC with a subnet for the LAN. 2. Set up firewall rules to open up relevant traffic between the DMZ and the LAN subnets, and another firewall rule to allow public egress traffic for the DMZ." }, correct: ["A"] },
  { id: 214, text: "You are working with a Cloud SQL MySQL database at your company. You need to retain a month-end copy of the database for three years for audit purposes. What should you do?", options: { A: "Set up an export job for the first of the month. Write the export file to an Archive class Cloud Storage bucket.", B: "Save the automatic first-of-the-month backup for three years. Store the backup file in an Archive class Cloud Storage bucket.", C: "Set up an on-demand backup for the first of the month. Write the backup to an Archive class Cloud Storage bucket.", D: "Convert the automatic first-of-the-month backup to an export file. Write the export file to a Coldline class Cloud Storage bucket." }, correct: ["A"] },
  { id: 215, text: "You have files in a Cloud Storage bucket that you need to share with your suppliers. You want to restrict the time that the files are available to your suppliers to 1 hour. You want to follow Google recommended practices. What should you do?", options: { A: "Create a service account with just the permissions to access files in the bucket. Create a JSON key for the service account. Execute the command gsutil signurl -m 1h gs:///*.", B: "Create a service account with just the permissions to access files in the bucket. Create a JSON key for the service account. Execute the command gsutil signurl -d 1h gs:///**.", C: "Create a service account with just the permissions to access files in the bucket. Create a JSON key for the service account. Execute the command gsutil signurl -p 60m gs:///.", D: "Create a JSON key for the Default Compute Engine Service Account. Execute the command gsutil signurl -t 60m gs:///***" }, correct: ["B"] },
  { id: 216, text: "You have developed a containerized web application that will serve internal colleagues during business hours. You want to ensure that no costs are incurred outside of the hours the application is used. You have just created a new Google Cloud project and want to deploy the application. What should you do?", options: { A: "Deploy the container on Cloud Run for Anthos, and set the minimum number of instances to zero.", B: "Deploy the container on Cloud Run (fully managed), and set the minimum number of instances to Zero.", C: "Deploy the container on App Engine flexible environment with autoscaling, and set the value min_instances to zero in the app.yaml.", D: "Deploy the container on App Engine flexible environment with manual scaling, and set the value instances to zero in the app.yaml." }, correct: ["B"] },
  { id: 217, text: "Your coworker has helped you set up several configurations for gcloud. You've noticed that you're running commands against the wrong project. Being new to the company, you haven't yet memorized any of the projects. With the fewest steps possible, what's the fastest way to switch to the correct configuration?", options: { A: "Run gcloud configurations list followed by gcloud configurations activate .", B: "Run gcloud config list followed by gcloud config activate.", C: "Run gcloud config configurations list followed by gcloud config configurations activate.", D: "Re-authenticate with the gcloud auth login command and select the correct configurations on login." }, correct: ["C"] },
  { id: 218, text: "You are running a data warehouse on BigQuery. A partner company is offering a recommendation engine based on the data in your data warehouse. The partner company is also running their application on Google Cloud. They manage the resources in their own project, but they need access to the BigQuery dataset in your project. You want to provide the partner company with access to the dataset What should you do?", options: { A: "Create a Service Account in your own project, and grant this Service Account access to BigGuery in your project", B: "Create a Service Account in your own project, and ask the partner to grant this Service Account access to BigQuery in their project", C: "Ask the partner to create a Service Account in their project, and have them give the Service Account access to BigQuery in their project", D: "Ask the partner to create a Service Account in their project, and grant their Service Account access to the BigQuery dataset in your project" }, correct: ["D"] },
  { id: 219, text: "You have been asked to set up the billing configuration for a new Google Cloud customer. Your customer wants to group resources that share common IAM policies. What should you do?", options: { A: "Use labels to group resources that share common IAM policies", B: "Use folders to group resources that share common IAM policies", C: "Set up a proper billing account structure to group IAM policies", D: "Set up a proper project naming structure to group IAM policies" }, correct: ["B"] },
  { id: 220, text: "You are developing a new web application that will be deployed on Google Cloud Platform. As part of your release cycle, you want to test updates to your application on a small portion of real user traffic. The majority of the users should still be directed towards a stable version of your application. What should you do?", options: { A: "Deploy me application on App Engine For each update, create a new version of the same service Configure traffic splitting to send a small percentage of traffic to the new version", B: "Deploy the application on App Engine For each update, create a new service Configure traffic splitting to send a small percentage of traffic to the new service.", C: "Deploy the application on Kubernetes Engine For a new release, update the deployment to use the new version", D: "Deploy the application on Kubernetes Engine For a now release, create a new deployment for the newversion Update the service e to use the now deployment." }, correct: ["A"] },
  { id: 221, text: "You received a JSON file that contained a private key of a Service Account in order to get access to several resources in a Google Cloud project. You downloaded and installed the Cloud SDK and want to use this private key for authentication and authorization when performing gcloud commands. What should you do?", options: { A: "Use the command gcloud auth login and point it to the private key", B: "Use the command gcloud auth activate-service-account and point it to the private key", C: "Place the private key file in the installation directory of the Cloud SDK and rename it to “credentials ison\"", D: "Place the private key file in your home directory and rename it to “GOOGLE_APPUCATION_CREDENTIALS\"." }, correct: ["B"] },
  { id: 222, text: "You need to configure optimal data storage for files stored in Cloud Storage for minimal cost. The files are used in a mission-critical analytics pipeline that is used continually. The users are in Boston, MA (United States). What should you do?", options: { A: "Configure regional storage for the region closest to the users Configure a Nearline storage class", B: "Configure regional storage for the region closest to the users Configure a Standard storage class", C: "Configure dual-regional storage for the dual region closest to the users Configure a Nearline storageclass", D: "Configure dual-regional storage for the dual region closest to the users Configure a Standard storage class" }, correct: ["D"] },
  { id: 223, text: "You created a cluster. YAML file containing resources: name: cluster type: container.v1.cluster properties: Zone: europe-west1-b cluster: description: My GCP ACE cluster initialINodeCount: 2 You want to use Cloud Deployment Manager to create this cluster in GKE. What should you do?", options: { A: "gcloud deployment-manager deployments create my-gcp-ace-cluster --config cluster.yaml", B: "gcloud deployment-manager deployments create my-gcp-ace-cluster --type container.v1.cluster - -config cluster.yaml", C: "gcloud deployment-manager deployments apply my-gcp-ace-cluster --type container.v1.cluster -- config cluster.yaml", D: "gcloud deployment-manager deployments apply my-gcp-ace-cluster --config cluster.yaml" }, correct: ["D"] },
  { id: 224, text: "You are designing an application that uses WebSockets and HTTP sessions that are not distributed across the web servers. You want to ensure the application runs properly on Google Cloud Platform. What should you do?", options: { A: "Meet with the cloud enablement team to discuss load balancer options.", B: "Redesign the application to use a distributed user session service that does not rely on WebSockets and HTTP sessions.", C: "Review the encryption requirements for WebSocket connections with the security team.", D: "Convert the WebSocket code to use HTTP streaming." }, correct: ["A"] },
  { id: 225, text: "You have deployed multiple Linux instances on Compute Engine. You plan on adding more instances in the coming weeks. You want to be able to access all of these instances through your SSH client over me Internet without having to configure specific access on the existing and new instances. You do not want the Compute Engine instances to have a public IP. What should you do?", options: { A: "Configure Cloud Identity-Aware Proxy (or HTTPS resources", B: "Configure Cloud Identity-Aware Proxy for SSH and TCP resources.", C: "Create an SSH keypair and store the public key as a project-wide SSH Key", D: "Create an SSH keypair and store the private key as a project-wide SSH Key" }, correct: ["B"] },
  { id: 226, text: "You need to deploy a single stateless web application with a web interface and multiple endpoints. For security reasons, the web application must be reachable from an internal IP address from your company's private VPC and on- premises network. You also need to update the web application multiple times per day with minimal effort and want to manage a minimal amount of cloud infrastructure. What should you do?", options: { A: "Deploy the web application on Google Kubernetes Engine standard edition with an internal ingress.", B: "Deploy the web application on Cloud Run with Private Google Access configured", C: "Deploy the web application to GKE Autopilot with Private Google Access configured", D: "Deploy the web application on Cloud Run with Private Service Connect configured." }, correct: ["A"] },
  { id: 227, text: "Your company requires that Google Cloud products are created with a specific configuration to comply with your company's security policies. You need to implement a mechanism that will allow software engineers at your company to deploy and update Google Cloud products in a preconfigured and approved manner. What should you do?", options: { A: "Create Java packages that utilize the Google Cloud Client Libraries for Java to configure Google Cloud products. Store and share the packages in a source code repository.", B: "Create bash scripts that utilize the Google Cloud CLI to configure Google Cloud products. Store and share the bash scripts in a source code repository.", C: "Use the Google Cloud APIs by using curl to configure Google Cloud products. Store and share the curl commands in a source code repository.", D: "Create Terraform modules that utilize the Google Cloud Terraform Provider to configure Google Cloud products. Store and share the modules in a source code repository." }, correct: ["D"] },
  { id: 228, text: "You use Cloud Logging to capture application logs. You now need to use SQL to analyze the application logs in Cloud Logging, and you want to follow Google-recommended practices. What should you do?", options: { A: "Develop SQL queries by using Gemini for Google Cloud.", B: "Enable Log Analytics for the log bucket and create a linked dataset in BigQuery.", C: "Create a schema for the storage bucket and run SQL queries for the data in the bucket.", D: "Export logs to a storage bucket and create an external view in BigQuery." }, correct: ["B"] },
  { id: 229, text: "Your company is running a three-tier web application on virtual machines that use a MySQL database. You need to create an estimated total cost of cloud infrastructure to run this application on Google Cloud instances and Cloud SQL. What should you do?", options: { A: "Create a Google spreadsheet with multiple Google Cloud resource combinations. On a separate sheet, import the current Google Cloud prices and use these prices for the calculations within formulas.", B: "Use the Google Cloud Pricing Calculator and select the Cloud Operations template to define your web application with as much detail as possible.", C: "Implement a similar architecture on Google Cloud, and run a reasonable load test on a smaller scale. Check the billing information, and calculate the estimated costs based on the real load your system usually handles.", D: "Use the Google Cloud Pricing Calculator to determine the cost of every Google Cloud resource you expect to use. Use similar size instances for the web server, and use your current on-premises machines as a comparison for Cloud SQL." }, correct: ["D"] },
  { id: 230, text: "Your manager asks you to deploy a workload to a Kubernetes cluster. You are not sure of the workloads resource requirements or how the requirements might vary depending on usage patterns, external dependencies, or other factors. You need a solution that makes cost-effective recommendations regarding CPU and memory requirements, and allows the workload to function consistently in any situation. You want to follow Google-recommended practices. What should you do?", options: { A: "Configure the Horizontal Pod Autoscaler for availability, and configure the cluster autoscaler for suggestions.", B: "Configure the Horizontal Pod Autoscaler for availability, and configure the Vertical Pod Autoscaler recommendations for suggestions.", C: "Configure the Vertical Pod Autoscaler recommendations for availability, and configure the Cluster autoscaler for suggestions.", D: "Configure the Vertical Pod Autoscaler recommendations for availability, and configure the Horizontal Pod Autoscaler for suggestions." }, correct: ["B"] },
  { id: 231, text: "You need to deploy a third-party software application onto a single Compute Engine VM instance. The application requires the highest speed read and write disk access for the internal database. You need to ensure the instance will recover on failure. What should you do?", options: { A: "Create an instance template. Set the disk type to be an SSD Persistent Disk. Launch the instance template as part of a stateful managed instance group.", B: "Create an instance template. Set the disk type to be an SSD Persistent Disk. Launch the instance template as part of a stateless managed instance group.", C: "Create an instance template. Set the disk type to be Hyperdisk Extreme. Launch the instance template as part of a stateful managed instance group.", D: "Create an instance template. Set the disk type to be Hyperdisk Extreme. Launch the instance template as part of a stateless managed instance group." }, correct: ["C"] },
  { id: 232, text: "Your company is running a critical workload on a single Compute Engine VM instance. Your company's disaster recovery policies require you to back up the entire instance’s disk data every day. The backups must be retained for 7 days. You must configure a backup solution that complies with your company’s security policies and requires minimal setup and configuration. What should you do?", options: { A: "Configure the instance to use persistent disk asynchronous replication.", B: "Configure daily scheduled persistent disk snapshots with a retention period of 7 days.", C: "Configure Cloud Scheduler to trigger a Cloud Function each day that creates a new machine image and deletes machine images that are older than 7 days.", D: "Configure a bash script using gsutil to run daily through a cron job. Copy the disk’s files to a Cloud Storage bucket with archive storage class and an object lifecycle rule to delete the objects after 7 days." }, correct: ["B"] },
  { id: 233, text: "You have several hundred microservice applications running in a Google Kubernetes Engine (GKE) cluster. Each microservice is a deployment with resource limits configured for each container in the deployment. You've observed that the resource limits for memory and CPU are not appropriately set for many of the microservices. You want to ensure that each microservice has right sized limits for memory and CPU. What should you do?", options: { A: "Configure a Vertical Pod Autoscaler for each microservice.", B: "Modify the cluster's node pool machine type and choose a machine type with more memory and CPU.", C: "Configure a Horizontal Pod Autoscaler for each microservice.", D: "Configure GKE cluster autoscaling." }, correct: ["A"] },
  { id: 234, text: "You are deploying an application on Google Cloud that requires a relational database for storage. To satisfy your company's security policies, your application must connect to your database through an encrypted and authenticated connection that requires minimal management and integrates with Identity and Access Management (IAM). What should you do?", options: { A: "Deploy a Cloud SQL database with the SSL mode set to encrypted only, configure SSL/TLS client certificates, and configure a database user and password.", B: "Deploy a Cloud SOL database and configure IAM database authentication. Access the database through the Cloud SQL Auth Proxy.", C: "Deploy a Cloud SQL database with the SSL mode set to encrypted only, configure SSL/TLS client certificates, and configure IAM database authentication.", D: "Deploy a Cloud SQL database and configure a database user and password. Access the database through the Cloud SQL Auth Proxy." }, correct: ["B"] },
  { id: 235, text: "You want to deploy a new containerized application into Google Cloud by using a Kubernetes manifest. You want to have full control over the Kubernetes deployment, and at the same time, you want to minimize configuring infrastructure. What should you do?", options: { A: "Deploy the application on GKE Autopilot.", B: "Deploy the application on Cloud Run.", C: "Deploy the application on GKE Standard.", D: "Deploy the application on Cloud Functions." }, correct: ["A"] },
  { id: 236, text: "Your preview application, deployed on a single-zone Google Kubernetes Engine (GKE) cluster in us-central1, has gained popularity. You are now ready to make the application generally available. You need to deploy the application to production while ensuring high availability and resilience. You also want to follow Google-recommended practices. What should you do?", options: { A: "Use the gcloud container clusters create command with the options -enable-multi-networking and -- enable-autoscaling to create an autoscaling zonal cluster and deploy the application to it.", B: "Use the gcloud container clusters create-auto command to create an autopilot cluster and deploy the application to it.", C: "Use the gcloud container clusters update command with the option —region us-central1 to update the cluster and deploy the application to it.", D: "Use the gcloud container clusters update command with the option -node-locations us-central1-a,us- central1-b to update the cluster and deploy the application to the nodes." }, correct: ["B"] },
  { id: 237, text: "You are running out of primary internal IP addresses in a subnet for a custom mode VPC. The subnet has the IP tange 10.0.0.0/20, and the IP addresses are primarily used by virtual machines in the project. You need to provide more IP addresses for the virtual machines. What should you do?", options: { A: "Add a secondary IP range 10.1.0.0/20 to the subnet.", B: "Change the subnet IP range from 10.0.0.0/20 to 10.0.0.0/18.", C: "Change the subnet IP range from 10.0.0.0/20 to 10.0.0.0/22.", D: "Convert the subnet IP range from IPv4 to IPv6." }, correct: ["B"] },
  { id: 238, text: "You are a Google Cloud organization administrator. You need to configure organization policies and log sinks on Google Cloud projects that cannot be removed by project users to comply with your company's security policies. The security policies are different for each company department. Each company department has a user with the Project Owner role assigned to their projects. What should you do?", options: { A: "Use a standard naming convention for projects that includes the department name. Configure organization policies on the organization and log sinks on the projects.", B: "Use a standard naming convention for projects that includes the department name. Configure both organization policies and log sinks on the projects.", C: "Organize projects under folders for each department. Configure both organization policies and log sinks on the folders.", D: "Organize projects under folders for each department. Configure organization policies on the organization and log sinks on the folders." }, correct: ["C"] },
  { id: 239, text: "Your application stores files on Cloud Storage by using the Standard Storage class. The application only requires access to files created in the last 30 days. You want to automatically save costs on files that are no longer accessed by the application. What should you do?", options: { A: "Create an object lifecycle on the storage bucket to change the storage class to Archive Storage for objects with an age over 30 days.", B: "Create a cron job in Cloud Scheduler to call a Cloud Functions instance every day to delete files older than 30 days.", C: "Create a retention policy on the storage bucket of 30 days, and lock the bucket by using a retention policy lock.", D: "Enable object versioning on the storage bucket and add lifecycle rules to expire non-current versions after 30 days." }, correct: ["A"] },
  { id: 240, text: "During a recent audit of your existing Google Cloud resources, you discovered several users with email addresses outside of your Google Workspace domain. You want to ensure that your resources are only shared with users whose email addresses match your domain. You need to remove any mismatched users, and you want to avoid having to audit your Tesources to identify mismatched users. What should you do?", options: { A: "Create a Cloud Scheduler task to regularly scan your projects and delete mismatched users.", B: "Create a Cloud Scheduler task to regularly scan your resources and delete mismatched users.", C: "Set an organizational policy constraint to limit identities by domain to automatically remove mismatched users.", D: "Set an organizational policy constraint to limit identities by domain, and then retroactively remove the existing mismatched users" }, correct: ["D"] },
  { id: 241, text: "You have deployed an application on a Compute Engine instance. An external consultant needs to access the Linux-based instance. The consultant is connected to your corporate network through a VPN connection, but the consultant has no Google account. What should you do?", options: { A: "Instruct the external consultant to use the gcloud compute ssh command line tool by using Identity- Aware Proxy to access the instance.", B: "Instruct the external consultant to use the gcloud compute ssh command line tool by using the public IP address of the instance to access it.", C: "Instruct the external consultant to generate an SSH key pair, and request the public key from the consultant. Add the public key to the instance yourself, and have the consultant access the instance through SSH with their private key.", D: "Instruct the external consultant to generate an SSH key pair, and request the private key from the consultant. Add the private key to the instance yourself, and have the consultant access the instance through SSH with their public key." }, correct: ["C"] },
  { id: 242, text: "You have an on-premises data analytics set of binaries that processes data files in memory for about 45 minutes every midnight. The sizes of those data files range from 1 gigabyte to 16 gigabytes. You want to migrate this application to Google Cloud with minimal effort and cost. What should you do?", options: { A: "Create a container for the set of binaries. Use Cloud Scheduler to start a Cloud Run job for the container.", B: "Create a container for the set of binaries. Deploy the container to Google Kubernetes Engine (GKE) and use the Kubernetes scheduler to start the application.", C: "Upload the code to Cloud Functions. Use Cloud Scheduler to start the application.", D: "Lift and shift to a VM on Compute Engine. Use an instance schedule to start and stop the instance." }, correct: ["D"] },
  { id: 243, text: "Your company is moving its continuous integration and delivery (CI/CD) pipeline to Compute Engine instances. The pipeline will manage the entire cloud infrastructure through code. How can you ensure that the pipeline has appropriate permissions while your system is following security best practices?", options: { A: "+ Attach a single service account to the compute instances. + Add minimal rights to the service account. + Allow the service account to impersonate a Cloud Identity user with elevated permissions to create, update, or delete resources.", B: "« Add a step for human approval to the CI/CD pipeline before the execution of the infrastructure provisioning. + Use the human approvals IAM account for the provisioning.", C: "+ Attach a single service account to the compute instances. + Add all required Identity and Access Management (IAM) permissions to this service account to create, update, or delete resources.", D: "+ Create multiple service accounts, one for each pipeline with the appropriate minimal Identity and Access Management (IAM) permissions. + Use a secret manager service to store the key files of the service accounts. + Allow the CI/CD pipeline to request the appropriate secrets during the execution of the pipeline." }, correct: ["D"] },
  { id: 244, text: "Your auditor wants to view your organization's use of data in Google Cloud. The auditor is most interested in auditing who accessed data in Cloud Storage buckets. You need to help the auditor access the data they need. What should you do?", options: { A: "Turn on Data Access Logs for the buckets they want to audit, and then build a query in the log viewer that filters on Cloud Storage.", B: "Assign the appropriate permissions, and then create a Data Studio report on Admin Activity Audit Logs.", C: "Assign the appropriate permissions, and then use Cloud Monitoring to review metrics.", D: "Use the export logs API to provide the Admin Activity Audit Logs in the format they want." }, correct: ["A"] },
  { id: 245, text: "You are working for a hospital that stores its medical images in an on-premises data room. The hospital wants to use Cloud Storage for archival storage of these images. The hospital wants an automated process to upload any new medical images to Cloud Storage. You need to design and implement a solution. What should you do?", options: { A: "Create a Pub/Sub topic, and enable a Cloud Storage trigger for the Pub/Sub topic. Create an application that sends all medical images to the Pub/Sub topic.", B: "Create a script that uses the gcloud storage command to synchronize the on-premises storage with Cloud Storage, Schedule the script as a cron job.", C: "Create a Pub/Sub topic, and create a Cloud Function connected to the topic that writes data to Cloud Storage. Create an application that sends all medical images to the Pub/Sub topic.", D: "In the Google Cloud console, go to Cloud Storage. Upload the relevant images to the appropriate bucket." }, correct: ["B"] },
  { id: 246, text: "Your organization needs to grant users access to query datasets in BigQuery but prevent them from accidentally deleting the datasets. You want a solution that follows Google-recommended practices. What should you do?", options: { A: "Add users to roles/bigquery user role only, instead of roles/bigquery dataOwner.", B: "Add users to roles/bigquery dataEditor role only, instead of roles/bigquery dataOwner.", C: "Create a custom role by removing delete permissions, and add users to that role only.", D: "Create a custom role by removing delete permissions. Add users to the group, and then add the group to the custom role." }, correct: ["D"] },
  { id: 247, text: "Your company wants to migrate their on-premises workloads to Google Cloud. The current on-premises workloads consist of: + A Flask web application + A backend API + A scheduled long-running background job for ETL and reporting You need to keep operational costs low. You want to follow Google-recommended practices to migrate these workloads to serverless solutions on Google Cloud. What should you do?", options: { A: "Migrate the web application to App Engine and the backend API to Cloud Run. Use Cloud Tasks to run your backg\"cu1nd job on Compute Engine.", B: "Migrate the web application to App Engine and the backend API to Cloud Run. Use Cloud Tasks to run your background job on Cloud Run.", C: "Run the web application on a Cloud Storage bucket and the backend API on Cloud Run. Use Cloud Tasks to run your background job on Cloud Run.", D: "Run the web application on a Cloud Storage bucket and the backend API on Cloud Run. Use Cloud Tasks to run your background job on Compute Engine. a Cresta" }, correct: ["B"] },
  { id: 248, text: "Your company runs a variety of applications and workloads on Google Cloud and you are responsible for managing cloud costs. You need to identify a solution that enables you to perform detailed cost analysis You also must be able to visualize the cost data in multiple ways on the same dashboard What should you do?", options: { A: "Run Queries in Cloud Monitoring Create dashboards to visualize the billing metrics", B: "Enable Cloud Monitoring metrics export to BigQuery and use Looker to visualize the data", C: "Enable the Cloud Billing export to BigQuery. and use Looker Studio to visualize the data", D: "Use the cost breakdown report with the available filters from Cloud Billing to visualize the data" }, correct: ["C"] },
  { id: 249, text: "Your company completed the acquisition of a startup and is now merging the IT systems of both companies. The startup had a production Google Cloud project in their organization. You need to move this project into your organization and ensure that the project is billed to your organization. You want to accomplish this task with minimal effort. What should you do?", options: { A: "Use the projects.move method to move the project to your organization. Update the billing account of the project to that of your organization.", B: "Ensure that you have an Organization Administrator Identity and Access Management (IAM) role assigned to you in both organizations. Navigate to the Resource Manager in the startup’s Google Cloud organization, and drag the project to your company's organization.", C: "Create a Private Catalog for the Google Cloud Marketplace, and upload the resources of the startup's production project to the Catalog. Share the Catalog with your organization, and deploy the resources in your company’s project.", D: "Create an infrastructure-as-code template for all resources in the project by using Terraform, and deploy that template to a new project in your organization. Delete the project from the startup’s Google Cloud organization." }, correct: ["A"] },
  { id: 250, text: "A colleague handed over a Google Cloud Platform project for you to maintain. As part of a security checkup, you want to review who has been granted the Project Owner role. What should you do?", options: { A: "In the console, validate which SSH keys have been stored as project-wide keys.", B: "Navigate to Identity-Aware Proxy and check the permissions for these resources.", C: "Enable Audit Logs on the IAM & admin page for all resources, and validate the results.", D: "Use the command gcloud projects get\"€aiam\"€apolicy to view the current role assignments." }, correct: ["D"] },
  { id: 251, text: "You are responsible for a web application on Compute Engine. You want your support team to be notified automatically if users experience high latency for at least 5 minutes. You need a Google-recommended solution with no development cost. What should you do?", options: { A: "Export Cloud Monitoring metrics to BigQuery and use a Looker Studio dashboard to monitor your web application's latency.", B: "Create an alert policy to send a notification when the HTTP response latency exceeds the specified threshold.", C: "Implement an App Engine service which invokes the Cloud Monitoring API and sends a notification in case of anomalies.", D: "Use the Cloud Monitoring dashboard to observe latency and take the necessary actions when the response latency exceeds the specified threshold." }, correct: ["B"] },
  { id: 252, text: "You have an application on a general-purpose Compute Engine instance that is experiencing excessive disk read throttling on its Zonal SSD Persistent Disk. The application primarily reads large files from disk. The disk size is currently 350 GB. You want to provide the maximum amount of throughput while minimizing costs. What should you do?", options: { A: "Increase the size of the disk to 1 TB.", B: "Increase the allocated CPU to the instance.", C: "Migrate to use a Local SSD on the instance.", D: "Migrate to use a Regional SSD on the instance." }, correct: ["C"] },
  { id: 253, text: "You are configuring Cloud DNS. You want to create DNS records to point home.mydomain.com, mydomain.com, and www.mydomain.com to the IP address of your Google Cloud load balancer. What should you do?", options: { A: "Create one CNAME record to point mydomain.com to the load balancer, and create two A records to point WWW and HOME to mydomain.com respectively.", B: "Create one CNAME record to point mydomain.com to the load balancer, and create two AAAA records to point WWW and HOME to mydomain.com respectively.", C: "Create one A record to point mydomain.com to the load balancer, and create two CNAME records to point WWW and HOME to mydomain.com respectively.", D: "Create one A record to point mydomain.com to the load balancer, and create two NS records to point WWW and HOME to mydomain.com respectively." }, correct: ["C"] },
  { id: 254, text: "Your digital media company stores a large number of video files on-premises. Each video file ranges from 100 MB to 100 GB. You are currently storing 150 TB of video data in your on-premises network, with no room for expansion. You need to migrate all infrequently accessed video files older than one year to Cloud Storage to ensure that on-premises storage remains available for new files. You must also minimize costs and control bandwidth usage. What should you do?", options: { A: "Create a Cloud Storage bucket. Establish an Identity and Access Management (IAM) role with write permissions to the bucket. Use the gsutil tool to directly copy files over the network to Cloud Storage.", B: "Set up a Cloud Interconnect connection between the on-premises network and Google Cloud. Establish a private endpoint for Filestore access. Transfer the data from the existing Network File System (NFS) to Filestore.", C: "Use Transfer Appliance to request an appliance. Load the data locally, and ship the appliance back to Google for ingestion into Cloud Storage.", D: "Use Storage Transfer Service to move the data from the selected on-premises file storage systems to a Cloud Storage bucket." }, correct: ["D"] },
  { id: 255, text: "Your application is running on Google Cloud in a managed instance group (MIG). You see errors in Cloud Logging for one VM that one of the processes is not responsive. You want to replace this VM in the MIG quickly. What should you do?", options: { A: "Select the MIG from the Compute Engine console and, in the menu, select Replace VMs.", B: "Use the gcloud compute instance-groups managed recreate-instances command to recreate the VM.", C: "Use the gcloud compute instances update command with a REFRESH action for the VM. D .Update and apply the instance template of the MIG." }, correct: ["A"] },
  { id: 256, text: "The DevOps group in your organization needs full control of Compute Engine resources in your development project. However, they should not have permission to create or update any other resources in the project. You want to follow Google's recommendations for setting permissions for the DevOps group. What should you do?", options: { A: "Grant the basic role roles/viewer and the predefined role roles/compute.admin to the DevOps group.", B: "Create an IAM policy and grant all compute.instanceAdmin.* permissions to the policy. Attach the policy to the DevOps group.", C: "Create a custom role at the folder level and grant all compute.instanceAdmin.* permissions to the role. Grant the custom role to the DevOps group.", D: "Grant the basic role roles/editor to the DevOps group." }, correct: ["A"] },
  { id: 257, text: "You are the Google Cloud systems administrator for your organization. User A reports that they received an error when attempting to access the Cloud SQL database in their Google Cloud project, while User B can access the database. You need to troubleshoot the issue for User A, while following Google-recommended practices. What should you do first?", options: { A: "Verify that User A has the Identity and Access Management (IAM) Project Owner role assigned.", B: "Review recent configuration changes that may have caused unintended modifications to permissions.", C: "Review the error message that User A received.", D: "Confirm that network firewall rules are not blocking traffic for User A." }, correct: ["C"] },
  { id: 258, text: "You need to migrate multiple PostgreSQL databases from your on-premises data center to Google Cloud. You want to significantly improve the performance of your databases while minimizing changes to your data schema and application code. You expect to exceed 150 TB of data per geographical region. You want to follow Google-recommended practices and minimize your operational costs. What should you do?", options: { A: "Migrate your data to Firebase.", B: "Migrate your data to Spanner.", C: "Migrate your data to Bigtable.", D: "Migrate your data to AlloyDB." }, correct: ["D"] },
  { id: 259, text: "You are working with a Cloud SQL MySQL database at your company. You need to retain a month-end copy of the database for three years for audit purposes. What should you do?", options: { A: "Set up an export job for the first of the month. Write the export file to an Archive class Cloud Storage bucket.", B: "Save the automatic first-of-the-month backup for three years. Store the backup file in an Archive class Cloud Storage bucket.", C: "Set up an on-demand backup for the first of the month. Write the backup to an Archive class Cloud Storage bucket.", D: "Convert the automatic first-of-the-month backup to an export file. Write the export file to a Coldline class Cloud Storage bucket." }, correct: ["A"] },
  { id: 260, text: "You created a Kubernetes deployment by running kubectl run nginx image=nginx labels=app=prod. Your Kubernetes cluster is also used by a number of other deployments. How can you find the identifier of the pods for this nginx deployment?", options: { A: "gcloud list gke-deployments -filter={pod }", B: "kubectl get deployments -output=pods", C: "gcloud get pods -selector=\"app=prod\"", D: "kubectl get pods -I “app=prod\"" }, correct: ["D"] },
  { id: 261, text: "Your management has asked an external auditor to review all the resources in a specific project. The security team has enabled the Organization Policy called Domain Restricted Sharing on the organization node by specifying only your Cloud Identity domain. You want the auditor to only be able to view, but not modify, the resources in that project. What should you do?", options: { A: "Ask the auditor for their Google account, and give them the Viewer role on the project.", B: "Ask the auditor for their Google account, and give them the Security Reviewer role on the project.", C: "Create a temporary account for the auditor in Cloud Identity, and give that account the Viewer role on the project", D: "Create a temporary account for the auditor in Cloud Identity, and give that account the Security Reviewer role on the project." }, correct: ["C"] },
  { id: 262, text: "You are deploying a web application using Compute Engine. You created a managed instance group (MIG) to host the application. You want to follow Google-recommended practices to implement a secure and highly available solution. What should you do?", options: { A: "Use SSL proxy load balancing for the MIG and an A record in your DNS private zone with the load balancer's IP address.", B: "Use SSL proxy load balancing for the MIG and a CNAME record in your DNS public zone with the load balancer’s IP address.", C: "Use HTTP(S) load balancing for the MIG and a CNAME record in your DNS private zone with the load balancer's IP address.", D: "Use HTTP(S) load balancing for the MIG and an A record in your DNS public zone with the load balancer’s IP address." }, correct: ["D"] },
  { id: 263, text: "You are developing a new application and are looking for a Jenkins installation to build and deploy your source code. You want to automate the installation as quickly and easily as possible. What should you do?", options: { A: "Deploy Jenkins through the Google Cloud Marketplace.", B: "Create a new Compute Engine instance. Run the Jenkins executable.", C: "Create a new Kubernetes Engine cluster. Create a deployment for the Jenkins image.", D: "Create an instance template with the Jenkins executable. Create a managed instance group with this template." }, correct: ["A"] },
  { id: 264, text: "You have an application that uses Cloud Spanner as a database backend to keep current state information about users. Cloud Bigtable logs all events triggered by users. You export Cloud Spanner data to Cloud Storage during daily backups. One of your analysts asks you to join data from Cloud Spanner and Cloud Bigtable for specific users. You want to complete this ad hoc request as efficiently as possible. What should you do? ACreate a dataflow job that copies data from Cloud Bigtable and Cloud Spanner for specific users.", options: { A: "Create a dataflow job that copies data from Cloud Bigtable and Cloud Spanner for specific users.", B: "Create two separate BigQuery external tables on Cloud Storage and Cloud Bigtable. Use the BigQuery console to join these tables through user fields, and apply appropriate filters.", C: "Create a Cloud Dataproc cluster that runs a Spark job to extract data from Cloud Bigtable and Cloud Storage for specific users.", D: "Create a dataflow job that copies data from Cloud Bigtable and Cloud Storage for specific users." }, correct: ["B"] },
  { id: 265, text: "You need to create and manage service accounts for your workloads running on Google Cloud. You want to follow Google-recommended practices. What should you do? Choose 2 answers", options: { A: "Manage service accounts as resources.", B: "Create as few service accounts as possible.", C: "Create single-purpose service accounts.", D: "Delete any unused service accounts immediately.", E: "Use random names for the service accounts." }, correct: ["C", "D"] },
  { id: 266, text: "You have a VM instance running in a VPC with single-stack subnets. You need to ensure that the VM instance has a fixed IP address so that other services hosted in the same VPC can communicate with the VM. You want to follow Google-recommended practices while minimizing cost. What should you do?", options: { A: "Promote the existing IP address of the VM to become a static external IP address.", B: "Promote the existing IP address of the VM to become a static internal IP address.", C: "Reserve a new static external IPv6 address and assign the new IP address to the VM.", D: "Reserve a new static external IP address and assign the new IP address to the VM." }, correct: ["B"] },
  { id: 267, text: "You are the team lead of a group of 10 developers. You provided each developer with an individual Google Cloud Project that they can use as their personal sandbox to experiment with different Google Cloud solutions. You want to be notified if any of the developers are spending above $500 per month on their sandbox environment. What should you do?", options: { A: "Create a single budget for all projects and configure budget alerts on this budget.", B: "Create a separate billing account per sandbox project and enable BigQuery billing exports. Create a Data Studio dashboard to plot the spending per billing account.", C: "Create a budget per project and configure budget alerts on all of these budgets.", D: "Create a single billing account for all sandbox projects and enable BigQuery billing exports. Create a Data Studio dashboard to plot the spending per project." }, correct: ["C"] },
  { id: 268, text: "Your organization has three existing Google Cloud projects. You need to bill the Marketing department for only their Google Cloud services for a new initiative within their group. What should you do?", options: { A: "1. Verify that you are assigned the Billing Administrator IAM role for your organization's Google Cloud Project for the Marketing department. 2. Link the new project to a Marketing Billing Account.", B: "1. Verify that you are assigned the Billing Administrator IAM role for your organization's Google Cloud account. 2. Create a new Google Cloud Project for the Marketing department. 3. Set the default key-value project labels to department:marketing for all services in this project.", C: "1. Verify that you are assigned the Organization Administrator IAM role for your organization's Google Cloud account. 2. Create a new Google Cloud Project for the Marketing department. 3. Link the new project to a Marketing Billing Account.", D: "1. Verify that you are assigned the Organization Administrator IAM role for your organization's Google Cloud account. 2. Create a new Google Cloud Project for the Marketing department. 3. Set the default key-value project labels to department:marketing for all services in this project." }, correct: ["A"] },
  { id: 269, text: "The core business of your company is to rent out construction equipment at large scale. All the equipment that is being rented out has been equipped with multiple sensors that send event information every few seconds. These signals can vary from engine status, distance traveled, fuel level, and more. Customers are billed based on the consumption monitored by these sensors. You expect high throughput - up to thousands of events per hour per device — and need to retrieve consistent data based on the time of the event. Storing and retrieving individual signals should be atomic. What should you do?", options: { A: "Create files in Cloud Storage as data comes in.", B: "Create a file in Filestore per device, and append new data to that file.", C: "Ingest the data into Cloud SQL. Use multiple read replicas to match the throughput.", D: "Ingest the data into Bigtable. Create a row key based on the event timestamp." }, correct: ["D"] },
  { id: 270, text: "Your team wants to deploy a specific content management system (CMS) solution to Google Cloud. You need a quick and easy way to deploy and install the solution. What should you do?", options: { A: "Search for the CMS solution in Google Cloud Marketplace. Use gcloud CLI to deploy the solution.", B: "Search for the CMS solution in Google Cloud Marketplace. Deploy the solution directly from Cloud Marketplace.", C: "Search for the CMS solution in Google Cloud Marketplace. Use Terraform and the Cloud Marketplace ID to deploy the solution with the appropriate parameters.", D: "Use the installation guide of the CMS provider. Perform the installation through your configuration management system." }, correct: ["B"] },
  { id: 271, text: "You have just created a new project which will be used to deploy a globally distributed application. You will use Cloud Spanner for data storage. You want to create a Cloud Spanner instance. You want to perform the first step in preparation of creating the instance. What should you do?", options: { A: "Enable the Cloud Spanner API.", B: "Configure your Cloud Spanner instance to be multi-regional.", C: "Create a new VPC network with subnetworks in all desired regions.", D: "Grant yourself the IAM role of Cloud Spanner Admin." }, correct: ["A"] },
  { id: 272, text: "Your company wants to standardize the creation and management of multiple Google Cloud resources using Infrastructure as Code. You want to minimize the amount of repetitive code needed to manage the environment. What should you do?", options: { A: "Develop templates for the environment using Cloud Deployment Manager.", B: "Use curl in a terminal to send a REST request to the relevant Google API for each individual resource.", C: "Use the Cloud Console interface to provision and manage all related resources.", D: "Create a bash script that contains all requirement steps as gcloud commands." }, correct: ["A"] },
  { id: 273, text: "You recently discovered that your developers are using many service account keys during their development process. While you work on a long term improvement, you need to quickly implement a process to enforce short-lived service account credentials in your company. You have the following requirements: + All service accounts that require a key should be created in a centralized project called pj-sa. + Service account keys should only be valid for one day. You need a Google-recommended solution that minimizes cost. What should you do?", options: { A: "Implement a Cloud Run job to rotate all service account keys periodically in pj-sa. Enforce an org policy to deny service account key creation with an exception to pj-sa.", B: "Implement a Kubernetes CronJob to rotate all service account keys periodically. Disable attachment of service accounts to resources in all projects with an exception to pj-sa.", C: "Enforce an org policy constraint allowing the lifetime of service account keys to be 24 hours. Enforce an org policy constraint denying service account key creation with an exception on pj-sa.", D: "Enforce a DENY org policy constraint over the lifetime of service account keys for 24 hours. Disable attachment of service accounts to resources in all projects with an exception to pj-sa." }, correct: ["C"] },
  { id: 274, text: "You built an application on your development laptop that uses Google Cloud services. Your application uses Application Default Credentials for authentication and works fine on your development laptop. You want to migrate this application to a Compute Engine virtual machine (VM) and set up authentication using Google- recommended practices and minimal changes. What should you do?", options: { A: "Assign appropriate access for Google services to the service account used by the Compute Engine VM.", B: "Create a service account with appropriate access for Google services, and configure the application to use this account.", C: "Store credentials for service accounts with appropriate access for Google services in a config file, and deploy this config file with your application.", D: "Store credentials for your user account with appropriate access for Google services in a config file, and deploy this config file with your application." }, correct: ["A"] },
  { id: 275, text: "You need to immediately change the storage class of an existing Google Cloud bucket. You need to reduce service cost for infrequently accessed files stored in that bucket and for all files that will be added to that bucket in the future. What should you do?", options: { A: "Use the gsutil to rewrite the storage class for the bucket Change the default storage class for the bucket", B: "Use the gsutil to rewrite the storage class for the bucket Set up Object Lifecycle management on the bucket", C: "Create a new bucket and change the default storage class for the bucket Set up Object Lifecycle management on lite bucket", D: "Create a new bucket and change the default storage class for the bucket import the files from the previous bucket into the new bucket" }, correct: ["B"] },
  { id: 276, text: "Users of your application are complaining of slowness when loading the application. You realize the slowness is because the App Engine deployment serving the application is deployed in us-central whereas all users of this application are closest to europe-west3. You want to change the region of the App Engine application to europe-west3 to minimize latency. What's the best way to change the App Engine region?", options: { A: "Create a new project and create an App Engine instance in europe-west3", B: "Use the gcloud app region set command and supply the name of the new region.", C: "From the console, under the App Engine page, click edit, and change the region drop-down.", D: "Contact Google Cloud Support and request the change. om" }, correct: ["A"] },
  { id: 277, text: "Your existing application running in Google Kubernetes Engine (GKE) consists of multiple pods running on four GKE n1°\"standard’\"2 nodes. You need to deploy additional pods requiring n2\"\"highmem’\"16 nodes without any downtime. What should you do?", options: { A: "Use gcloud container clusters upgrade. Deploy the new services.", B: "Create a new Node Pool and specify machine type n2\"€ahighmem .16\"€aDeploy the new pods.", C: "Create a new cluster with n2\"€ahighmem 16\"€anodes. Redeploy the pods and delete the old cluster.", D: "Create a new cluster with both n1\"€astandard 2\"€aand n2\"€ahighmem 16\"€anodes. Redeploy the pods and delete the old cluster." }, correct: ["B"] },
  { id: 278, text: "You are monitoring an application and receive user feedback that a specific error is spiking. You notice that the error is caused by a Service Account having insufficient permissions. You are able to solve the problem but want to be notified if the problem recurs. What should you do?", options: { A: "In the Log Viewer, filter the logs on severity ‘Error’ and the name of the Service Account.", B: "Create a sink to BigQuery to export all the logs. Create a Data Studio dashboard on the exported logs.", C: "Create a custom log-based metric for the specific error to be used in an Alerting Policy.", D: "Grant Project Owner access to the Service Account." }, correct: ["C"] },
  { id: 279, text: "You are designing an application that lets users upload and share photos. You expect your application to grow really fast and you are targeting a worldwide audience. You want to delete uploaded photos after 30 days. You want to minimize costs while ensuring your application is highly available. Which GCP storage solution should you choose?", options: { A: "Persistent SSD on VM instances.", B: "Cloud Filestore.", C: "Multiregional Cloud Storage bucket.", D: "Cloud Datastore database." }, correct: ["C"] },
  { id: 280, text: "An application generates daily reports in a Compute Engine virtual machine (VM). The VM is in the project corp-iot-insights. Your team operates only in the project corp-aggregate-reports and needs a copy of the daily exports in the bucket corp-aggregate-reports-storage. You want to configure access so that the daily reports from the VM are available in the bucket corp-aggregate-reports-storage and use as few steps as possible while following Google-recommended practices. What should you do?", options: { A: "Move both projects under the same folder.", B: "Grant the VM Service Account the role Storage Object Creator on corp-aggregate-reports- storage.", C: "Create a Shared VPC network between both project", D: "Grant the VM Service Account the role Storage Object Creator on corp-iot-insights.", E: "Make corp-aggregate-reports-storage public and create a folder with a pseudo-randomized suffix name.Share the folder with the loT team." }, correct: ["B"] },
  { id: 281, text: "Your company requires all developers to have the same permissions, regardless of the Google Cloud project they are working on. Your company’s security policy also restricts developer permissions to Compute Engine, Cloud Functions, and Cloud SQL. You want to implement the security policy with minimal effort. What should you do?", options: { A: "+ Create a custom role with Compute Engine, Cloud Functions, and Cloud SQL permissions in one project within the Google Cloud organization. + Copy the role across all projects created within the organization with the gcloud iam roles copy command. + Assign the role to developers in those projects.", B: "+ Add all developers to a Google group in Google Groups for Workspace. + Assign the predefined role of Compute Admin to the Google group at the Google Cloud organization level.", C: "+ Add all developers to a Google group in Cloud Identity. + Assign predefined roles for Compute Engine, Cloud Functions, and Cloud SQL permissions to the Google group for each project in the Google Cloud organization.", D: "+ Add all developers to a Google group in Cloud Identity. + Create a custom role with Compute Engine, Cloud Functions, and Cloud SQL permissions at the Google Cloud organization level. + Assign the custom role to the Google group." }, correct: ["D"] },
  { id: 282, text: "Your team is using Linux instances on Google Cloud. You need to ensure that your team logs in to these instances in the most secure and cost efficient way. What should you do?", options: { A: "Attach a public IP to the instances and allow incoming connections from the internet on port 22 for SSH.", B: "Use the gcloud compute ssh command with the --tunnel-through-iap flag. Allow ingress traffic from the IP range 35.235.240.0/20 on port 22.", C: "Use a third party tool to provide remote access to the instances.", D: "Create a bastion host with public internet access. Create the SSH tunnel to the instance through the bastion host." }, correct: ["B"] },
  { id: 283, text: "You have been asked to set up Object Lifecycle Management for objects stored in storage buckets. The objects are written once and accessed frequently for 30 days. After 30 days, the objects are not read again unless there is a special need. The objects should be kept for three years, and you need to minimize cost. What should you do?", options: { A: "Set up a policy that uses Nearline storage for 30 days and then moves to Archive storage for three years.", B: "Set up a policy that uses Standard storage for 30 days and then moves to Archive storage for three years.", C: "Set up a policy that uses Nearline storage for 30 days, then moves the Coldline for one year, and then moves tc Archive storage for two years.", D: "Set up a policy that uses Standard storage for 30 days, then moves to Coldline for one year, and then moves to Archive storage for two years." }, correct: ["B"] },
  { id: 284, text: "You are developing a financial trading application that will be used globally. Data is stored and queried using a relational structure, and clients from all over the world should get the exact identical state of the data. The application will be deployed in multiple regions to provide the lowest latency to end users. You need to select a storage option for the application data while minimizing latency. What should you do?", options: { A: "Use Cloud Bigtable for data storage.", B: "Use Cloud SQL for data storage.", C: "Use Cloud Spanner for data storage.", D: "Use Firestore for data storage." }, correct: ["C"] },
  { id: 285, text: "You are running a web application on Cloud Run for a few hundred users. Some of your users complain that the initial web page of the application takes much longer to load than the following pages. You want to follow Google’s recommendations to mitigate the issue. What should you do?", options: { A: "Set the minimum number of instances for your Cloud Run service to 3.", B: "Set the concurrency number to 1 for your Cloud Run service.", C: "Set the maximum number of instances for your Cloud Run service to 100.", D: "Update your web application to use the protocol HTTP/2 instead of HTTP/1.1." }, correct: ["A"] },
  { id: 286, text: "You manage an App Engine Service that aggregates and visualizes data from BigQuery. The application is deployed with the default App Engine Service account. The data that needs to be visualized resides in a different project managed by another team. You do not have access to this project, but you want your application to be able to read data from the BigQuery dataset. What should you do?", options: { A: "Ask the other team to grant your default App Engine Service account the role of BigQuery Job User.", B: "Ask the other team to grant your default App Engine Service account the role of BigQuery Data Viewer.", C: "In Cloud IAM of your project, ensure that the default App Engine service account has the role of BigQuery Data Viewer.", D: "In Cloud IAM of your project, grant a newly created service account from the other team the role of BigQuery Job User in your project." }, correct: ["B"] },
  { id: 287, text: "You need to assign a Cloud Identity and Access Management (Cloud IAM) role to an external auditor. The auditor needs to have permissions to review your Google Cloud Platform (GCP) Audit Logs and also to review your Data Access logs. What should you do?", options: { A: "Assign the auditor the IAM role roles/logging.privateLogViewer. Perform the export of logs to Cloud Storage.", B: "Assign the auditor the IAM role roles/logging.privateLogViewer. Direct the auditor to also review the logs for changes to Cloud IAM policy.", C: "Assign the auditor's IAM user to a custom role that has logging. privateLogEntries.list permission. Perform the export of logs to Cloud Storage.", D: "Assign the auditor's IAM user to a custom role that has logging. privateLogEntries.list permission. Direct the auditor to also review the logs for changes to Cloud IAM policy." }, correct: ["B"] },
  { id: 288, text: "You used the gcloud container clusters command to create two Google Cloud Kubernetes (GKE) clusters: prod-cluster and dev-cluster. + prod-cluster is a standard cluster. + dev-cluster is an auto-pilot cluster. When you run the kubectl get nodes command, you only see the nodes from prod-cluster. Which commands should you run to check the node status for dev-cluster?", options: { A: "gcloud container clusters get-credentials dev-cluster kubectl get nodes", B: "gcloud container clusters update -generate-password dev-cluster kubectl get nodes", C: "kubectl config set-context dev-cluster kubectl cluster-info", D: "kubectl config set-credentials dev-cluster kubectl cluster-info" }, correct: ["A"] },
  { id: 289, text: "You need to set up permissions for a set of Compute Engine instances to enable them to write data into a particular Cloud Storage bucket. You want to follow Google-recommended practices. What should you do?", options: { A: "Create a service account with an access scope. Use the access scope ‘", B: "Create a service account with an access scope. Use the access scope ‘ platform’.", C: "Create a service account and add it to the IAM role 'storage.objectCreator' for that bucket.", D: "Create a service account and add it to the IAM role 'storage.objectAdmin’ for that bucket." }, correct: ["C"] },
  { id: 290, text: "You have a batch workload that runs every night and uses a large number of virtual machines (VMs). It is fault-tolerant and can tolerate some of the VMs being terminated. The current cost of VMs is too high. What should you do?", options: { A: "Run a test using simulated maintenance events. If the test is successful, use preemptible N1 Standard VMs when running future jobs.", B: "Run a test using simulated maintenance events. If the test is successful, use N1 Standard VMs when running future jobs.", C: "Run a test using a managed instance group. If the test is successful, use N1 Standard VMs in the managed instance group when running future jobs.", D: "Run a test using N1 standard VMs instead of N2. If the test is successful, use N1 Standard VMs when running future jobs." }, correct: ["A"] },
  { id: 291, text: "You have a managed instance group comprised of preemptible VM's. All of the VM's keepdeleting and recreating themselves every minute. What is a possible cause of thisbehavior?", options: { A: "Your zonal capacity is limited, causing all preemptible VM's to be shutdown torecover capacit", B: "Try deploying your group to another zone.", C: "You have hit your instance quota for the region.", D: "Your managed instance group's VM's are toggled to only last 1 minute inpreemptible settings.", E: "Your managed instance group's health check is repeatedly failing, either to amisconfigured health check or misconfigured firewall rules not allowing the healthcheck to access the instance" }, correct: ["D"] },
  { id: 292, text: "You are deploying a production application on Compute Engine. You want to prevent anyone from accidentally destroying the instance by clicking the wrong button. What should you do?", options: { A: "Disable the flag €aDelete boot disk when instance is deleted.€a", B: "Enable delete protection on the instance.", C: "Disable Automatic restart on the instance.", D: "Enable Preemptibility on the instance." }, correct: ["B"] },
  { id: 293, text: "You are using Data Studio to visualize a table from your data warehouse that is built on top of BigQuery. Data is appended to the data warehouse during the day. At night, the daily summary is recalculated by overwriting the table. You just noticed that the charts in Data Studio are broken, and you want to analyze the problem. What should you do?", options: { A: "Review the Error Reporting page in the Cloud Console to find any errors.", B: "Use the BigQuery interface to review the nightly job and look for any errors.", C: "Use Cloud Debugger to find out why the data was not refreshed correctly.", D: "In Cloud Logging, create a filter for your Data Studio report." }, correct: ["B"] },
  { id: 294, text: "You need to monitor resources that are distributed over different projects in Google Cloud Platform. You want to consolidate reporting under the same Stackdriver Monitoring dashboard. What should you do?", options: { A: "Use Shared VPC to connect all projects, and link Stackdriver to one of the projects.", B: "For each project, create a Stackdriver account. In each project, create a service account for that project and grant it the role of Stackdriver Account Editor in all other projects.", C: "Configure a single Stackdriver account, and link all projects to the same account.", D: "Configure a single Stackdriver account for one of the projects. In Stackdriver, create a Group and add the other project names as criteria for that Group." }, correct: ["C"] },
  { id: 295, text: "You have created an application that is packaged into a Docker image. You want to deploy the Docker image as a workload on Google Kubernetes Engine. What should you do?", options: { A: "Upload the image to Cloud Storage and create a Kubernetes Service referencing the image.", B: "Upload the image to Cloud Storage and create a Kubernetes Deployment referencing the image.", C: "Upload the image to Container Registry and create a Kubernetes Service referencing the image.", D: "Upload the image to Container Registry and create a Kubernetes Deployment referencing the image." }, correct: ["D"] },
  { id: 296, text: "You are planning to deploy an application to Google Cloud. Your application processes asynchronous events from Google services and must be accessible from the public Internet. You need to identify how to deploy your application. You want to follow a standardized process while minimizing development costs. You also want to have no costs when your workloads are not in use. What should you do?", options: { A: "Deploy your code to GKE. Use Pub/Sub for event delivery.", B: "Deploy your code to Compute Engine. Use Pub/Sub for event delivery.", C: "Deploy your code to GKE. Use Eventarc for event delivery.", D: "Deploy your code to Cloud Run. Use Eventarc for event delivery." }, correct: ["D"] },
  { id: 297, text: "You are managing the security configuration of your company’s Google Cloud organization. The Operations team needs specific permissions on both a Google Kubernetes Engine (GKE) cluster and a Cloud SQL instance. Two predefined Identity and Access Management (IAM) roles exist that contain a subset of the permissions needed by the team. You need to configure the necessary IAM permissions for this team while following Google-recommended practices. What should you do?", options: { A: "Create a custom IAM role that combines the permissions from the two relevant predefined roles.", B: "Grant the team the two predefined IAM roles.", C: "Create a custom IAM role that includes only the required permissions from the predefined roles.", D: "Grant the team the IAM roles of Kubernetes Engine Admin and Cloud SQL Admin." }, correct: ["C"] },
  { id: 298, text: "Your company uses a multi-cloud strategy that includes Google Cloud. You want to centralize application logs in a third- party software-as-a-service (SaaS) tool from all environments. You need to integrate logs originating from Cloud Logging, and you want to ensure the export occurs with the least amount of delay possible. What should you do?", options: { A: "Create a Cloud Logging sink and configure BigQuery as the destination. Configure the SaaS tool to query BigQuery to retrieve the logs.", B: "Create a Cloud Logging sink and configure Pub/Sub as the destination. Configure the SaaStool to subscribe to the Pub/Sub topic to retrieve the logs.", C: "Create a Cloud Logging sink and configure Cloud Storage as the destination. Configure the SaaS tool to read the Cloud Storage bucket to retrieve the logs.", D: "Use a Cloud Scheduler cron job to trigger a Cloud Function that queries Cloud Logging and sends the logs to the SaaS tool." }, correct: ["B"] },
  { id: 299, text: "You are deploying an application to Google Kubernetes Engine (GKE). The application needs to make API calls to a private Cloud Storage bucket. You need to configure your application Pods to authenticate to the Cloud Storage API, but your organization policy prevents the usage of service account keys. You want to follow Google-recommended practices. What should you do?", options: { A: "Create the GKE cluster with Workload Identity Federation. Configure the default node service account to access the bucket. Deploy the application into the cluster so the application can use the node service account permissions. Use Identity and Access Management (IAM) to grant the service account access to the bucket.", B: "Create the GKE cluster with Workload Identity Federation. Create a Google service account and a Kubernetes ServiceAccount, and configure both service accounts to use Workload Identity Federation. Attach the Kubernetes ServiceAccount to the application Pods and configure the Google service account to access the bucket with Identity and Access Managemeni (IAM).", C: "Create the GKE cluster and deploy the application. Request a security exception to create a Google service account key. Set the constraints/iam.serviceAccountKeyExpiryHours organization policy to 24 hours.", D: "Create the GKE cluster and deploy the application. Request a security exception to create a Google service account key. Set the constraints/iam.serviceAccountKeyExpiryHours organization policy to 8 hours." }, correct: ["B"] },
  { id: 300, text: "You are planning to migrate your containerized workloads to Google Kubernetes Engine (GKE). You need to determine which GKE option to use. Your solution must have high availability, minimal downtime, and the ability to promptly apply security updates to your nodes. You also want to pay only for the compute resources that your workloads use without managing nodes. You want to follow Google-recommended practices and minimize operational costs. What should you do?", options: { A: "Configure a Standard regional GKE duster.", B: "Configure a Standard zonal GKE duster.", C: "Configure a Standard multi-zonal GKE cluster.", D: "Configure an Autopilot GKE cluster." }, correct: ["D"] },
  { id: 301, text: "Your company is seeking a scalable solution to retain and explore application logs hosted on Compute Engine. You must be able to analyze your logs with SQL queries, and you want to be able to create charts to identify patterns and trends in your logs over time. You want to follow Google-recommended practices and minimize your operational costs. What should you do?", options: { A: "Use a custom script to push your application logs to BigQuery for exploration.", B: "Ingest your application logs to Cloud Logging by using Ops Agent, and explore your logs in Logs Explorer.", C: "Ingest your application logs to Cloud Logging by using Ops Agent, and explore your logs with Log Analytics.", D: "Use a custom script to push your application logs to Cloud SQL for exploration." }, correct: ["C"] },
  { id: 302, text: "You work for a financial services company that operates as a stock market broker. Your company is planning to migrate to Google Cloud. You need to plan the network design in Google Cloud. Your design must: + Minimize the latency between all production systems. + Minimize costs related to your development environment. What should you do?", options: { A: "Create a VPC in the Standard Tier and one in the Premium Tier. Deploy production workloads in the Standard Tier and development workloads in the Premium Tier.", B: "Create a VPC in the Standard Tier and one in the Premium Tier. Deploy development workloads in the Standard Tier and production workloads in the Premium Tier.", C: "Create a VPC in the Premium Tier, and deploy both production and development workloads on this VPC.", D: "Create a VPC in the Standard Tier, and deploy both production and development workloads on this VPC." }, correct: ["B"] },
  { id: 303, text: "You are the Organization Administrator for your company's Google Cloud resources. Your company has strict compliance tules that require you to be notified about any modifications to files and documents hosted on Cloud Storage. In a recent incident, one of your team members was able to modify files and you did not receive any notifications, causing other production jobs to fail. You must ensure that you receive notifications for all changes to files and documents in Cloud Storage while minimizing management overhead. What should you do?", options: { A: "View Cloud Audit logs for all Cloud Storage files in Logs Explorer. Filter by Admin Activity logs.", B: "Enable Cloud Storage object versioning on your bucket. Configure Pub/Sub notifications for your Cloud Storage buckets.", C: "Enable versioning on the Cloud Storage bucket. Set up a custom script that scans versions of Cloud Storage objects being modified and alert the admin by using the script.", D: "Configure Object change notifications on the Cloud Storage buckets. Send the events to Pub/Sub." }, correct: ["B"] },
  { id: 304, text: "Your company was recently impacted by a service disruption that caused multiple Dataflow jobs to get stuck, resulting in significant downtime in downstream applications and revenue loss. You were able to resolve the issue by identifying and fixing an error you found in the code. You need to design a solution with minimal management effort to identify when jobs are stuck in the future to ensure that this issue does not occur again. What should you do?", options: { A: "Update the Dataflow job configurations to send messages to a Pub/Sub topic when there are delays. Configure a backup Dataflow job to process jobs that are delayed. Use Cloud Tasks to trigger an alert when messages are pushed to the Pub/Sub topic.", B: "Set up Cloud Monitoring alerts on the data freshness metric for the Dataflow jobs to receive a notification when a certain threshold is reached.", C: "Set up Error Reporting to identify stack traces that indicate slowdowns in Dataflow jobs. Set up alerts based on these log entries.", D: "Use the Personalized Service Health dashboard to identify issues with Dataflow jobs across regions." }, correct: ["B"] },
  { id: 305, text: "You have an application running inside a Compute Engine instance. You want to provide the application with secure access to a BigQuery dataset. You must ensure that credentials are only valid for a short period of time, and your application will only have access to the intended BigQuery dataset. You want to follow Google-recommended practices and minimize your operational costs. What should you do?", options: { A: "Attach a new service account to the instance every hour, and grant the service account the BigQuery Data Viewer IAM role on the project.", B: "Attach a custom service account to the instance, and grant the service account the BigQuery Data Viewer IAM role on the dataset.", C: "Attach a new service account to the instance every hour, and grant the service account the BigQuery Data Viewer IAM role on the dataset.", D: "Attach a custom service account to the instance, and grant the service account the BigQuery Data Viewer IAM role on the project." }, correct: ["B"] },
  { id: 306, text: "Your team has developed a stateless application which requires it to be run directly on virtual machines. The application is expected to receive a fluctuating amount of traffic and needs to scale automatically. You need to deploy the application. What should you do?", options: { A: "Deploy the application on a managed instance group and configure autoscaling.", B: "Deploy the application on a Kubernetes Engine cluster and configure node pool autoscaling.", C: "Deploy the application on Cloud Functions and configure the maximum number instances.", D: "Deploy the application on Cloud Run and configure autoscaling." }, correct: ["A"] },
  { id: 307, text: "Your company uses BigQuery to store and analyze data. Upon submitting your query in BigQuery, the query fails with a quotaExceeded error. You need to diagnose the issue causing the error. What should you do? (Choose two.)", options: { A: "Use BigQuery BI Engine to analyze the issue.", B: "Use the INFORMATION_SCHEMA views to analyze the underlying issue.", C: "Configure Cloud Trace to analyze the issue.", D: "Search errors in Cloud Audit Logs to analyze the issue.", E: "View errors in Cloud Monitoring to analyze the issue." }, correct: ["B", "D"] },
  { id: 308, text: "Your company is using Google Workspace to manage employee accounts. Anticipated growth will increase the number of personnel from 100 employees to 1,000 employees within 2 years. Most employees will need access to your company’s Google Cloud account. The systems and processes will need to support 10x growth without performance degradation, unnecessary complexity, or security issues. What should you do?", options: { A: "Migrate the users to Active Directory. Connect the Human Resources system to Active Directory. Turn on Google Cloud Directory Sync (GCDS) for Cloud Identity. Turn on Identity Federation from Cloud Identity to Active Directory.", B: "Organize the users in Cloud Identity into groups. Enforce multi-factor authentication in Cloud Identity.", C: "Turn on identity federation between Cloud Identity and Google Workspace. Enforce multi-factor authentication for domain wide delegation.", D: "Use a third-party identity provider service through federation. Synchronize the users from Google Workplace to the third- party provider in real time." }, correct: ["B"] },
  { id: 309, text: "You are planning to migrate a database and a backend application to a Standard Google Kubernetes Engine (GKE) cluster. You need to prevent data loss and make sure there are enough nodes available for your backend application based on the demands of your workloads. You want to follow Google-recommended practices and minimize the amount of manual work required. What should you do?", options: { A: "Run your database as a Stateful Set. Configure cluster autoscaling to handle changes in the demands of your workloads.", B: "Run your database as a single Pod. Run the resize command when you notice changes in the demands of your workloads.", C: "Run your database as a Daemon Set. Run the resize command when you notice changes in the demands of your workloads.", D: "Run your database as a Deployment. Configure cluster autoscaling to handle changes in the demands of your workloads." }, correct: ["A"] },
  { id: 310, text: "You are using Looker Studio to visualize a table from your data warehouse that is built on top of BigQuery. Data is appended to the data warehouse during the day. At night, the daily summary is recalculated by overwriting the table. You just noticed that the charts in Looker Studio are broken, and you want to analyze the problem. What should you do?", options: { A: "In Cloud Logging, create a filter for your Looker Studio report.", B: "Use the open source CLI tool, Snapshot Debugger, to find out why the data was not refreshed correctly.", C: "Review the Error Reporting page in the Google Cloud console to find any errors.", D: "Use the BigQuery interface to review the nightly job and look for any errors." }, correct: ["D"] },
  { id: 311, text: "You have deployed multiple Linux instances on Compute Engine. You plan on adding more instances in the coming weeks. You want to be able to access all of these instances through your SSH client over the internet without having to configure specific access on the existing and new instances. You do not want the Compute Engine instances to have a public IP. What should you do?", options: { A: "Configure Cloud Identity-Aware Proxy for HTTPS resources.", B: "Configure Cloud Identity-Aware Proxy for SSH and TCP resources", C: "Create an SSH keypair and store the public key as a project-wide SSH Key.", D: "Create an SSH keypair and store the private key as a project-wide SSH Key." }, correct: ["B"] },
  { id: 312, text: "You are configuring service accounts for an application that spans multiple projects. Virtual machines (VMs) running in the web-applications project need access to BigQuery datasets in the crm-databases project. You want to follow Google-recommended practices to grant access to the service account in the web-applications project. What should you do?", options: { A: "Grant \"project owner\" for web-applications appropriate roles to crm-databases.", B: "Grant \"project owner\" role to crm-databases and the web-applications project.", C: "Grant \"project owner\" role to crm-databases and roles/bigquery.dataViewer role to web-applications.", D: "Grant roles/bigquery.dataViewer role to crm-databases and appropriate roles to web-applications." }, correct: ["D"] },
  { id: 313, text: "You have an application that runs on Compute Engine VM instances in a custom Virtual Private Cloud (VPC). Your company’s security policies only allow the use of internal IP addresses on VM instances and do not let VM instances connect to the internet. You need to ensure that the application can access a file hosted in a Cloud Storage bucket within your project. What should you do?", options: { A: "Enable Private Service Access on the Cloud Storage Bucket.", B: "Add storage.googleapis.com to the list of restricted services in a VPC Service Controls perimeter and add your project to the list of protected projects.", C: "Enable Private Google Access on the subnet within the custom VPC.", D: "Deploy a Cloud NAT instance and route the traffic to the dedicated IP address of the Cloud Storage bucket." }, correct: ["C"] },
  { id: 314, text: "You installed the Google Cloud CLI on your workstation and set the proxy configuration. However, you are worried that your proxy credentials will be recorded in the gcloud CLI logs. You want to prevent your proxy credential from being logged. What should you do?", options: { A: "Configure username and password by using gcloud config set proxy/username and gcloud config set proxy/password commands.", B: "Encode username and password in sha256 encoding, and save in to a text file. Use filename as a value in the gcloud config set core/custom_ca_certs_file command.", C: "Provide values for CLOUDSDK_PROXY_USERNAME and CLOUDSDK_PROXY_PASSWORD in the gcloud CLI tool configuration file.", D: "Set the CLOUDSDK_PROXY_USERNAME and CLOUDSDK_PROXY_PASSWORD properties by using environment variables in your command line tool." }, correct: ["D"] },
  { id: 315, text: "You have two Google Cloud projects: project-a with VPC vpc-a (10.0.0.0/16) and project-b with VPC vpc-b (10.8.0.0/16). Your frontend application resides in vpc-a and the backend API services are deployed in vpc-b. You need to efficiently and cost-effectively enable communication between these Google Cloud projects. You also want to follow Google-recommended practices. What should you do?", options: { A: "Create an OpenVPN connection between vpc-a and vpc-b.", B: "Create VPC Network Peering between vpc-a and vpc-b.", C: "Configure a Cloud Router in vpc-a and another Cloud Route; in vpe-b.", D: "Configure a Cloud Interconnect connection between vpc-a and vpc-b." }, correct: ["B"] },
  { id: 316, text: "You deployed an application on a managed instance group in Compute Engine. The application accepts Transmission Control Protocol (TCP) traffic on port 389 and requires you to preserve the IP address of the client who is making a request. You want to expose the application to the internet by using a load balancer. What should you do?", options: { A: "Expose the application by using an external TCP Network Load Balancer.", B: "Expose the application by using a TCP Proxy Load Balancer.", C: "Expose the application by using an SSL Proxy Load Balancer.", D: "Expose the application by using an internal TCP Network Load Balancer. ee" }, correct: ["A"] },
  { id: 317, text: "You need to migrate invoice documents stored on-premises to Cloud Storage. The documents have the following storage requirements: + Documents must be kept for five years. + Up to five revisions of the same invoice document must be stored, to allow for corrections. * Documents older than 365 days should be moved to lower cost storage tiers. You want to follow Google-recommended practices to minimize your operational and development costs. What should you do?", options: { A: "Enable retention policies on the bucket, and use Cloud Scheduler to invoke a Cloud Function to move or delete your documents based on their metadata.", B: "Enable retention policies on the bucket, use lifecycle rules to change the storage classes of the objects, set the number of versions, and delete old files.", C: "Enable object versioning on the bucket, and use Cloud Scheduler to invoke a Cloud Functions instance to move or delete your documents based on their metadata.", D: "Enable object versioning on the bucket, use lifecycle conditions to change the storage class of the objects, set the number of versions, and delete old files. \"= SAnewer: Ban cscs" }, correct: [], needsAnswer: true },
  { id: 318, text: "You are planning to migrate the following on-premises data management solutions to Google Cloud: + One MySQL cluster for your main database + Apache Kafka for your event streaming platform * One Cloud SQL for PostgreSQL database for your analytical and reporting needs You want to implement Google-recommended solutions for the migration. You need to ensure that the new solutions provide global scalability and require minimal operational and infrastructure management. What should you do?", options: { A: "Migrate from MySQL to Cloud SQL, from Kafka to Pub/Sub, and from Cloud SQL for PostgreSQL to BigQuery.", B: "Migrate from MySQL to Cloud Spanner, from Kafka to Pub/Sub, and from Cloud SQL for PostgreSQL to BigQuery.", C: "Migrate from MySQL to Cloud Spanner, from Kafka to Memorystore, and from Cloud SQL for PostgreSQL to Cloud SQL.", D: "Migrate from MySQL to Cloud SQL, from Kafka to Memorystore, and from Cloud SQL for PostgreSQL to Cloud SQL." }, correct: ["B"] },
  { id: 319, text: "Your company would like to store invoices and other financial documents in Google Cloud. You need to identify a Google-managed solution to store this information for your company. You must ensure that the documents are kept for a duration of three years. Your company's analysts need frequent access to invoices from the past six months. After six months, invoices should be archived for audit purposes only. You want to minimize costs and follow Google-recommended practices. What should you do?", options: { A: "Use Cloud Storage with Object Lifecycle Management to change the object storage class to Coldline after six months.", B: "Use Cloud Storage with Object Lifecycle Management to change the object storage class to Standard after six months.", C: "Store your documents on Filestore, and move the documents to Cloud Storage with object storage class set to Celdiine after six months.", D: "Store your documents on Filestore, and move the documents to Cloud Storage with object storage class set to Standard after six months." }, correct: ["A"] },
  { id: 320, text: "You have been asked to create robust Virtual Private Network (VPN) connectivity between a new Virtual Private Cloud (VPC) and a remote site. Key requirements include dynamic routing, a shared address space of 10.19.0.1/22, and no overprovisioning of tunnels during a failover event. You want to follow Google- recommended practices to set up a high availability Cloud VPN. What should you do?", options: { A: "Use a custom mode VPC network, configure static routes, and use active/passive routing.", B: "Use an automatic mode VPC network, configure static routes, and use active/active routing.", C: "Use a custom mode VPC network, use Cloud Router border gateway protocol (BGP) routes, and use active/passive ro.'ting.", D: "Use an automatic mode VPC network, use Cloud Router border gateway protocol (BGP) routes, and configure policy-based routing." }, correct: ["C"] },
  { id: 321, text: "You are in charge of provisioning access for all Google Cloud users in your organization. Your company recently acquired a startup company that has their own Google Cloud organization. You need to ensure that your Site Reliability Engineers (SREs) have the same project permissions in the startup company's organization as in your own organization. What should you do?", options: { A: "In the Google Cloud console for your organization, select Create role from selection, and choose destination as the startup company's organization.", B: "In the Google Cloud console for the startup company, select Create role from selection and choose source as the startup company's Google Cloud organization.", C: "Use the gcloud iam roles copy command, and provide the Organization ID of the startup company's Google Cloud Organization as the destination.", D: "Use the gcloud iam roles copy command, and provide the project IDs of all projects in the startup company's organization as the destination." }, correct: ["C"] },
  { id: 322, text: "You are developing an application that will be deployed on Google Cloud. The application will use a service account to retrieve data from BigQuery. Before you deploy your application, you want to test the permissions of this service account from your local machine to ensure there will be no authentication issues. You want to ensure that you use the most secure method while following Google-recommended practices. What should you do?", options: { A: "Generate a service account key, and configure the gcloud CLI to use this key. Issue a relevant BigQuery request through the gdoud CLI to test the access.", B: "Grant the service account the BigQuery Administrator IAM role to ensure the service account has all required access.", C: "Configure the gcloud CLI to use service account impersonation. Issue a relevant BigQuery request through the gsta:sd CLI to test the access.", D: "Configure the gcloud CLI with Application Default Credentials using your user account. Issue a relevant BigQuery request through the gcloud CLI to test the access." }, correct: ["C"] },
  { id: 323, text: "You have a Bigtable instance that consists of three nodes that store personally identifiable information (PII) data. You need to log all read or write operations, including any metadata or configuration reads of this database table, in your company’s Security Information and Event Management (SIEM) system. What should you do?", options: { A: "+ Navigate to Cloud Monitoring in the Google Cloud console, and create a custom monitoring job for the Bigtable instance to track all changes. + Create an alert by using webhook endpoints, with the SIEM endpoint as a receiver.", B: "« Navigate to the Audit Logs page in the Google Cloud console, and enable Admin Write logs for the Bigtable instance. + Create a Cloud Functions instance to export logs from Cloud Logging to your SIEM.", C: "+ Navigate to the Audit Logs page in the Google Cloud console, and enable Data Read, Data Write and Admin Read logs for the Bigtable instance. + Create a Pub/Sub topic as a Cloud Logging sink destination, and add your SIEM as a subscriber to the topic.", D: "+ Install the Ops Agent on the Bigtable instance during configuration. + Create a service account with read permissions for the Bigtable instance. + Create a custom Dataflow job with this service account to export logs to the company’s SIEM system." }, correct: ["C"] },
  { id: 324, text: "You are storing sensitive information in a Cloud Storage bucket. For legal reasons, you need to be able to record all requests that read any of the stored data. You want to make sure you comply with these requirements. What should you do?", options: { A: "Enable the Identity Aware Proxy API on the project.", B: "Scan the bucket using the Data Loss Prevention API.", C: "Allow only a single Service Account access to read the data.", D: "Enable Data Access audit logs for the Cloud Storage API." }, correct: ["D"] },
  { id: 325, text: "Your team is running an on-premises ecommerce application. The application contains a complex set of microservices written in Python, and each microservice is running on Docker containers. Configurations are injected by using environment variables. You need to deploy your current application to a serverless Google Cloud cloud solution. What should you do?", options: { A: "Use your existing CI/CD pipeline. Use the generated Docker images and deploy them to Cloud Run. Update the configurations and the required endpoints.", B: "Use your existing continuous integration and delivery (CI/CD) pipeline. Use the generated Docker images and deploy them to Cloud Function. Use the same configuration as on-premises.", C: "Use the existing codebase and deploy each service as a separate Cloud Function. Update the configurations and the required endpoints.", D: "Use your existing codebase and deploy each service as a separate Cloud Run. Use the same configurations as on-premises." }, correct: ["A"] },
  { id: 326, text: "You have developed an application that consists of multiple microservices, with each microservice packaged in its own Docker container image. You want to deploy the entire application on Google Kubernetes Engine so that each microservice can be scaled individually. What should you do?", options: { A: "Create and deploy a Custom Resource Definition per microservice.", B: "Create and deploy a Docker Compose File.", C: "Create and deploy a Job per microservice.", D: "Create and deploy a Deployment per microservice." }, correct: ["D"] },
  { id: 327, text: "You want to host your video encoding software on Compute Engine. Your user base is growing rapidly, and users need to be able to encode their videos at any time without interruption or CPU limitations. You must ensure that your encoding solution is highly available, and you want to follow Google-recommended practices to automate operations. What should you do?", options: { A: "Deploy your solution on multiple standalone Compute Engine instances, and increase the number of existing instances when CPU utilization on Cloud Monitoring reaches a certain threshold.", B: "Deploy your solution on multiple standalone Compute Engine instances, and replace existing instances with high-CPU instances when CPU utilization on Cloud Monitoring reaches a certain threshold.", C: "Deploy your solution to an instance group, and increase the number of available instances whenever you see high CFI’ utilization in Cloud Monitoring.", D: "Deploy your solution to an instance group, and set the autoscaling based on CPU utilization." }, correct: ["D"] },
  { id: 328, text: "You have two subnets (subnet-a and subnet-b) in the default VPC. Your database servers are running in subnet-a. Your application servers and web servers are running in subnet-b. You want to configure a firewall rule that only allows database traffic from the application servers to the database servers. What should you do?", options: { A: "+ Create service accounts sa-app and sa-db. + Associate service account sa-app with the application servers and the service account sa-db with the database servers. + Create an ingress firewall rule to allow network traffic from source service account sa-app to target service account sa-db.", B: "+ Create network tags app-server and db-server. + Add the app-server tag to the application servers and the db-server tag to the database servers. + Create an egress firewall rule to allow network traffic from source network tag app-server to target network tag db-server.", C: "+ Create a service account sa-app and a network tag db-server. + Associate the service account sa-app with the application servers and the network tag db-server with the database servers. + Create an ingress firewall rule to allow network traffic from source VPC IP addresses and target the subnet-a IP addresses.", D: "* Create a network tag app-server and service account sa-db. + Add the tag to the application servers and associate the service account with the database servers. + Create an egress firewall rule to allow network traffic from source network tag app-server to target service account sa-db." }, correct: ["A"] },
  { id: 329, text: "You are building a multi-player gaming application that will store game information in a database. As the popularity of the application increases, you are concerned about delivering consistent performance. You need to ensure an optimal gaming performance for global users, without increasing the management complexity. What should you do?", options: { A: "Use Cloud SQL database with cross-region replication to store game statistics in the EU, US, and APAC regions.", B: "Use Cloud Spanner to store user data mapped to the game statistics.", C: "Use BigQuery to store game statistics with a Redis on Memorystore instance in the front to provide global consistency.", D: "Store game statistics in a Bigtable database partitioned by username." }, correct: ["B"] },
  { id: 330, text: "You need to extract text from audio files by using the Speech-to-Text API. The audio files are pushed to a Cloud Storage bucket. You need to implement a fully managed, serverless compute solution that requires authentication and aligns with Google-recommended practices. You want to automate the call to the API by submitting each file to the API as the audio file arrives in the bucket. What should you do?", options: { A: "Create an App Engine standard environment triggered by Cloud Storage bucket events to submit the file URI to the Google Speech-to-TextAPI.", B: "Run a Kubernetes job to scan the bucket regularly for incoming files, and call the Speech-to-Text API for each unprocessed file.", C: "Run a Python script by using a Linux cron job in Compute Engine to scan the bucket regularly for incoming files, and call the Speech-to-Text API for each unprocessed file.", D: "Create a Cloud Function triggered by Cloud Storage bucket events to submit the file URI to the Google Speech-to-Text API." }, correct: ["D"] },
  { id: 331, text: "You want to set up a Google Kubernetes Engine cluster. Verifiable node identity and integrity are required for the cluster, and nodes cannot be accessed from the internet. You want to reduce the operational cost of managing your cluster, and you want to follow Google-recommended practices. What should you do?", options: { A: "Deploy a private autopilot cluster.", B: "Deploy a public autopilot cluster.", C: "Deploy a standard public cluster and enable shielded nodes.", D: "Deploy a standard private cluster and enable shielded nodes." }, correct: ["A"] },
  { id: 332, text: "After a recent security incident, your startup company wants better insight into what is happening in the Google Cloud environment. You need to monitor unexpected firewall changes and instance creation. Your company prefers simple solutions. What should you do?", options: { A: "Create a log sink to forward Cloud Audit Logs filtered for firewalls and compute instances to Cloud Storage. Use BigQuery to periodically analyze log events in the storage bucket.", B: "Use Cloud Logging filters to create log-based metrics for firewall and instance actions. Monitor the changes and set up reasonable alerts.", C: "Install Kibana on a compute instance. Create a log sink to forward Cloud Audit Logs filtered for firewalls and compute instances to Pub/Sub. Target the Pub/Sub topic to push messages to the Kibana instance. Analyze the logs on Kibana in real time.", D: "Turn on Google Cloud firewall rules logging, and set up alerts for any insert, update, or delete events." }, correct: ["B"] },
  { id: 333, text: "Your team is building a website that handles votes from a large user population. The incoming votes will arrive at various rates. You want to optimize the storage and processing of the votes. What should you do?", options: { A: "Save the incoming votes to Firestore. Use Cloud Scheduler to trigger a Cloud Functions instance to periodically process the votes.", B: "Use a dedicated instance to process the incoming votes. Send the votes directly to this instance.", C: "Save the incoming votes to a JSON file on Cloud Storage. Process the votes in a batch at the end of the day.", D: "Save the incoming votes to Pub/Sub. Use the Pub/Sub topic to trigger a Cloud Functions instance to process the votes." }, correct: ["D"] },
  { id: 334, text: "You want to permanently delete a Pub/Sub topic managed by Config Connector in your Google Cloud project. What should you do?", options: { A: "Use kubectl to create the label deleted-by-cnrm and to change its value to true for the topic resource.", B: "Use kubectl to delete the topic resource.", C: "Use gcloud CLI to delete the topic.", D: "Use gcloud CLI to update the topic label managed-by-cnrm to false." }, correct: ["B"] },
  { id: 335, text: "You recently received a new Google Cloud project with an attached billing account where you will work. You need to create instances, set firewalls, and store data in Cloud Storage. You want to follow Google-recommended practices. What should you do?", options: { A: "Use the gcloud CLI services enable cloudresourcemanager.googleapis.com command to enable all resources.", B: "Use the gcloud services enable compute.googleapis.com command to enable Compute Engine and the gcloud services enable storage-api.googleapis.com command to enable the Cloud Storage APIs.", C: "Open the Google Cloud console and enable all Google Cloud APIs from the API dashboard.", D: "Open the Google Cloud console and run gcloud init -project in a Cloud Shell." }, correct: ["B"] },
  { id: 336, text: "Your web application is hosted on Cloud Run and needs to query a Cloud SQL database. Every morning during a traffic spike, you notice API quota errors in Cloud SQL logs. The project has already reached the maximum API quota. You want to make a configuration change to mitigate the issue. What should you do?", options: { A: "Modify the minimum number of Cloud Run instances.", B: "Use traffic splitting.", C: "Modify the maximum number of Cloud Run instances.", D: "Set a minimum concurrent requests environment variable for the application." }, correct: ["A"] },
  { id: 1262, text: "Your company has developed a new application that consists of multiple microservices. You want to deploy the application to Google Kubernetes Engine (GKE), and you want to ensure that the cluster can scale as more applications are deployed in the future. You want to avoid manual intervention when each new application is deployed. What should you do?", options: { A: "Deploy the application on GKE, and add a HorizontalPodAutoscaler to the deployment.", B: "Deploy the application on GKE, and add a VerticalPodAutoscaler to the deployment.", C: "Create a GKE cluster with autoscaling enabled on the node pool. Set a minimum and maximum for the size of the node pool.", D: "Create a separate node pool for each application, and deploy each application to its dedicated node pool." }, correct: ["C"], origDupNo: 262 },
];
